window.KANT_WORK_DATA = {"metadata": {"work_id": "aa-VII-streit", "series": "AA", "band": "VII", "title": "Der Streit der Facultäten (1798)", "short_title": "Streit der Facultäten", "siglum": "AA VII", "edition": "Akademie-Ausgabe (1900–1923) via Kant im Kontext III (2017)", "collection_title": "Digitale Kant-Edition", "citation_systems": ["AA"], "citation_prefix": "AA VII"}, "toc_printed": [{"title": "Der Streit der Facultäten in drei Abschnitten", "page_id": "2484", "page_pdf": 2484, "page_book": null, "level": 2}, {"title": "Carl Friedrich Stäudlin,", "page_id": "2486_1", "page_pdf": 2486, "page_book": 3, "level": 2}, {"title": "von dem Verfasser.", "page_id": "2486_1", "page_pdf": 2486, "page_book": 3, "level": 2}, {"title": "Allgemeine Anmerkung.", "page_id": "2516_0", "page_pdf": 2516, "page_book": 48, "level": 2}, {"title": "durch den bloßen Vorsatz seiner krankhaften Gefühle Meister zu sein.", "page_id": "2551_0", "page_pdf": 2551, "page_book": 96, "level": 2}], "pages": [{"page_id": "2484", "page_pdf": 2484, "page_book": null, "page_kind": "title_page", "sigel": "", "units": [{"type": "heading", "text": "Der Streit der Facultäten in drei Abschnitten", "level": 2}, {"type": "paragraph", "text": "von Immanuel Kant."}, {"type": "paragraph", "text": "1798."}]}, {"page_id": "2485", "page_pdf": 2485, "page_book": null, "page_kind": "title_page", "sigel": "", "units": []}, {"page_id": "2486_0", "page_pdf": 2486, "page_book": null, "page_kind": "frontmatter", "sigel": "", "units": [{"type": "paragraph", "text": "[Zueignung]"}]}, {"page_id": "2486_1", "page_pdf": 2486, "page_book": 3, "page_kind": "frontmatter", "sigel": "AA VII, 3", "units": [{"type": "paragraph", "text": "Dem Herrn"}, {"type": "heading", "text": "Carl Friedrich Stäudlin,", "level": 2}, {"type": "paragraph", "text": "Doctor und Professor in Göttingen,"}, {"type": "paragraph", "text": "*zugeeignet*"}, {"type": "heading", "text": "von dem Verfasser.", "level": 2}], "markers": [{"system": "AA", "band": "VII", "page": 3, "ref": "VII3"}]}, {"page_id": "2487_0", "page_pdf": 2487, "page_book": 4, "page_kind": "body", "sigel": "AA VII, 4", "units": [{"type": "paragraph", "text": "Vorrede."}], "running_header": "Vorrede (Der Streit der Facultäten)"}, {"page_id": "2487_1", "page_pdf": 2487, "page_book": 5, "page_kind": "body", "sigel": "AA VII, 5", "units": [{"type": "paragraph", "text": "Gegenwärtige Blätter, denen eine aufgeklärte, den menschlichen Geist seiner Fesseln entschlagende und eben durch diese Freiheit im Denken desto bereitwilligern Gehorsam zu bewirken geeignete Regierung jetzt den Ausflug verstattet, – mögen auch zugleich die Freiheit verantworten, die der Verfasser sich nimmt, von dem, was bei diesem Wechsel der Dinge ihn selbst angeht, eine kurze Geschichtserzählung voran zu schicken. König Friedrich Wilhelm II. , ein tapferer, redlicher, menschenliebender und – von gewissen Temperamentseigenschaften abgesehen – durchaus vortrefflicher Herr, der auch mich persönlich kannte und von Zeit zu Zeit Äußerungen seiner Gnade an mich gelangen ließ, hatte auf Anregung eines Geistlichen, nachmals zum Minister im geistlichen Departement erhobenen Mannes, dem man billigerweise auch keine andere, als auf seine innere Überzeugung sich gründende gut gemeinte Absichten unterzulegen Ursache hat, – im Jahr 1788 ein Religionsedict, bald nachher ein die Schriftstellerei überhaupt sehr einschränkendes, mithin auch jenes mit schärfendes Censuredict ergehen lassen. Man kann nicht in Abrede ziehen: daß gewisse Vorzeichen, die der Explosion, welche nachher erfolgte, vorhergingen, der Regierung die Nothwendigkeit einer Reform in jenem Fache anräthig machen mußten; welches auf dem stillen Wege des akademischen Unterrichts künftiger öffentlicher Volkslehrer zu erreichen war: denn diese hatten als junge Geistliche ihren Kanzelvortrag auf solchen Ton gestimmt, daß, wer Scherz versteht, sich durch solche Lehrer eben nicht wird bekehren lassen. Indessen daß nun das Religionsedict auf einheimische sowohl als auswärtige Schriftsteller lebhaften Einfluß hatte, kam auch meine Abhandlung unter dem Titel: »Religion innerhalb den Gränzen der bloßen"}], "markers": [{"system": "AA", "band": "VII", "page": 5, "ref": "VII5"}], "running_header": "Vorrede (Der Streit der Facultäten)"}, {"page_id": "2487_2", "page_pdf": 2487, "page_book": 6, "page_kind": "body", "sigel": "AA VII, 6", "units": [{"type": "paragraph", "text": "Vernunft« heraus,*[1] und da ich, um keiner Schleichwege beschuldigt zu werden, allen meinen Schriften meinen Namen vorsetze, so erging an mich im Jahr 1794 folgendes Königl. Rescript, von welchem es merkwürdig ist, daß es, da ich nur meinem vertrautesten Freunde die Existenz desselben bekannt machte, auch nicht eher als jetzt öffentlich bekannt wurde."}, {"type": "paragraph", "text": "Von Gottes Gnaden Friedrich Wilhelm, König von Preußen etc. etc."}, {"type": "paragraph", "text": "Unsern gnädigen Gruß zuvor. Würdiger und Hochgelahrter, lieber Getreuer! Unsere höchste Person hat schon seit geraumer Zeit mit großem Mißfallen ersehen: wie Ihr Eure Philosophie zu Entstellung und Herabwürdigung mancher Haupt- und Grundlehren der heiligen Schrift und des Christenthums mißbraucht; wie Ihr dieses namentlich in Eurem Buch: »Religion innerhalb der Gränzen der bloßen Vernunft,« desgleichen in anderen, kleineren Abhandlungen gethan habt. Wir haben Uns zu Euch eines Besseren versehen, da Ihr selbst einsehen müsset, wie unverantwortlich Ihr dadurch gegen Eure Pflicht als Lehrer der Jugend und gegen Unsere Euch sehr wohl bekannte landesväterliche Absichten handelt. Wir verlangen des ehsten Eure gewissenhafteste Verantwortung und gewärtigen Uns von Euch bei Vermeidung Unserer höchsten Ungnade, daß Ihr Euch künftighin Nichts dergleichen werdet zu Schulden kommen lassen, sondern vielmehr Eurer Pflicht gemäß Euer Ansehen und Eure Talente dazu anwenden, daß Unsere landesväterliche Intention je mehr und mehr erreicht werde; widrigenfalls Ihr Euch bei fortgesetzter Renitenz unfehlbar unangenehmer Verfügungen zu gewärtigen habt. Sind Euch mit Gnade gewogen. Berlin, den 1. October 1794."}, {"type": "paragraph", "text": "Auf Seiner Königl. Majestät allergnädigsten _Special_befehl. Woellner."}], "markers": [{"system": "AA", "band": "VII", "page": 6, "ref": "VII6"}], "running_header": "Vorrede (Der Streit der Facultäten)"}, {"page_id": "2487_3", "page_pdf": 2487, "page_book": 7, "page_kind": "body", "sigel": "AA VII, 7", "units": [{"type": "paragraph", "text": "_ab extra – _Dem würdigen und hochgelahrten, Unserem Professor, auch lieben, getreuen _Kant _ zu"}], "markers": [{"system": "AA", "band": "VII", "page": 7, "ref": "VII7"}], "running_header": "Vorrede (Der Streit der Facultäten)"}, {"page_id": "2488_0", "page_pdf": 2488, "page_book": 7, "page_kind": "body", "sigel": "AA VII, 7", "units": [{"type": "paragraph", "text": "Königsberg in Preußen. _praesentat. _d. 12. Oct. 1794."}, {"type": "paragraph", "text": "Worauf meinerseits folgende allerunterthänigste Antwort abgestattet wurde."}, {"type": "paragraph", "text": "Allergnädigster etc. etc. Ew. Königl. Maj. allerhöchster den 1sten _October c. _an mich ergangener und den 12ten _eiusd. _ mir gewordener Befehl legt es mir zur devotesten Pflicht auf: Erstlich »wegen des Mißbrauchs meiner Philosophie in Entstellung und Herabwürdigung mancher Haupt- und Grundlehren der heil. Schrift und des Christenthums, namentlich in meinem Buch: »Religion innerhalb den Gränzen der bloßen Vernunft,« desgleichen in anderen, kleineren Abhandlungen und der hiedurch auf mich fallenden Schuld der Übertretung meiner Pflicht als Lehrer der Jugend und gegen die höchste, mir sehr wohl bekannte landesväterliche Absichten eine gewissenhafte Verantwortung beizubringen.« Zweitens auch, »nichts dergleichen künftighin mir zu Schulden kommen zu lassen.« – In Ansehung beider Stücke ermangle nicht den Beweis meines allerunterthänigsten Gehorsams Ew. Königl. Maj. in folgender Erklärung zu Füßen zu legen: Was das Erste, nämlich die gegen mich erhobene Anklage, betrifft, so ist meine gewissenhafte Verantwortung folgende: Daß ich als Lehrer der Jugend, d.i., wie ich es verstehe, in akademischen Vorlesungen, niemals Beurtheilung der heil. Schrift und des Christenthums eingemischt habe, noch habe einmischen können, würden schon die von mir zum Grunde gelegte Handbücher Baumgartens, als welche allein einige Beziehung auf einen solchen Vortrag haben dürften, beweisen: weil in diesen nicht einmal ein Titel von Bibel und Christenthum enthalten ist und als bloßer Philosophie auch nicht enthalten sein kann; der Fehler aber, über die Gränzen einer vorhabenden Wissenschaft auszuschweifen, oder sie in einander laufen zu lassen, mir, der ich ihn jederzeit gerügt und dawider gewarnt habe, am wenigsten wird vorgeworfen werden können. Daß ich auch nicht etwa als Volkslehrer , in Schriften, namentlich"}], "running_header": "Vorrede (Der Streit der Facultäten)"}, {"page_id": "2488_1", "page_pdf": 2488, "page_book": 8, "page_kind": "body", "sigel": "AA VII, 8", "units": [{"type": "paragraph", "text": "nicht im Buche: »Religion innerhalb den Gränzen u.s.w.,« mich gegen die allerhöchste, mir bekannte landesväterliche Absichten vergangen, d.i. der öffentlichen Landesreligion Abbruch gethan habe; welches schon daraus erhellt, daß jenes Buch dazu gar nicht geeignet, vielmehr für das Publicum ein unverständliches, verschlossenes Buch und nur eine Verhandlung zwischen Facultätsgelehrten vorstellt, wovon das Volk keine Notiz nimmt; in Ansehung deren aber die Facultäten selbst frei bleiben, nach ihrem besten Wissen und Gewissen öffentlich zu urtheilen, und nur die eingesetzte Volkslehrer (in Schulen und auf Kanzeln) an dasjenige Resultat jener Verhandlungen, was die Landesherrschaft zum öffentlichen Vortrage für diese sanctionirt, gebunden werden, und zwar darum, weil die letztere sich ihren eigenen Religionsglauben auch nicht selbst ausgedacht, sondern ihn nur auf demselben Wege, nämlich der Prüfung und Berichtigung durch dazu sich qualificirende Facultäten (die theologische und philosophische), hat überkommen können, mithin die Landesherrschaft diese nicht allein zuzulassen, sondern auch von ihnen zu fordern berechtigt ist, alles, was sie einer öffentlichen Landesreligion zuträglich finden, durch ihre Schriften zur Kenntniß der Regierung gelangen zu lassen. Daß ich in dem genannten Buche, weil es gar keine Würdigung des Christenthums enthält, mir auch keine Abwürdigung desselben habe zu Schulden kommen lassen: denn eigentlich enthält es nur die Würdigung der natürlichen Religion. Die Anführung einiger biblischer Schriftstellen zur Bestätigung gewisser reiner Vernunftlehren der Religion kann allein zu diesem Mißverstande Veranlassung gegeben haben. Aber der sel. Michaelis, der in seiner philosophischen Moral eben so verfuhr, erklärte sich schon hierüber dahin, daß er dadurch weder etwas Biblisches in die Philosophie hinein, noch etwas Philosophisches aus der Bibel heraus zu bringen gemeint sei, sondern nur seinen Vernunftsätzen durch wahre oder vermeinte Einstimmung"}], "markers": [{"system": "AA", "band": "VII", "page": 8, "ref": "VII8"}], "running_header": "Vorrede (Der Streit der Facultäten)"}, {"page_id": "2489_0", "page_pdf": 2489, "page_book": 8, "page_kind": "body", "sigel": "AA VII, 8", "units": [{"type": "paragraph", "text": "mit Anderer (vielleicht Dichter und Redner) Urtheile Licht und Bestätigung gäbe. – Wenn aber die Vernunft hiebei so spricht, als ob sie für sich selbst hinlänglich, die Offenbarungslehre also überflüssig wäre (welches, wenn es objectiv so verstanden werden sollte, wirklich für Abwürdigung des Christenthums gehalten werden müßte), so ist dieses wohl nichts, als der Ausdruck der Würdigung ihrer selbst; nicht nach ihrem Vermögen, nach dem, was sie als zu thun vorschreibt, sofern aus ihr allein Allgemeinheit, Einheit und Nothwendigkeit der Glaubenslehren hervorgeht, die das Wesentliche einer Religion überhaupt ausmachen,"}], "running_header": "Vorrede (Der Streit der Facultäten)"}, {"page_id": "2489_1", "page_pdf": 2489, "page_book": 9, "page_kind": "body", "sigel": "AA VII, 9", "units": [{"type": "paragraph", "text": "welches im Moralisch-Praktischen (dem, was wir thun sollen) besteht, wogegen das, was wir auf historische Beweisgründe zu glauben Ursache haben (denn hiebei gilt kein Sollen), d.i. die Offenbarung als an sich zufällige Glaubenslehre, für außerwesentlich, darum aber doch nicht für unnöthig und überflüssig angesehen wird; weil sie den theoretischen Mangel des reinen Vernunftglaubens, den dieser nicht abläugnet, z.B. in den Fragen über den Ursprung des Bösen, den Übergang von diesem zum Guten, die Gewißheit des Menschen im letzteren Zustande zu sein u.dgl., zu ergänzen dienlich und als Befriedigung eines Vernunftbedürfnisses dazu nach Verschiedenheit der Zeitumstände und der Personen mehr oder weniger beizutragen behülflich ist. Daß ich ferner meine große Hochachtung für die biblische Glaubenslehre im Christenthum unter anderen auch durch die Erklärung in demselben obbenannten Buche bewiesen habe, daß die Bibel, als das beste vorhandene, zur Gründung und Erhaltung einer wahrhaftig seelenbessernden Landesreligion auf unabsehliche Zeiten taugliche Leitmittel der öffentlichen Religionsunterweisung darin von mir angepriesen und daher auch die Unbescheidenheit gegen die theoretische, Geheimniß enthaltende Lehren derselben in Schulen oder auf Kanzeln, oder in Volksschriften (denn in Facultäten muß es erlaubt sein), Einwürfe und Zweifel dagegen zu erregen von mir getadelt und für Unfug erklärt worden; welches aber noch nicht die größte Achtungsbezeigung für das Christenthum ist. Denn die hier aufgeführte Zusammenstimmung desselben mit dem reinsten moralischen Vernunftglauben ist die beste und dauerhafteste Lobrede desselben: weil eben dadurch, nicht durch historische Gelehrsamkeit das so oft entartete Christenthum immer wieder hergestellt worden ist und ferner bei ähnlichen Schicksalen, die auch künftig nicht ausbleiben werden, allein wiederum hergestellt werden kann. Daß ich endlich, so wie ich anderen Glaubensbekennern jederzeit und vorzüglich gewissenhafte Aufrichtigkeit, nicht mehr davon vorzugeben und anderen als Glaubensartikel aufzudringen, als sie selbst davon gewiß sind, empfohlen, ich auch diesen Richter in mir selbst bei Abfassung meiner Schriften jederzeit als mir zur Seite stehend vorgestellt habe, um mich von jedem nicht allein seelenverderblichen Irrthum, sondern selbst jeder Anstoß erregenden Unbehutsamkeit im Ausdruck entfernt zu halten; weshalb ich auch jetzt in meinem 71sten Lebensjahre, wo der Gedanke leicht aufsteigt, es könne wohl sein, daß ich für alles dieses in Kurzem einem Weltrichter"}], "markers": [{"system": "AA", "band": "VII", "page": 9, "ref": "VII9"}], "running_header": "Vorrede (Der Streit der Facultäten)"}, {"page_id": "2489_2", "page_pdf": 2489, "page_book": 10, "page_kind": "body", "sigel": "AA VII, 10", "units": [{"type": "paragraph", "text": "als Herzenskündiger Rechenschaft geben müsse, die gegenwärtige mir wegen meiner Lehre abgeforderte Verantwortung als mit völliger Gewissenhaftigkeit abgefaßt freimüthig einreichen kann. Was den zweiten Punkt betrifft, mir keine dergleichen (angeschuldigte) Entstellung und Herabwürdigung des Christenthums künftighin zu Schulden kommen zu lassen: so halte ich, um auch dem mindesten Verdachte darüber vorzubeugen, für das Sicherste, hiemit, als Ew. Königl. Maj. getreuester Unterthan,*[2] feierlichst zu erklären: daß ich mich fernerhin aller öffentlichen Vorträge die Religion betreffend, es sei die natürliche oder geoffenbarte, sowohl in Vorlesungen als in Schriften gänzlich enthalten werde. In tiefster Devotion ersterbe ich u.s.w."}, {"type": "paragraph", "text": "Die weitere Geschichte des fortwährenden Treibens zu einem sich immer mehr von der Vernunft entfernenden Glauben ist bekannt. Die Prüfung der Candidaten zu geistlichen Ämtern ward nun einer Glaubenscommission"}], "markers": [{"system": "AA", "band": "VII", "page": 10, "ref": "VII10"}], "running_header": "Vorrede (Der Streit der Facultäten)"}, {"page_id": "2490_0", "page_pdf": 2490, "page_book": 10, "page_kind": "body", "sigel": "AA VII, 10", "units": [{"type": "paragraph", "text": "anvertraut, der ein _Schema Examinationis _nach pietistischem Zuschnitte zum Grunde lag, welche gewissenhafte Candidaten der Theologie zu Schaaren von geistlichen Ämtern verscheuchte und die Juristenfacultät übervölkerte; eine Art von Auswanderung, die zufälligerweise nebenbei auch ihren Nutzen gehabt haben mag. – Um einen kleinen Begriff vom Geiste dieser Commission zu geben: so ward nach der Forderung einer vor der Begnadigung nothwendig vorhergehenden Zerknirschung noch ein tiefer reuiger Gram (_maeror animi_) erfordert und von diesem nun gefragt, ob ihn der Mensch sich auch selbst geben könne. _Quod negandum ac pernegandum_, war die Antwort; der reuvolle Sünder muß sich diese Reue besonders vom Himmel erbitten. – Nun fällt ja in die Augen: daß den, welcher um Reue (über seine Übertretung) noch bitten muß, seine That wirklich nicht reuet; welches eben so widersprechend aussieht, als wenn es vom Gebet heißt: es müsse, wenn es erhörlich sein soll, im Glauben geschehen. Denn wenn der Beter den Glauben hat, so braucht er nicht darum zu bitten: hat er ihn aber nicht, so kann er nicht erhörlich bitten. —————"}, {"type": "paragraph", "text": "Diesem Unwesen ist nunmehr gesteuret. Denn nicht allein zum bürgerlichen Wohl des gemeinen Wesens überhaupt, dem Religion ein"}], "running_header": "Vorrede (Der Streit der Facultäten)"}, {"page_id": "2490_1", "page_pdf": 2490, "page_book": 11, "page_kind": "body", "sigel": "AA VII, 11", "units": [{"type": "paragraph", "text": "höchstwichtiges Staatsbedürfniß ist, sondern besonders zum Vortheil der Wissenschaften vermittelst eines diesen zu befördern eingesetzten Oberschulcollegiums – hat sich neuerdings das glückliche Eräugniß zugetragen, daß die Wahl einer weisen Landesregierung einen erleuchteten Staatsmann getroffen hat, welcher nicht durch einseitige Vorliebe für ein besonderes Fach derselben (die Theologie), sondern in Hinsicht auf das ausgebreitete Interesse des ganzen Lehrstandes zur Beförderung desselben Beruf, Talent und Willen hat und so das Fortschreiten der Cultur im Felde der Wissenschaften wider alle neue Eingriffe der Obscuranten sichern wird."}, {"type": "paragraph", "text": "* * *"}, {"type": "paragraph", "text": "Unter dem allgemeinen Titel: »der Streit der Facultäten« erscheinen hier drei in verschiedener Absicht, auch zu verschiedenen Zeiten von mir abgefaßte, gleichwohl aber doch zur systematischen Einheit ihrer Verbindung in einem Werk geeignete Abhandlungen, von denen ich nur späterhin inne ward, daß sie als der Streit der unteren mit den drei oberen (um der Zerstreuung vorzubeugen) schicklich in Einem Bande sich zusammen finden können."}, {"type": "paragraph", "text": "—————"}, {"type": "paragraph", "text": "Anmerkungen: *[1] Diese Betitelung war absichtlich so gestellt, damit man jene Abhandlung nicht dahin deutete: als sollte sie die Religion aus bloßer Vernunft (ohne Offenbarung) bedeuten; denn das wäre zu viel Anmaßung gewesen: weil es doch sein konnte, daß die Lehren derselben von übernatürlich inspirirten Männern herrührten; sondern daß ich nur dasjenige, was im Text der für geoffenbart geglaubten Religion, der Bibel, auch durch bloße Vernunft erkannt werden kann, hier in einem Zusammenhange vorstellig machen wollte. *[2] Auch diesen Ausdruck wählte ich vorsichtig, damit ich nicht der Freiheit meines Urtheils in diesem Religionsproceß auf immer, sondern nur so lange Se. Maj. am Leben wäre, entsagte."}], "markers": [{"system": "AA", "band": "VII", "page": 11, "ref": "VII11"}], "running_header": "Vorrede (Der Streit der Facultäten)"}, {"page_id": "2491_0", "page_pdf": 2491, "page_book": 12, "page_kind": "title_page", "sigel": "AA VII, 12", "units": [{"type": "paragraph", "text": "Erster Abschnitt. Der Streit der philosophischen Facultät mit der theologischen."}]}, {"page_id": "2491_1", "page_pdf": 2491, "page_book": 15, "page_kind": "title_page", "sigel": "AA VII, 15", "units": [], "markers": [{"system": "AA", "band": "VII", "page": 15, "ref": "VII15"}]}, {"page_id": "2492_0", "page_pdf": 2492, "page_book": 16, "page_kind": "body", "sigel": "AA VII, 16", "units": [{"type": "paragraph", "text": "Einleitung."}], "running_header": "Einleitung (Streit der Facultäten)"}, {"page_id": "2492_1", "page_pdf": 2492, "page_book": 17, "page_kind": "body", "sigel": "AA VII, 17", "units": [{"type": "paragraph", "text": "Es war kein übeler Einfall desjenigen, der zuerst den Gedanken faßte und ihn zur öffentlichen Ausführung vorschlug, den ganzen Inbegriff der Gelehrsamkeit (eigentlich die derselben gewidmeten Köpfe) gleichsam fabrikenmäßig, durch Vertheilung der Arbeiten, zu behandeln, wo, so viel es Fächer der Wissenschaften giebt, so viel öffentliche Lehrer, Professoren, als Depositeure derselben angestellt würden, die zusammen eine Art von gelehrtem gemeinen Wesen, Universität (auch hohe Schule) genannt, ausmachten, die ihre Autonomie hätte (denn über Gelehrte als solche können nur Gelehrte urtheilen); die daher vermittelst ihrer Facultäten* (kleiner, nach Verschiedenheit der Hauptfächer der Gelehrsamkeit, in welche sich die Universitätsgelehrte theilen, verschiedener Gesellschaften) theils die aus niedern Schulen zu ihr aufstrebende Lehrlinge aufzunehmen, theils auch freie (keine Glieder derselben ausmachende) Lehrer, Doctoren genannt, nach vorhergehender Prüfung aus eigner Macht mit einem von jedermann anerkannten Rang zu versehen (ihnen einen Grad zu ertheilen), d.i. sie zu creiren, berechtigt wäre."}], "markers": [{"system": "AA", "band": "VII", "page": 17, "ref": "VII17"}], "running_header": "Einleitung (Streit der Facultäten)"}, {"page_id": "2492_2", "page_pdf": 2492, "page_book": 18, "page_kind": "body", "sigel": "AA VII, 18", "units": [{"type": "paragraph", "text": "Außer diesen zünftigen kann es noch zunftfreie Gelehrte geben, die nicht zur Universität gehören, sondern, indem sie blos einen Theil des großen Inbegriffs der Gelehrsamkeit bearbeiten, entweder gewisse freie Corporationen (Akademien, auch Societäten der Wissenschaften genannt) als so viel Werkstätten ausmachen, oder gleichsam im Naturzustande der Gelehrsamkeit leben und jeder für sich ohne öffentliche Vorschrift und Regel sich mit Erweiterung oder Verbreitung derselben als Liebhaber beschäftigen. Von den eigentlichen Gelehrten sind noch die Litteraten (Studirte) zu unterscheiden, die als Instrumente der Regierung, von dieser zu ihrem eigenen Zweck (nicht eben zum Besten der Wissenschaften) mit einem Amte bekleidet, zwar auf der Universität ihre Schule gemacht haben müssen, allenfalls aber Vieles davon (was die Theorie betrifft) auch können vergessen haben, wenn sie nur so viel, als zu Führung eines bürgerlichen Amts, das seinen Grundlehren nach nur von Gelehrten ausgehen kann, erforderlich ist, nämlich empirische Kenntniß der Statuten ihres Amts (was also die Praxis angeht), übrig behalten haben; die man also Geschäftsleute oder Werkkundige der Gelehrsamkeit nennen kann. Diese, weil sie als Werkzeuge der Regierung (Geistliche, Justizbeamte und Ärzte) aufs Publicum gesetzlichen Einfluß haben und eine besondere Klasse von Litteraten ausmachen, die nicht frei sind, aus eigener Weisheit, sondern nur unter der Censur der Facultäten von der Gelehrsamkeit öffentlichen Gebrauch zu machen, müssen, weil sie sich unmittelbar ans Volk wenden, welches aus Idioten besteht (wie etwa der Klerus an die Laiker), in ihrem Fache aber zwar nicht die gesetzgebende, doch zum Theil die ausübende Gewalt haben, von der Regierung sehr in Ordnung gehalten werden, damit sie sich nicht über die richtende, welche den Facultäten zukommt, wegsetzen."}, {"type": "paragraph", "text": "Anmerkungen: * Deren jede ihren Decan als Regenten der Facultät hat. Dieser aus der Astrologie entlehnte Titel, der ursprünglich einen der 3 Astralgeister bedeutete, welche einem Zeichen des Thierkreises (von 30) vorstehen, deren jeder 10 Grade anführt, ist von den Gestirnen zuerst auf die Feldläger (_ab astris ad castra. vid. Salmasius _ _de annis climacteriis pag._ 561) und zuletzt gar auf die Universitäten gezogen worden; ohne doch hiebei eben auf die Zahl 10 (der Professoren) zu sehen. Man wird es den Gelehrten nicht verdenken, daß sie, von denen fast alle Ehrentitel, mit denen sich jetzt Staatsleute ausschmücken, zuerst ausgedacht sind, sich selbst nicht vergessen haben."}], "markers": [{"system": "AA", "band": "VII", "page": 18, "ref": "VII18"}], "running_header": "Einleitung (Streit der Facultäten)"}, {"page_id": "2493_0", "page_pdf": 2493, "page_book": 18, "page_kind": "body", "sigel": "AA VII, 18", "units": [{"type": "paragraph", "text": "Eintheilung der Facultäten überhaupt."}], "running_header": "Eintheilung der Facultäten überhaupt"}, {"page_id": "2493_1", "page_pdf": 2493, "page_book": 18, "page_kind": "body", "sigel": "AA VII, 18", "units": [{"type": "paragraph", "text": "Nach dem eingeführten Brauch werden sie in zwei Klassen, die der drei obern Facultäten und die einer untern, eingetheilt. Man sieht wohl, daß bei dieser Eintheilung und Benennung nicht der Gelehrtenstand, sondern die Regierung befragt worden ist. Denn zu den obern werden nur diejenigen gezählt, deren Lehren, ob sie so oder anders beschaffen sein, oder öffentlich vorgetragen werden sollen, es die Regierung selbst interessirt; da hingegen diejenige, welche nur das Interesse der"}], "markers": [{"system": "AA", "band": "VII", "page": 18, "ref": "VII18"}], "running_header": "Eintheilung der Facultäten überhaupt"}, {"page_id": "2493_2", "page_pdf": 2493, "page_book": 19, "page_kind": "body", "sigel": "AA VII, 19", "units": [{"type": "paragraph", "text": "Wissenschaft zu besorgen hat, die untere genannt wird, weil diese es mit ihren Sätzen halten mag, wie sie es gut findet. Die Regierung aber interessirt das am allermeisten, wodurch sie sich den stärksten und daurendsten Einfluß aufs Volk verschafft, und dergleichen sind die Gegenstände der oberen Facultäten. Daher behält sie sich das Recht vor, die Lehren der oberen selbst zu sanctioniren; die der untern überläßt sie der eigenen Vernunft des gelehrten Volks. – Wenn sie aber gleich Lehren sanctionirt, so lehrt sie (die Regierung) doch nicht selbst; sondern will nur, daß gewisse Lehren von den respectiven Facultäten in ihren öffentlichen Vortrag aufgenommen und die ihnen entgegengesetzte davon ausgeschlossen werden sollen. Denn sie lehrt nicht, sondern befehligt nur die, welche lehren (mit der Wahrheit mag es bewandt sein, wie es wolle), weil sie sich bei Antretung ihres Amts*[1] durch einen Vertrag mit der Regierung dazu verstanden haben. – Eine Regierung, die sich mit den Lehren, also auch mit der Erweiterung oder Verbesserung der Wissenschaften befaßte, mithin selbst in höchster Person den Gelehrten spielen wollte, würde sich durch diese Pedanterei nur um die ihr schuldige Achtung bringen, und es ist unter ihrer Würde, sich mit dem Volk (dem Gelehrtenstande desselben) gemein zu machen, welches keinen Scherz versteht und alle, die sich mit Wissenschaften bemengen, über einen Kamm schiert. Es muß zum gelehrten gemeinen Wesen durchaus auf der Universität noch eine Facultät geben, die, in Ansehung ihrer Lehren vom Befehle der Regierung unabhängig**[2], keine Befehle zu geben, aber doch alle zu"}], "markers": [{"system": "AA", "band": "VII", "page": 19, "ref": "VII19"}], "running_header": "Eintheilung der Facultäten überhaupt"}, {"page_id": "2493_3", "page_pdf": 2493, "page_book": 20, "page_kind": "body", "sigel": "AA VII, 20", "units": [{"type": "paragraph", "text": "beurtheilen die Freiheit habe, die mit dem wissenschaftlichen Interesse, d.i. mit dem der Wahrheit, zu thun hat, wo die Vernunft öffentlich zu sprechen berechtigt sein muß: weil ohne eine solche die Wahrheit (zum Schaden der Regierung selbst) nicht an den Tag kommen würde, die Vernunft aber ihrer Natur nach frei ist und keine Befehle etwas für wahr zu halten (kein _crede_, sondern nur ein freies _credo_) annimmt. – Daß aber eine solche Facultät unerachtet dieses großen Vorzugs (der Freiheit) dennoch die untere genannt wird, davon ist die Ursache in der Natur des Menschen anzutreffen: daß nämlich der, welcher befehlen kann, ob er gleich ein demüthiger Diener eines andern ist, sich doch vornehmer dünkt als ein anderer, der zwar frei ist, aber niemanden zu befehlen hat."}, {"type": "paragraph", "text": "Anmerkungen: *[1] Man muß es gestehen, daß der Grundsatz des großbritannischen Parlaments: die Rede ihres Königes vom Thron sei als ein Werk seines Ministers anzusehen (da es der Würde eines Monarchen zuwider sein würde, sich Irrthum, Unwissenheit oder Unwahrheit vorrücken zu lassen, gleichwohl aber das Haus über ihren Inhalt zu urtheilen, ihn zu prüfen und anzufechten berechtigt sein muß), daß, sage ich, dieser Grundsatz sehr fein und richtig ausgedacht sei. Eben so muß auch die Auswahl gewisser Lehren, welche die Regierung zum öffentlichen Vortrage ausschließlich sanctionirt, der Prüfung der Gelehrten ausgesetzt bleiben, weil sie nicht als das Product des Monarchen, sondern eines dazu befehligten Staatsbeamten, von dem man annimmt, er könne auch wohl den Willen seines Herrn nicht recht verstanden oder auch verdreht haben, angesehen werden muß."}], "markers": [{"system": "AA", "band": "VII", "page": 20, "ref": "VII20"}], "running_header": "Eintheilung der Facultäten überhaupt"}, {"page_id": "2494", "page_pdf": 2494, "page_book": 20, "page_kind": "body", "sigel": "AA VII, 20", "units": [{"type": "paragraph", "text": "**[2] Ein französischer Minister berief einige der angesehensten Kaufleute zu sich und verlangte von ihnen Vorschläge, wie dem Handel aufzuhelfen sei: gleich als ob er darunter die beste zu wählen verstände. Nachdem Einer dies, der Andere das in Vorschlag gebracht hatte, sagte ein alter Kaufmann, der so lange geschwiegen hatte: Schafft gute Wege, schlagt gut Geld, gebt ein promptes Wechselrecht u.d.gl., übrigens aber »laßt uns machen«! Dies wäre ungefähr die Antwort, welche die philosophische Facultät zu geben hätte, wenn die Regierung sie um die Lehren befrüge, die sie den Gelehrten überhaupt vorzuschreiben habe: den Fortschritt der Einsichten und Wissenschaften nur nicht zu hindern."}], "markers": [{"system": "AA", "band": "VII", "page": 20, "ref": "VII20"}], "running_header": "Eintheilung der Facultäten überhaupt"}, {"page_id": "2495_0", "page_pdf": 2495, "page_book": 20, "page_kind": "body", "sigel": "AA VII, 20", "units": [{"type": "paragraph", "text": "I. Vom Verhältnisse der Facultäten. *Erster Abschnitt.* Begriff und Eintheilung der oberen Facultäten."}], "running_header": "1 Abschn. Begriff und Eintheilung der oberen Facultäten"}, {"page_id": "2495_1", "page_pdf": 2495, "page_book": 21, "page_kind": "body", "sigel": "AA VII, 21", "units": [{"type": "paragraph", "text": "Man kann annehmen, daß alle künstliche Einrichtungen, welche eine Vernunftidee (wie die von einer Regierung ist) zum Grunde haben, die sich an einem Gegenstande der Erfahrung (dergleichen das ganze gegenwärtige Feld der Gelehrsamkeit) praktisch beweisen soll, nicht durch blos zufällige Aufsammlung und willkürliche Zusammenstellung vorkommender Fälle, sondern nach irgend einem in der Vernunft, wenn gleich nur dunkel, liegenden Princip und darauf gegründetem Plan versucht worden sind, der eine gewisse Art der Eintheilung nothwendig macht. Aus diesem Grunde kann man annehmen, daß die Organisation einer Universität in Ansehung ihrer Klassen und Facultäten nicht so ganz vom Zufall abgehangen habe, sondern daß die Regierung, ohne deshalb eben ihr frühe Weisheit und Gelehrsamkeit anzudichten, schon durch ihr eignes gefühltes Bedürfniß (vermittelst gewisser Lehren aufs Volk zu wirken)_ a priori _auf ein Princip der Eintheilung, was sonst empirischen Ursprungs zu sein scheint, habe kommen können, das mit dem jetzt angenommenen glücklich zusammentrifft; wiewohl ich ihr darum, als ob sie fehlerfrei sei, nicht das Wort reden will. Nach der Vernunft (d.h. objectiv) würden die Triebfedern, welche die Regierung zu ihrem Zweck (auf das Volk Einfluß zu haben) benutzen kann, in folgender Ordnung stehen: zuerst eines jeden ewiges Wohl, dann das bürgerliche als Glied der Gesellschaft, endlich das Leibeswohl (lange leben und gesund sein). Durch die öffentlichen Lehren in Ansehung des ersten kann die Regierung selbst auf das Innere der Gedanken"}], "markers": [{"system": "AA", "band": "VII", "page": 21, "ref": "VII21"}], "running_header": "1 Abschn. Begriff und Eintheilung der oberen Facultäten"}, {"page_id": "2495_2", "page_pdf": 2495, "page_book": 22, "page_kind": "body", "sigel": "AA VII, 22", "units": [{"type": "paragraph", "text": "und die verschlossensten Willensmeinungen der Unterthanen, jene zu entdecken, diese zu lenken, den größten Einfluß haben; durch die, so sich aufs zweite beziehen, ihr äußeres Verhalten unter dem Zügel öffentlicher Gesetze halten; durch die dritte sich die Existenz eines starken und zahlreichen Volks sichern, welches sie zu ihren Absichten brauchbar findet. – – Nach der Vernunft würde also wohl die gewöhnlich angenommene Rangordnung unter den oberen Facultäten Statt finden; nämlich zuerst die theologische, darauf die der Juristen und zuletzt die medicinische Facultät. Nach dem Naturinstinct hingegen würde dem Menschen der Arzt der wichtigste Mann sein, weil dieser ihm sein Leben fristet, darauf allererst der Rechtserfahrne, der ihm das zufällige Seine zu erhalten verspricht, und nur zuletzt (fast nur, wenn es zum Sterben kommt), ob es zwar um die Seligkeit zu thun ist, der Geistliche gesucht werden: weil auch dieser selbst, so sehr er auch die Glückseligkeit der künftigen Welt preiset, doch, da er nichts von ihr vor sich sieht, sehnlich wünscht, von dem Arzt in diesem Jammerthal immer noch einige Zeit erhalten zu werden."}, {"type": "paragraph", "text": "* * *"}, {"type": "paragraph", "text": "Alle drei obere Facultäten gründen die ihnen von der Regierung anvertraute Lehren auf Schrift, welches im Zustande eines durch Gelehrsamkeit geleiteten Volks auch nicht anders sein kann, weil ohne diese es keine beständige, für jedermann zugängliche Norm, darnach es sich richten könnte, geben würde. Daß eine solche Schrift (oder Buch) Statute, d.i. von der Willkür eines Obern ausgehende (für sich selbst nicht aus der Vernunft entspringende) Lehren, enthalten müsse, versteht sich von selbst, weil diese sonst nicht als von der Regierung sanctionirt schlechthin Gehorsam fordern könnte, und dieses gilt auch von dem Gesetzbuche selbst in Ansehung derjenigen öffentlich vorzutragenden Lehren, die zugleich aus der Vernunft abgeleitet werden könnten, auf deren Ansehen aber jenes keine Rücksicht nimmt, sondern den Befehl eines äußeren Gesetzgebers zum Grunde legt. – Von dem Gesetzbuch, als dem Kanon, sind diejenigen Bücher, welche als (vermeintlich) vollständiger Auszug des Geistes des Gesetzbuchs zum faßlichern Begriff und sicherern Gebrauch des gemeinen Wesens (der Gelehrten und"}], "markers": [{"system": "AA", "band": "VII", "page": 22, "ref": "VII22"}], "running_header": "1 Abschn. Begriff und Eintheilung der oberen Facultäten"}, {"page_id": "2496_0", "page_pdf": 2496, "page_book": 22, "page_kind": "body", "sigel": "AA VII, 22", "units": [{"type": "paragraph", "text": "Ungelehrten) von den Facultäten abgefaßt werden, wie etwa die symbolischen Bücher, gänzlich unterschieden. Sie können nur verlangen als Organon, um den Zugang zu jenem zu"}], "running_header": "1 Abschn. Begriff und Eintheilung der oberen Facultäten"}, {"page_id": "2496_1", "page_pdf": 2496, "page_book": 23, "page_kind": "body", "sigel": "AA VII, 23", "units": [{"type": "paragraph", "text": "erleichtern, angesehen zu werden und haben gar keine Autorität; selbst dadurch nicht, daß sich etwa die vornehmsten Gelehrten von einem gewissen Fache darüber geeinigt haben, ein solches Buch statt Norm für ihre Facultät gelten zu lassen, wozu sie gar nicht befugt sind, sondern sie einstweilen als Lehrmethode einzuführen, die aber nach Zeitumständen veränderlich bleibt und überhaupt auch nur das Formale des Vortrags betreffen kann, im Materialen der Gesetzgebung aber schlechterdings nichts ausmacht. Daher schöpft der biblische Theolog (als zur obern Facultät gehörig) seine Lehren nicht aus der Vernunft, sondern aus der Bibel, der Rechtslehrer nicht aus dem Naturrecht, sondern aus dem Landrecht, der Arzneigelehrte seine ins Publicum gehende Heilmethode nicht aus der Physik des menschlichen Körpers, sondern aus der Medicinalordnung. – So bald eine dieser Facultäten etwas als aus der Vernunft Entlehntes einzumischen wagt: so verletzt sie die Autorität der durch sie gebietenden Regierung und kommt ins Gehege der philosophischen, die ihr alle glänzende von jener geborgte Federn ohne Verschonen abzieht und mit ihr nach dem Fuß der Gleichheit und Freiheit verfährt. – Daher müssen die obern Facultäten am meisten darauf bedacht sein, sich mit der untern ja nicht in Mißheirath einzulassen, sondern sie fein weit in ehrerbietiger Entfernung von sich abzuhalten, damit das Ansehen ihrer Statute nicht durch die freien Vernünfteleien der letzteren Abbruch leide."}], "markers": [{"system": "AA", "band": "VII", "page": 23, "ref": "VII23"}], "running_header": "1 Abschn. Begriff und Eintheilung der oberen Facultäten"}, {"page_id": "2497_0", "page_pdf": 2497, "page_book": 23, "page_kind": "body", "sigel": "AA VII, 23", "units": [{"type": "paragraph", "text": "_A._ Eigenthümlichkeit der theologischen Facultät."}], "running_header": "A. Eigenthümlichkeit der theologischen Facultät"}, {"page_id": "2497_1", "page_pdf": 2497, "page_book": 23, "page_kind": "body", "sigel": "AA VII, 23", "units": [{"type": "paragraph", "text": "Daß ein Gott sei, beweiset der biblische Theolog daraus, daß er in der Bibel geredet hat, worin diese auch von seiner Natur (selbst bis dahin, wo die Vernunft mit der Schrift nicht Schritt halten kann, z.B. vom unerreichbaren Geheimniß seiner dreifachen Persönlichkeit) spricht. Daß aber Gott selbst durch die Bibel geredet habe, kann und darf, weil es eine Geschichtssache ist, der biblische Theolog als ein solcher nicht beweisen; denn das gehört zur philosophischen Facultät. Er wird es also als Glaubenssache auf ein gewisses (freilich nicht erweisliches oder erklärliches) Gefühl der Göttlichkeit derselben selbst für den Gelehrten gründen, die Frage aber wegen dieser Göttlichkeit (im buchstäblichen Sinne genommen) des Ursprungs derselben im öffentlichen Vortrage ans Volk gar nicht aufwerfen"}], "markers": [{"system": "AA", "band": "VII", "page": 23, "ref": "VII23"}], "running_header": "A. Eigenthümlichkeit der theologischen Facultät"}, {"page_id": "2497_2", "page_pdf": 2497, "page_book": 24, "page_kind": "body", "sigel": "AA VII, 24", "units": [{"type": "paragraph", "text": "müssen: weil dieses sich darauf als eine Sache der Gelehrsamkeit doch gar nicht versteht und hiedurch nur in vorwitzige Grübeleien und Zweifel verwickelt werden würde; da man hingegen hierin weit sicherer auf das Zutrauen rechnen kann, was das Volk in seine Lehrer setzt. – Den Sprüchen der Schrift einen mit dem Ausdruck nicht genau zusammentreffenden, sondern etwa moralischen Sinn unterzulegen, kann er auch nicht befugt sein, und da es keinen von Gott autorisirten menschlichen Schriftausleger giebt, muß der biblische Theolog eher auf übernatürliche Eröffnung des Verständnisses durch einen in alle Wahrheit leitenden Geist rechnen, als zugeben, daß die Vernunft sich darin menge und ihre (aller höheren Autorität ermangelnde) Auslegung geltend mache. – Endlich was die Vollziehung der göttlichen Gebote an unserem Willen betrifft, so muß der biblische Theolog ja nicht auf die Natur, d.i. das eigne moralische Vermögen des Menschen (die Tugend), sondern auf die Gnade (eine übernatürliche, dennoch zugleich moralische Einwirkung) rechnen, deren aber der Mensch auch nicht anders, als vermittelst eines inniglich das Herz umwandelnden Glaubens theilhaftig werden, diesen Glauben selbst aber doch wiederum von der Gnade erwarten kann. – Bemengt der biblische Theolog sich in Ansehung irgend eines dieser Sätze mit der Vernunft, gesetzt daß diese auch mit der größten Aufrichtigkeit und dem größten Ernst auf dasselbe Ziel hinstrebte, so überspringt er (wie der Bruder des Romulus) die Mauer des allein seligmachenden Kirchenglaubens und verläuft sich in das offene, freie Feld der eigenen Beurtheilung und Philosophie, wo er, der geistlichen Regierung entlaufen, allen Gefahren der Anarchie ausgesetzt ist. – Man muß aber wohl merken, daß ich hier vom reinen (_purus, putus_) biblischen Theologen rede, der von dem verschrieenen Freiheitsgeist der Vernunft und Philosophie noch nicht angesteckt ist. Denn so bald wir zwei Geschäfte von verschiedener Art vermengen und in einander laufen lassen, können wir uns von der Eigenthümlichkeit jedes einzelnen derselben keinen bestimmten Begriff machen."}], "markers": [{"system": "AA", "band": "VII", "page": 24, "ref": "VII24"}], "running_header": "A. Eigenthümlichkeit der theologischen Facultät"}, {"page_id": "2498_0", "page_pdf": 2498, "page_book": 24, "page_kind": "body", "sigel": "AA VII, 24", "units": [{"type": "paragraph", "text": "_B._ Eigenthümlichkeit der Juristenfacultät."}], "running_header": "B. Eigenthümlichkeit der Juristenfacultät"}, {"page_id": "2498_1", "page_pdf": 2498, "page_book": 24, "page_kind": "body", "sigel": "AA VII, 24", "units": [{"type": "paragraph", "text": "Der schriftgelehrte Jurist sucht die Gesetze der Sicherung des Mein und Dein (wenn er, wie er soll, als Beamter der Regierung verfährt) nicht in seiner Vernunft, sondern im öffentlich gegebenen und höchsten"}], "markers": [{"system": "AA", "band": "VII", "page": 24, "ref": "VII24"}], "running_header": "B. Eigenthümlichkeit der Juristenfacultät"}, {"page_id": "2498_2", "page_pdf": 2498, "page_book": 25, "page_kind": "body", "sigel": "AA VII, 25", "units": [{"type": "paragraph", "text": "Orts sanctionirten Gesetzbuch. Den Beweis der Wahrheit und Rechtmäßigkeit derselben, ingleichen die Vertheidigung wider die dagegen gemachte Einwendung der Vernunft kann man billigerweise von ihm nicht fordern. Denn die Verordnungen machen allererst, daß etwas recht ist, und nun nachzufragen, ob auch die Verordnungen selbst recht sein mögen, muß von den Juristen als ungereimt gerade zu abgewiesen werden. Es wäre lächerlich, sich dem Gehorsam gegen einen äußern und obersten Willen darum, weil dieser angeblich nicht mit der Vernunft übereinstimmt, entziehen zu wollen. Denn darin besteht eben das Ansehen der Regierung, daß sie den Unterthanen nicht die Freiheit läßt, nach ihren eigenen Begriffen, sondern nach Vorschrift der gesetzgebenden Gewalt über Recht und Unrecht zu urtheilen. In einem Stücke aber ist es mit der Juristenfacultät für die Praxis doch besser bestellt, als mit der theologischen: daß nämlich jene einen sichtbaren Ausleger der Gesetze hat, nämlich entweder an einem Richter, oder in der Appellation von ihm an einer Gesetzcommission und (in der höchsten) am Gesetzgeber selbst, welches in Ansehung der auszulegenden Sprüche eines heiligen Buchs der theologischen Facultät nicht so gut wird. Doch wird dieser Vorzug andererseits durch einen nicht geringeren Nachtheil aufgewogen, nämlich daß die weltlichen Gesetzbücher der Veränderung unterworfen bleiben müssen, nachdem die Erfahrung mehr oder bessere Einsichten gewährt, dahingegen das heilige Buch keine Veränderung (Verminderung oder Vermehrung) statuirt und für immer geschlossen zu sein behauptet. Auch findet die Klage der Juristen, daß es beinah vergeblich sei, eine genau bestimmte Norm der Rechtspflege (_ius certum_) zu hoffen, beim biblischen Theologen nicht statt. Denn dieser läßt sich den Anspruch nicht nehmen, daß seine Dogmatik nicht eine solche klare und auf alle Fälle bestimmte Norm enthalte. Wenn überdem die juristischen Praktiker (Advocaten oder Justizcommissarien), die dem Clienten schlecht gerathen und ihn dadurch in Schaden versetzt haben, darüber doch nicht verantwortlich sein wollen (_ob _ _consilium nemo tenetur_), so nehmen es doch die theologischen Geschäftsmänner (Prediger und Seelsorger) ohne Bedenken auf sich und stehen dafür, nämlich dem Tone nach, daß alles so auch in der künftigen Welt werde abgeurtheilt werden, als sie es in dieser abgeschlossen haben; obgleich, wenn sie aufgefordert würden, sich förmlich zu erklären, ob sie für die Wahrheit alles dessen, was sie auf biblische Autorität geglaubt wissen wollen, mit ihrer Seele Gewähr zu leisten sich getraueten,"}], "markers": [{"system": "AA", "band": "VII", "page": 25, "ref": "VII25"}], "running_header": "B. Eigenthümlichkeit der Juristenfacultät"}, {"page_id": "2498_3", "page_pdf": 2498, "page_book": 26, "page_kind": "body", "sigel": "AA VII, 26", "units": [{"type": "paragraph", "text": "sie wahrscheinlicher Weise sich entschuldigen würden. Gleichwohl liegt es doch in der Natur der Grundsätze dieser Volkslehrer, die Richtigkeit ihrer Versicherung keinesweges bezweifeln zu lassen, welches sie freilich um desto sicherer thun können, weil sie in diesem Leben keine Widerlegung derselben durch Erfahrung befürchten dürfen."}], "markers": [{"system": "AA", "band": "VII", "page": 26, "ref": "VII26"}], "running_header": "B. Eigenthümlichkeit der Juristenfacultät"}, {"page_id": "2499_0", "page_pdf": 2499, "page_book": 26, "page_kind": "body", "sigel": "AA VII, 26", "units": [{"type": "paragraph", "text": "_C_. Eigenthümlichkeit der medicinischen Facultät."}], "running_header": "C. Eigenthümlichkeit der medicinischen Facultät"}, {"page_id": "2499_1", "page_pdf": 2499, "page_book": 26, "page_kind": "body", "sigel": "AA VII, 26", "units": [{"type": "paragraph", "text": "Der Arzt ist ein Künstler, der doch, weil seine Kunst von der Natur unmittelbar entlehnt und um deswillen von einer Wissenschaft der Natur abgeleitet werden muß, als Gelehrter irgend einer Facultät untergeordnet ist, bei der er seine Schule gemacht haben und deren Beurtheilung er unterworfen bleiben muß. – Weil aber die Regierung an der Art, wie er die Gesundheit des Volks behandelt, nothwendig großes Interesse nimmt: so ist sie berechtigt durch eine Versammlung ausgewählter Geschäftsleute dieser Facultät (praktischer Ärzte) über das öffentliche Verfahren der Ärzte durch ein Obersanitätscollegium und Medicinalverordnungen Aufsicht zu haben. Die letzteren aber bestehen wegen der besondern Beschaffenheit dieser Facultät, daß sie nämlich ihre Verhaltungsregeln nicht, wie die vorigen zwei obern, von Befehlen eines Oberen, sondern aus der Natur der Dinge selbst hernehmen muß – weshalb ihre Lehren auch ursprünglich der philosophischen Facultät, im weitesten Verstande genommen, angehören müßten –, nicht sowohl in dem, was die Ärzte thun, als was sie unterlassen sollen: nämlich erstlich, daß es fürs Publicum überhaupt Ärzte, zweitens, daß es keine Afterärzte gebe (kein _ius impune occidendi _ nach dem Grundsatz: _fiat experimentum in corpore vili_)_. _Da nun die Regierung nach dem ersten Princip für die öffentliche Bequemlichkeit, nach dem zweiten für die öffentliche Sicherheit (in der Gesundheitsangelegenheit des Volks) sorgt, diese zwei Stücke aber eine Polizei ausmachen, so wird alle Medicinalordnung eigentlich nur die medicinische Polizei betreffen. Diese Facultät ist also viel freier als die beiden ersten unter den obern und der philosophischen sehr nahe verwandt; ja was die Lehren derselben betrifft, wodurch Ärzte gebildet werden, gänzlich frei, weil es für sie keine durch höchste Autorität sanctionirte, sondern nur aus der Natur geschöpfte Bücher geben kann, auch keine eigentlichen Gesetze (wenn man darunter"}], "markers": [{"system": "AA", "band": "VII", "page": 26, "ref": "VII26"}], "running_header": "C. Eigenthümlichkeit der medicinischen Facultät"}, {"page_id": "2499_2", "page_pdf": 2499, "page_book": 27, "page_kind": "body", "sigel": "AA VII, 27", "units": [{"type": "paragraph", "text": "den unveränderlichen Willen des Gesetzgebers versteht), sondern nur Verordnungen ( Edicte), welche zu kennen nicht Gelehrsamkeit ist, als zu der ein systematischer Inbegriff von Lehren erfordert wird, den zwar die Facultät besitzt, welchen aber (als in keinem Gesetzbuch enthalten) die Regierung zu sanctioniren nicht Befugniß hat, sondern jener überlassen muß, indessen sie durch Dispensatorien und Lazarethanstalten den Geschäftsleuten derselben ihre Praxis im öffentlichen Gebrauch nur zu befördern bedacht ist. – Diese Geschäftsmänner (die Ärzte) aber bleiben in Fällen, welche als die medicinische Polizei betreffend die Regierung interessiren, dem Urtheile ihrer Facultät unterworfen."}], "markers": [{"system": "AA", "band": "VII", "page": 27, "ref": "VII27"}], "running_header": "C. Eigenthümlichkeit der medicinischen Facultät"}, {"page_id": "2500_0", "page_pdf": 2500, "page_book": 27, "page_kind": "body", "sigel": "AA VII, 27", "units": [{"type": "paragraph", "text": "* Zweiter Abschnitt.* Begriff und Eintheilung der untern Facultät."}], "running_header": "2. Abschn. Begriff und Eintheilung der untern Facultaet"}, {"page_id": "2500_1", "page_pdf": 2500, "page_book": 27, "page_kind": "body", "sigel": "AA VII, 27", "units": [{"type": "paragraph", "text": "Man kann die untere Facultät diejenige Klasse der Universität nennen, die oder so fern sie sich nur mit Lehren beschäftigt, welche nicht auf den Befehl eines Oberen zur Richtschnur angenommen werden. Nun kann es zwar geschehen, daß man eine praktische Lehre aus Gehorsam befolgt; sie aber darum, weil es befohlen ist (_de par le Roi_), für wahr anzunehmen, ist nicht allein objectiv (als ein Urtheil, das nicht sein sollte), sondern auch subjectiv (als ein solches, welches kein Mensch fällen kann) schlechterdings unmöglich. Denn der irren will, wie er sagt, irrt wirklich nicht und nimmt das falsche Urtheil nicht in der That für wahr an, sondern giebt nur ein Fürwahrhalten fälschlich vor, das in ihm doch nicht anzutreffen ist. – Wenn also von der Wahrheit gewisser Lehren, die in öffentlichen Vortrag gebracht werden sollen, die Rede ist, so kann sich der Lehrer desfalls nicht auf höchsten Befehl berufen, noch der Lehrling vorgeben, sie auf Befehl geglaubt zu haben, sondern nur wenn vom Thun geredet wird. Alsdann aber muß er doch, daß ein solcher Befehl wirklich ergangen, imgleichen daß er ihm zu gehorchen verpflichtet oder wenigstens befugt sei, durch ein freies Urtheil erkennen, widrigenfalls seine Annahme ein leeres Vorgeben und Lüge ist. – Nun nennt man das Vermögen, nach der Autonomie, d.i. frei (Principien des Denkens überhaupt gemäß), zu urtheilen, die Vernunft. Also wird die philosophische Facultät darum, weil sie für die Wahrheit der Lehren, die sie aufnehmen oder auch nur einräumen soll, stehen muß, in so fern als frei und nur unter der Gesetzgebung der Vernunft, nicht der der Regierung stehend gedacht werden müssen."}], "markers": [{"system": "AA", "band": "VII", "page": 27, "ref": "VII27"}], "running_header": "2. Abschn. Begriff und Eintheilung der untern Facultaet"}, {"page_id": "2500_2", "page_pdf": 2500, "page_book": 28, "page_kind": "body", "sigel": "AA VII, 28", "units": [{"type": "paragraph", "text": "Auf einer Universität muß aber auch ein solches Departement gestiftet, d.i. es muß eine philosophische Facultät sein. In Ansehung der drei obern dient sie dazu, sie zu controlliren und ihnen eben dadurch nützlich zu werden, weil auf Wahrheit (die wesentliche und erste Bedingung der Gelehrsamkeit überhaupt) alles ankommt; die Nützlichkeit aber, welche die oberen Facultäten zum Behuf der Regierung versprechen, nur ein Moment vom zweiten Range ist. – Auch kann man allenfalls der theologischen Facultät den stolzen Anspruch, daß die philosophische ihre Magd sei, einräumen (wobei doch noch immer die Frage bleibt: ob diese ihrer gnädigen Frau die Fackel vorträgt oder die Schleppe nachträgt), wenn man sie nur nicht verjagt, oder ihr den Mund zubindet; denn eben diese Anspruchlosigkeit, blos frei zu sein, aber auch frei zu lassen, blos die Wahrheit zum Vortheil jeder Wissenschaft auszumitteln und sie zum beliebigen Gebrauch der oberen Facultäten hinzustellen, muß sie der Regierung selbst als unverdächtig, ja als unentbehrlich empfehlen. Die philosophische Facultät enthält nun zwei Departemente, das eine der historischen Erkenntniß (wozu Geschichte, Erdbeschreibung, gelehrte Sprachkenntniß, Humanistik mit allem gehört, was die Naturkunde von empirischem Erkenntniß darbietet), das andere der reinen Vernunfterkenntnisse (reinen Mathematik und der reinen Philosophie, Metaphysik der Natur und der Sitten) und beide Theile der Gelehrsamkeit in ihrer wechselseitigen Beziehung auf einander. Sie erstreckt sich eben darum auf alle Theile des menschlichen Wissens (mithin auch historisch über die obern Facultäten), nur daß sie nicht alle (nämlich die eigenthümlichen Lehren oder Gebote der obern) zum Inhalte, sondern zum Gegenstande ihrer Prüfung und Kritik in Absicht auf den Vortheil der Wissenschaften macht. Die philosophische Facultät kann also alle Lehren in Anspruch nehmen, um ihre Wahrheit der Prüfung zu unterwerfen. Sie kann von der Regierung, ohne daß diese ihrer eigentlichen, wesentlichen Absicht zuwider handle, nicht mit einem Interdict belegt werden, und die obern Facultäten müssen sich ihre Einwürfe und Zweifel, die sie öffentlich vorbringt, gefallen lassen, welches jene zwar allerdings lästig finden dürften, weil sie ohne solche Kritiker in ihrem, unter welchem Titel es auch sei, einmal inne habenden Besitz ungestört ruhen und dabei noch despotisch hätten befehlen können. – Nur den Geschäftsleuten jener oberen Facultäten (den Geistlichen, Rechtsbeamten und Ärzten) kann es allerdings verwehrt werden, daß sie"}], "markers": [{"system": "AA", "band": "VII", "page": 28, "ref": "VII28"}], "running_header": "2. Abschn. Begriff und Eintheilung der untern Facultaet"}, {"page_id": "2501_0", "page_pdf": 2501, "page_book": 29, "page_kind": "body", "sigel": "AA VII, 29", "units": [{"type": "paragraph", "text": "den ihnen in Führung ihres respectiven Amts von der Regierung zum Vortrage anvertrauten Lehren nicht öffentlich widersprechen und den Philosophen zu spielen sich erkühnen; denn das kann nur den Facultäten, nicht den von der Regierung bestellten Beamten erlaubt sein: weil diese ihr Wissen nur von jenen her haben. Die letztern nämlich, z.B. Prediger und Rechtsbeamte, wenn sie ihre Einwendungen und Zweifel gegen die geistliche oder weltliche Gesetzgebung ans Volk zu richten sich gelüsten ließen, würden es dadurch gegen die Regierung aufwiegeln; dagegen die Facultäten sie nur gegen einander, als Gelehrte, richten, wovon das Volk praktischerweise keine Notiz nimmt, selbst wenn sie auch zu seiner Kenntniß gelangen, weil es sich selbst bescheidet, daß Vernünfteln nicht seine Sache sei, und sich daher verbunden fühlt, sich nur an dem zu halten, was ihm durch die dazu bestellte Beamte der Regierung verkündigt wird. – Diese Freiheit aber, die der untern Facultät nicht geschmälert werden darf, hat den Erfolg, daß die obern Facultäten (selbst besser belehrt) die Beamte immer mehr in das Gleis der Wahrheit bringen, welche dann ihrerseits, auch über ihre Pflicht besser aufgeklärt, in der Abänderung des Vortrags keinen Anstoß finden werden; da er nur ein besseres Verständniß der Mittel zu eben demselben Zweck ist, welches ohne polemische und nur Unruhe erregende Angriffe auf bisher bestandene Lehrweisen mit völliger Beibehaltung des Materialen derselben gar wohl geschehen kann."}], "markers": [{"system": "AA", "band": "VII", "page": 29, "ref": "VII29"}], "running_header": "2. Abschn. Begriff und Eintheilung der untern Facultaet"}, {"page_id": "2502_0", "page_pdf": 2502, "page_book": 29, "page_kind": "body", "sigel": "AA VII, 29", "units": [{"type": "paragraph", "text": "*Dritter Abschnitt.* Vom gesetzwidrigen Streit der oberen Facultäten mit der unteren."}], "running_header": "3. Abschn. Vom gesetzwidrigen Streit der oberen Facultäten mit der unteren"}, {"page_id": "2502_1", "page_pdf": 2502, "page_book": 29, "page_kind": "body", "sigel": "AA VII, 29", "units": [{"type": "paragraph", "text": "Gesetzwidrig ist ein öffentlicher Streit der Meinungen, mithin ein gelehrter Streit entweder der Materie wegen, wenn es gar nicht erlaubt wäre, über einen öffentlichen Satz zu streiten, weil es gar nicht erlaubt ist, über ihn und seinen Gegensatz öffentlich zu urtheilen; oder blos der Form wegen, wenn die Art, wie er geführt wird, nicht in objectiven Gründen, die auf die Vernunft des Gegners gerichtet sind, sondern in subjectiven, sein Urtheil durch Neigung bestimmenden Bewegursachen besteht, um ihn durch List (wozu auch Bestechung gehört) oder Gewalt (Drohung) zur Einwilligung zu bringen. Nun wird der Streit der Facultäten um den Einfluß aufs Volk geführt,"}], "markers": [{"system": "AA", "band": "VII", "page": 29, "ref": "VII29"}], "running_header": "3. Abschn. Vom gesetzwidrigen Streit der oberen Facultäten mit der unteren"}, {"page_id": "2502_2", "page_pdf": 2502, "page_book": 30, "page_kind": "body", "sigel": "AA VII, 30", "units": [{"type": "paragraph", "text": "und diesen Einfluß können sie nur bekommen, so fern jede derselben das Volk glauben machen kann, daß sie das Heil desselben am besten zu befördern verstehe, dabei aber doch in der Art, wie sie dieses auszurichten gedenken, einander gerade entgegengesetzt sind. Das Volk aber setzt sein Heil zu oberst nicht in der Freiheit, sondern in seinen natürlichen Zwecken, also in diesen drei Stücken: nach dem Tode selig, im Leben unter andern Mitmenschen des Seinen durch öffentliche Gesetze gesichert, endlich des physischen Genusses des Lebens an sich selbst (d.i. der Gesundheit und langen Lebens) gewärtig zu sein. Die philosophische Facultät aber, die sich auf alle diese Wünsche nur durch Vorschriften, die sie aus der Vernunft entlehnt, einlassen kann, mithin dem Princip der Freiheit anhänglich ist, hält sich nur an das, was der Mensch selbst hinzuthun kann und soll: rechtschaffen zu leben, keinem Unrecht zu thun, sich mäßig im Genusse und duldend in Krankheiten und dabei vornehmlich auf die Selbsthülfe der Natur rechnend zu verhalten; zu welchem Allem es freilich nicht eben großer Gelehrsamkeit bedarf, wobei man dieser aber auch größtentheils entbehren kann, wenn man nur seine Neigungen bändigen und seiner Vernunft das Regiment anvertrauen wollte, was aber als Selbstbemühung dem Volk gar nicht gelegen ist. Die drei obern Facultäten werden nun vom Volk (das in obigen Lehren für seine Neigung zu genießen und Abneigung sich darum zu bearbeiten schlechten Ersatz findet) aufgefordert, ihrerseits Propositionen zu thun, die annehmlicher sind: und da lauten die Ansprüche an die Gelehrten, wie folgt: Was ihr Philosophen da schwatzet, wußte ich längst von selbst; ich will aber von euch als Gelehrten wissen: wie, wenn ich auch ruchlos gelebt hätte, ich dennoch kurz vor dem Thorschlusse mir ein Einlaßbillet ins Himmelreich verschaffen, wie, wenn ich auch Unrecht habe, ich doch meinen Proceß gewinnen, und wie, wenn ich auch meine körperlichen Kräfte nach Herzenslust benutzt und mißbraucht hätte, ich doch gesund bleiben und lange leben könne. Dafür habt ihr ja studirt, daß ihr mehr wissen müßt als unser einer (von euch Idioten genannt), der auf nichts weiter als auf gesunden Verstand Anspruch macht. – Es ist aber hier, als ob das Volk zu dem Gelehrten wie zum Wahrsager und Zauberer ginge, der mit übernatürlichen Dingen Bescheid weiß; denn der Ungelehrte macht sich von einem Gelehrten, dem er etwas zumuthet, gern übergroße Begriffe. Daher ist es natürlicherweise vorauszusehen, daß, wenn sich jemand für einen solchen Wundermann auszugeben nur dreust genug ist,"}], "markers": [{"system": "AA", "band": "VII", "page": 30, "ref": "VII30"}], "running_header": "3. Abschn. Vom gesetzwidrigen Streit der oberen Facultäten mit der unteren"}, {"page_id": "2502_3", "page_pdf": 2502, "page_book": 31, "page_kind": "body", "sigel": "AA VII, 31", "units": [{"type": "paragraph", "text": "ihm das Volk zufallen und die Seite der philosophischen Facultät mit Verachtung verlassen werde. Die Geschäftsleute der drei oberen Facultäten sind aber jederzeit solche Wundermänner, wenn der philosophischen nicht erlaubt wird, ihnen öffentlich entgegen zu arbeiten, nicht um ihre Lehren zu stürzen, sondern nur der magischen Kraft, die ihnen und den damit verbundenen Observanzen das Publicum abergläubisch beilegt, zu widersprechen, als wenn es bei einer passiven Übergebung an solche kunstreiche Führer alles Selbstthuns überhoben und mit großer Gemächlichkeit durch sie zu Erreichung jener angelegenen Zwecke schon werde geleitet werden. Wenn die obern Facultäten solche Grundsätze annehmen (welches freilich ihre Bestimmung nicht ist), so sind und bleiben sie ewig im Streit mit der unteren; dieser Streit aber ist auch gesetzwidrig, weil sie die Übertretung der Gesetze nicht allein als kein Hinderniß, sondern"}], "markers": [{"system": "AA", "band": "VII", "page": 31, "ref": "VII31"}], "running_header": "3. Abschn. Vom gesetzwidrigen Streit der oberen Facultäten mit der unteren"}, {"page_id": "2503_0", "page_pdf": 2503, "page_book": 31, "page_kind": "body", "sigel": "AA VII, 31", "units": [{"type": "paragraph", "text": "wohl gar als erwünschte Veranlassung ansehen, ihre große Kunst und Geschicklichkeit zu zeigen, alles wieder gut, ja noch besser zu machen, als es ohne dieselbe geschehen würde. Das Volk will geleitet, d.i. (in der Sprache der Demagogen) es will betrogen sein. Es will aber nicht von den Facultätsgelehrten (denn deren Weisheit ist ihm zu hoch), sondern von den Geschäftsmännern derselben, die das Machwerk (_savoir faire_) verstehen, von den Geistlichen, Justizbeamten, Ärzten, geleitet sein, die als Praktiker die vortheilhafteste Vermuthung für sich haben; dadurch dann die Regierung, die nur durch sie aufs Volk wirken kann, selbst verleitet wird, den Facultäten eine Theorie aufzudringen, die nicht aus der reinen Einsicht der Gelehrten derselben entsprungen, sondern auf den Einfluß berechnet ist, den ihre Geschäftsmänner dadurch aufs Volk haben können, weil dieses natürlicherweise dem am meisten anhängt, wobei es am wenigsten nöthig hat, sich selbst zu bemühen und sich seiner eigenen Vernunft zu bedienen, und wo am besten die Pflichten mit den Neigungen in Verträglichkeit gebracht werden können; z.B. im theologischen Fache, daß buchstäblich »Glauben«, ohne zu untersuchen (selbst ohne einmal recht zu verstehen), was geglaubt werden soll, für sich heilbringend sei und daß durch Begehung gewisser vorschriftmäßigen Formalien unmittelbar Verbrechen können abgewaschen werden; oder im juristischen, daß die Befolgung des Gesetzes nach dem Buchstaben der Untersuchung des Sinnes des Gesetzgebers überhebe. Hier ist nun ein wesentlicher, nie beizulegender gesetzwidriger Streit"}], "running_header": "3. Abschn. Vom gesetzwidrigen Streit der oberen Facultäten mit der unteren"}, {"page_id": "2503_1", "page_pdf": 2503, "page_book": 32, "page_kind": "body", "sigel": "AA VII, 32", "units": [{"type": "paragraph", "text": "zwischen den obern und der untern Facultät, weil das Princip der Gesetzgebung für die ersteren, welches man der Regierung unterlegt, eine von ihr autorisirte Gesetzlosigkeit selbst sein würde. – Denn da Neigung und überhaupt das, was jemand seiner Privatabsicht zuträglich findet, sich schlechterdings nicht zu einem Gesetze qualificirt, mithin auch nicht als ein solches von den obern Facultäten vorgetragen werden kann, so würde eine Regierung, welche dergleichen sanctionirte, indem sie wider die Vernunft selbst verstößt, jene obere Facultäten mit der philosophischen in einen Streit versetzen, der gar nicht geduldet werden kann, indem er diese gänzlich vernichtet, welches freilich das kürzeste, aber auch (nach dem Ausdruck der Ärzte) ein in Todesgefahr bringendes heroisches Mittel ist, einen Streit zu Ende zu bringen."}], "markers": [{"system": "AA", "band": "VII", "page": 32, "ref": "VII32"}], "running_header": "3. Abschn. Vom gesetzwidrigen Streit der oberen Facultäten mit der unteren"}, {"page_id": "2504_0", "page_pdf": 2504, "page_book": 32, "page_kind": "body", "sigel": "AA VII, 32", "units": [{"type": "paragraph", "text": "*Vierter Abschnitt.* Vom gesetzmäßigen Streit der oberen Facultäten mit der unteren."}], "running_header": "4. Abschn. Vom gesetzmäßigen Streit der oberen Facultäten mit der unteren"}, {"page_id": "2504_1", "page_pdf": 2504, "page_book": 32, "page_kind": "body", "sigel": "AA VII, 32", "units": [{"type": "paragraph", "text": "Welcherlei Inhalts auch die Lehren immer sein mögen, deren öffentlichen Vortrag die Regierung durch ihre Sanction den obern Facultäten aufzulegen befugt sein mag, so können sie doch nur als Statute, die von ihrer Willkür ausgehen, und als menschliche Weisheit, die nicht unfehlbar ist, angenommen und verehrt werden. Weil indessen die Wahrheit derselben ihr durchaus nicht gleichgültig sein darf, in Ansehung welcher sie der Vernunft (deren Interesse die philosophische Facultät zu besorgen hat) unterworfen bleiben müssen, dieses aber nur durch Verstattung völliger Freiheit einer öffentlichen Prüfung derselben möglich ist, so wird, weil willkürliche, obzwar höchsten Orts sanctionirte, Satzungen mit den durch die Vernunft als nothwendig behaupteten Lehren nicht so von selbst immer zusammenstimmen dürften, erstlich zwischen den obern Facultäten und der untern der Streit unvermeidlich, zweitens aber auch gesetzmäßig sein, und dieses nicht blos als Befugniß, sondern auch als Pflicht der letzteren, wenn gleich nicht die ganze Wahrheit öffentlich zu sagen, doch darauf bedacht zu sein, daß alles, was, so gesagt, als Grundsatz aufgestellt wird, wahr sei. Wenn die Quelle gewisser sanctionirter Lehren historisch ist, so mögen diese auch noch so sehr als heilig dem unbedenklichen Gehorsam des Glaubens anempfohlen werden: die philosophische Facultät ist berechtigt,"}], "markers": [{"system": "AA", "band": "VII", "page": 32, "ref": "VII32"}], "running_header": "4. Abschn. Vom gesetzmäßigen Streit der oberen Facultäten mit der unteren"}, {"page_id": "2504_2", "page_pdf": 2504, "page_book": 33, "page_kind": "body", "sigel": "AA VII, 33", "units": [{"type": "paragraph", "text": "ja verbunden, diesem Ursprunge mit kritischer Bedenklichkeit nachzuspüren. Ist sie rational, ob sie gleich im Tone einer historischen Erkenntniß (als Offenbarung) aufgestellt worden, so kann ihr (der untern Facultät) nicht gewehrt werden, die Vernunftgründe der Gesetzgebung aus dem historischen Vortrage herauszusuchen und überdem, ob sie technisch- oder moralisch-praktisch sind, zu würdigen. Wäre endlich der Quell der sich als Gesetz ankündigenden Lehre gar nur ästhetisch, d.i. auf ein mit einer Lehre verbundenes Gefühl gegründet (welches, da es kein objectives Princip abgiebt, nur als subjectiv gültig, ein allgemeines Gesetz daraus zu machen untauglich, etwa frommes Gefühl eines übernatürlichen Einflusses sein würde), so muß es der philosophischen Facultät frei stehen, den Ursprung und Gehalt eines solchen angeblichen Belehrungsgrundes mit kalter Vernunft öffentlich zu prüfen und zu würdigen, ungeschreckt durch die Heiligkeit des Gegenstandes, den man zu fühlen vorgiebt, und entschlossen dieses vermeinte Gefühl auf Begriffe zu bringen. – Folgendes enthält die formale Grundsätze der Führung eines solchen Streits und die sich daraus ergebende Folgen. 1) Dieser Streit kann und soll nicht durch friedliche Übereinkunft (_amicabilis compositio_) beigelegt werden, sondern bedarf (als Proceß) einer Sentenz, d.i. des rechtskräftigen Spruchs eines Richters (der Vernunft); denn es könnte nur durch Unlauterkeit, Verheimlichung der Ursachen des Zwistes und Beredung geschehen, daß er beigelegt würde, dergleichen Maxime aber dem Geiste einer philosophischen Facultät, als der auf öffentliche Darstellung der Wahrheit geht, ganz zuwider ist. 2) Er kann nie aufhören, und die philosophische Facultät ist diejenige, die dazu jederzeit gerüstet sein muß. Denn statutarische Vorschriften der Regierung in Ansehung der öffentlich vorzutragenden Lehren werden immer sein müssen, weil die unbeschränkte Freiheit, alle seine Meinungen ins Publicum zu schreien, theils der Regierung, theils aber auch diesem Publicum selbst gefährlich werden müßte. Alle Satzungen der Regierung aber, weil sie von Menschen ausgehen, wenigstens von diesen sanctionirt werden, bleiben jederzeit der Gefahr des Irrthums oder der Zweckwidrigkeit unterworfen; mithin sind sie es auch in Ansehung der Sanction der Regierung, womit diese die obere Facultäten versieht. Folglich kann die philosophische Facultät ihre Rüstung gegen die Gefahr, womit die Wahrheit, deren Schutz ihr aufgetragen ist, bedroht wird, nie ablegen, weil die obere Facultäten ihre Begierde zu herrschen nie ablegen werden."}], "markers": [{"system": "AA", "band": "VII", "page": 33, "ref": "VII33"}], "running_header": "4. Abschn. Vom gesetzmäßigen Streit der oberen Facultäten mit der unteren"}, {"page_id": "2504_3", "page_pdf": 2504, "page_book": 34, "page_kind": "body", "sigel": "AA VII, 34", "units": [{"type": "paragraph", "text": "3) Dieser Streit kann dem Ansehen der Regierung nie Abbruch thun. Denn er ist nicht ein Streit der Facultäten mit der Regierung, sondern einer Facultät mit der andern, dem die"}], "markers": [{"system": "AA", "band": "VII", "page": 34, "ref": "VII34"}], "running_header": "4. Abschn. Vom gesetzmäßigen Streit der oberen Facultäten mit der unteren"}, {"page_id": "2505_0", "page_pdf": 2505, "page_book": 34, "page_kind": "body", "sigel": "AA VII, 34", "units": [{"type": "paragraph", "text": "Regierung ruhig zusehen kann; weil, ob sie zwar gewisse Sätze der obern in ihren besondern Schutz genommen hat, so fern sie solche der letzteren ihren Geschäftsleuten zum öffentlichen Vortrage vorschreibt, so hat sie doch nicht die Facultäten, als gelehrten Gesellschaften, wegen der Wahrheit dieser ihrer öffentlich vorzutragenden Lehren, Meinungen und Behauptungen, sondern nur wegen ihres (der Regierung) eigenen Vortheils in Schutz genommen, weil es ihrer Würde nicht gemäß sein würde, über den innern Wahrheitsgehalt derselben zu entscheiden und so selbst den Gelehrten zu spielen. – Die obere Facultäten sind nämlich der Regierung für nichts weiter verantwortlich, als für die Instruction und Belehrung, die sie ihren Geschäftsleuten zum öffentlichen Vortrage geben; denn die laufen ins Publicum als bürgerliches gemeines Wesen und sind daher, weil sie dem Einfluß der Regierung auf dieses Abbruch thun könnten, dieser ihrer Sanction unterworfen. Dagegen gehen die Lehren und Meinungen, welche die Facultäten unter dem Namen der Theoretiker unter einander abzumachen haben, in eine andere Art von Publicum, nämlich in das eines gelehrten gemeinen Wesens, welches sich mit Wissenschaften beschäftigt; wovon das Volk sich selbst bescheidet, daß es nichts davon versteht, die Regierung aber mit gelehrten Händeln sich zu befassen für sich nicht anständig findet*."}], "running_header": "4. Abschn. Vom gesetzmäßigen Streit der oberen Facultäten mit der unteren"}, {"page_id": "2505_1", "page_pdf": 2505, "page_book": 35, "page_kind": "body", "sigel": "AA VII, 35", "units": [{"type": "paragraph", "text": "Die Classe der obern Facultäten (als die rechte Seite des Parlaments der Gelahrtheit) vertheidigt die Statute der Regierung, indessen daß es in einer so freien Verfassung, als die sein muß, wo es um Wahrheit zu thun ist, auch eine Oppositionspartei (die linke Seite) geben muß, welche die Bank der philosophischen Facultät ist, weil ohne deren strenge Prüfung und Einwürfe die Regierung von dem, was ihr selbst ersprießlich oder nachtheilig sein dürfte, nicht hinreichend belehrt werden würde. – Wenn aber die Geschäftsleute der Facultäten in Ansehung der für den öffentlichen Vortrag gegebenen Verordnung für ihren Kopf Änderungen machen wollten, so kann die Aufsicht der Regierung diese als Neuerer, welche ihr gefährlich werden könnten, in Anspruch nehmen und doch gleichwohl über sie nicht unmittelbar, sondern nur nach dem von der obern Facultät eingezogenen allerunterthänigsten Gutachten absprechen, weil diese Geschäftsleute nur durch die Facultät von der Regierung zu dem Vortrage gewisser Lehren haben angewiesen werden können. 4) Dieser Streit kann sehr wohl mit der Eintracht des gelehrten und bürgerlichen gemeinen Wesens in Maximen zusammen bestehen, deren Befolgung einen beständigen Fortschritt beider Classen von Facultäten zu größerer Vollkommenheit bewirken muß und endlich zur Entlassung von allen Einschränkungen die Freiheit des öffentlichen Urtheils durch die Willkür der Regierung vorbereitet. Auf diese Weise könnte es wohl dereinst dahin kommen, daß die Letzten die Ersten (die untere Facultät die obere) würden, zwar nicht in der Machthabung, aber doch in Berathung des Machthabenden (der Regierung), als welche in der Freiheit der philosophischen Facultät und der ihr daraus erwachsenden Einsicht besser als in ihrer eigenen absoluten Autorität Mittel zu Erreichung ihrer Zwecke antreffen würde."}, {"type": "paragraph", "text": "Anmerkungen:"}], "markers": [{"system": "AA", "band": "VII", "page": 35, "ref": "VII35"}], "running_header": "4. Abschn. Vom gesetzmäßigen Streit der oberen Facultäten mit der unteren"}, {"page_id": "2506", "page_pdf": 2506, "page_book": 35, "page_kind": "body", "sigel": "AA VII, 35", "units": [{"type": "paragraph", "text": "* Dagegen, wenn der Streit vor dem bürgerlichen gemeinen Wesen (öffentlich, z.B. auf Kanzeln) geführt würde, wie es die Geschäftsleute (unter dem Namen der Praktiker) gern versuchen, so wird er unbefugterweise vor den Richterstuhl des Volks (dem in Sachen der Gelehrsamkeit gar kein Urtheil zusteht) gezogen und hört auf, ein gelehrter Streit zu sein; da dann jener Zustand des gesetzwidrigen Streits, wovon oben Erwähnung geschehen, eintritt, wo Lehren den Neigungen des Volks angemessen vorgetragen werden und der Same des Aufruhrs und der Factionen ausgestreut, die Regierung aber dadurch in Gefahr gebracht wird. Diese eigenmächtig sich selbst dazu aufwerfende Volkstribunen treten so fern aus dem Gelehrtenstande, greifen in die Rechte der bürgerlichen Verfassung (Welthändel) ein und sind eigentlich die Neologen, deren mit Recht verhaßter Name aber sehr mißverstanden wird, wenn er jede Urheber einer Neuigkeit in Lehren und Lehrformen trifft. (Denn warum sollte das Alte eben immer das Bessere sein?) Dagegen diejenige eigentlich damit gebrandmarkt zu werden verdienen, welche eine ganz andere Regierungsform, oder vielmehr eine Regierungslosigkeit (Anarchie) einführen, indem sie das, was eine Sache der Gelehrsamkeit ist, der Stimme des Volks zur Entscheidung übergeben, dessen Urtheil sie durch Einfluß auf seine Gewohnheiten, Gefühle und Neigungen nach Belieben lenken und so einer gesetzmäßigen Regierung den Einfluß abgewinnen können."}], "markers": [{"system": "AA", "band": "VII", "page": 35, "ref": "VII35"}], "running_header": "4. Abschn. Vom gesetzmäßigen Streit der oberen Facultäten mit der unteren"}, {"page_id": "2507_0", "page_pdf": 2507, "page_book": 35, "page_kind": "body", "sigel": "AA VII, 35", "units": [{"type": "paragraph", "text": "Resultat."}], "running_header": "Resultat"}, {"page_id": "2507_1", "page_pdf": 2507, "page_book": 35, "page_kind": "body", "sigel": "AA VII, 35", "units": [{"type": "paragraph", "text": "Dieser Antagonism, d.i. Streit zweier mit einander zu einem gemeinschaftlichen Endzweck vereinigten Parteien, (_concordia discors, discordia concors_) ist also kein Krieg, d.i. keine Zwietracht aus der Entgegensetzung der Endabsichten in Ansehung des gelehrten Mein und Dein,"}], "markers": [{"system": "AA", "band": "VII", "page": 35, "ref": "VII35"}], "running_header": "Resultat"}, {"page_id": "2507_2", "page_pdf": 2507, "page_book": 36, "page_kind": "body", "sigel": "AA VII, 36", "units": [{"type": "paragraph", "text": "welches so wie das politische aus Freiheit und Eigenthum besteht, wo jene als Bedingung nothwendig vor diesem vorhergehen muß; folglich den oberen Facultäten kein Recht verstattet werden kann, ohne daß es der unteren zugleich erlaubt bleibe, ihre Bedenklichkeit über dasselbe an das gelehrte Publicum zu bringen."}], "markers": [{"system": "AA", "band": "VII", "page": 36, "ref": "VII36"}], "running_header": "Resultat"}, {"page_id": "2508_0", "page_pdf": 2508, "page_book": 36, "page_kind": "body", "sigel": "AA VII, 36", "units": [{"type": "paragraph", "text": "Anhang einer Erläuterung des Streits der Facultäten durch das Beispiel desjenigen zwischen der theologischen und philosophischen. I. Materie des Streits."}], "running_header": "Anhang einer Erläuterung des Streits der Facultäten [...]. I. Materie des Streits"}, {"page_id": "2508_1", "page_pdf": 2508, "page_book": 36, "page_kind": "body", "sigel": "AA VII, 36", "units": [{"type": "paragraph", "text": "Der biblische Theolog ist eigentlich der Schriftgelehrte für den Kirchenglauben, der auf Statuten, d.i. auf Gesetzen beruht, die aus der Willkür eines andern ausfließen; dagegen ist der rationale der Vernunftgelehrte für den Religionsglauben, folglich denjenigen, der auf innern Gesetzen beruht, die sich aus jedes Menschen eigener Vernunft entwickeln lassen. Daß dieses so sei, d.i. daß Religion nie auf Satzungen (so hohen Ursprungs sie immer sein mögen) gegründet werden könne, erhellt selbst aus dem Begriffe der Religion. Nicht der Inbegriff gewisser Lehren als göttlicher Offenbarungen (denn der heißt Theologie), sondern der aller unserer Pflichten überhaupt als göttlicher Gebote (und subjectiv der Maxime sie als solche zu befolgen) ist Religion. Religion unterscheidet sich nicht der Materie, d.i. dem Object, nach in irgend einem Stücke von der Moral, denn sie geht auf Pflichten überhaupt, sondern ihr Unterschied von dieser ist blos formal, d.i. eine Gesetzgebung der Vernunft, um der Moral durch die aus dieser selbst erzeugte Idee von Gott auf den menschlichen Willen zu Erfüllung aller seiner Pflichten Einfluß zu geben. Darum ist sie aber auch nur eine einzige, und es giebt nicht nur verschiedene Religionen, aber wohl verschiedene Glaubensarten an göttliche Offenbarung und deren statutarische Lehren, die nicht aus der Vernunft entspringen können, d.i. verschiedene Formen der sinnlichen Vorstellungsart des göttlichen Willens, um ihm Einfluß auf die Gemüther zu verschaffen, unter denen das Christenthum, so viel wir wissen, die schicklichste Form ist. Dies findet sich nun in der Bibel aus zwei ungleichartigen Stücken zusammengesetzt, dem"}], "markers": [{"system": "AA", "band": "VII", "page": 36, "ref": "VII36"}], "running_header": "Anhang einer Erläuterung des Streits der Facultäten [...]. I. Materie des Streits"}, {"page_id": "2508_2", "page_pdf": 2508, "page_book": 37, "page_kind": "body", "sigel": "AA VII, 37", "units": [{"type": "paragraph", "text": "einen, welches den Kanon, dem andern, was das Organon oder Vehikel der Religion enthält, wovon der erste der reine Religionsglaube (ohne Statuten auf bloßer Vernunft gegründet), der andere der Kirchenglaube, der ganz auf Statuten beruht, genannt werden kann, die einer Offenbarung bedurften, wenn sie für heilige Lehre und Lebensvorschriften gelten sollten. – Da aber auch dieses Leitzeug zu jenem Zweck zu gebrauchen Pflicht ist, wenn es für göttliche Offenbarung angenommen werden darf, so läßt sich daraus erklären, warum der sich auf Schrift gründende Kirchenglaube bei Nennung des Religionsglaubens gemeiniglich mit verstanden wird. Der biblische Theolog sagt: suchet in der Schrift, wo ihr meinet das ewige Leben zu finden. Dieses aber, weil die Bedingung desselben keine andere als die moralische Besserung des Menschen ist, kann kein Mensch in irgend einer Schrift finden, als wenn er sie hineinlegt, weil die dazu erforderlichen Begriffe und Grundsätze eigentlich nicht von irgend einem andern gelernt, sondern nur bei Veranlassung eines Vortrages aus der eigenen Vernunft des Lehrers entwickelt werden müssen. Die Schrift aber enthält noch mehr, als was an sich selbst zum ewigen Leben erforderlich ist, was nämlich zum Geschichtsglauben gehört und in Ansehung des Religionsglaubens als bloßes sinnliches Vehikel zwar (für diese oder jene Person, für dieses oder jenes Zeitalter) zuträglich sein kann, aber nicht nothwendig dazu gehört. Die biblisch-theologische Facultät dringt nun darauf als göttliche Offenbarung in gleichem Maße, als wenn der Glaube desselben zur Religion gehörte. Die philosophische aber widerstreitet jener in Ansehung dieser Vermengung und dessen, was jene über die eigentliche Religion Wahres in sich enthält. Zu diesem Vehikel (d.i. dem, was über die Religionslehre noch hinzukommt) gehört auch noch die Lehrmethode, die man als den Aposteln selbst überlassen und nicht als göttliche Offenbarung betrachten darf, sondern beziehungsweise auf die Denkungsart der damaligen Zeiten (kat’ anjðrwpon) und nicht als Lehrstücke an sich selbst (kat’ alhjðeian) geltend annehmen kann, und zwar entweder negativ als bloße Zulassung gewisser damals herrschender, an sich irriger Meinungen, um nicht gegen einen herrschenden, doch im Wesentlichen gegen die Religion"}], "markers": [{"system": "AA", "band": "VII", "page": 37, "ref": "VII37"}], "running_header": "Anhang einer Erläuterung des Streits der Facultäten [...]. I. Materie des Streits"}, {"page_id": "2509_0", "page_pdf": 2509, "page_book": 37, "page_kind": "body", "sigel": "AA VII, 37", "units": [{"type": "paragraph", "text": "nicht streitenden damaligen Wahn zu verstoßen (z.B. das von den Besessenen), oder auch positiv, um sich der Vorliebe eines Volks für ihren alten Kirchenglauben, der jetzt ein Ende haben sollte, zu bedienen, um den neuen zu introduciren. (Z.B. die Deutung der Geschichte des alten Bundes als Vorbilder von"}], "running_header": "Anhang einer Erläuterung des Streits der Facultäten [...]. I. Materie des Streits"}, {"page_id": "2509_1", "page_pdf": 2509, "page_book": 38, "page_kind": "body", "sigel": "AA VII, 38", "units": [{"type": "paragraph", "text": "dem, was im neuen geschah, welche als Judaism, wenn sie irrigerweise in die Glaubenslehre als ein Stück derselben aufgenommen wird, uns wohl den Seufzer ablocken kann: _nunc istae reliquiae _ _nos exercent. _Cicero.) Um deswillen ist eine Schriftgelehrsamkeit des Christenthums manchen Schwierigkeiten der Auslegungskunst unterworfen, über die und deren Princip die obere Facultät (der biblische Theolog) mit der unteren in Streit gerathen muß, indem die erstere als für die theoretische biblische Erkenntniß vorzüglich besorgt die letztere in Verdacht zieht, alle Lehren, die als eigentliche Offenbarungslehren und also buchstäblich angenommen werden müßten, wegzuphilosophiren und ihnen einen beliebigen Sinn unterzuschieben, diese aber als mehr aufs Praktische, d.i. mehr auf Religion als auf Kirchenglauben, sehend umgekehrt jene beschuldigt durch solche Mittel den Endzweck, der als innere Religion moralisch sein muß und auf der Vernunft beruht, ganz aus den Augen zu bringen. Daher die letztere, welche die Wahrheit zum Zweck hat, mithin die Philosophie im Falle des Streits über den Sinn einer Schriftstelle sich das Vorrecht anmaßt, ihn zu bestimmen. Folgendes sind die philosophischen Grundsätze der Schriftauslegerei, wodurch nicht verstanden werden will, daß die Auslegung philosophisch (zur Erweiterung der Philosophie abzielt), sondern daß blos die Grundsätze der Auslegung so beschaffen sein müssen: weil alle Grundsätze, sie mögen nun eine historisch- oder grammatisch-kritische Auslegung betreffen, jederzeit, hier aber besonders, weil, was aus Schriftstellen für die Religion (die blos ein Gegenstand der Vernunft sein kann) auszumitteln sei, auch von der Vernunft dictirt werden müssen."}], "markers": [{"system": "AA", "band": "VII", "page": 38, "ref": "VII38"}], "running_header": "Anhang einer Erläuterung des Streits der Facultäten [...]. I. Materie des Streits"}, {"page_id": "2510_0", "page_pdf": 2510, "page_book": 38, "page_kind": "body", "sigel": "AA VII, 38", "units": [{"type": "paragraph", "text": "II. Philosophische Grundsätze der Schriftauslegung zur Beilegung des Streits."}], "running_header": "II. Philosophische Grundsätze der Schriftauslegung zur Beilegung des Streits"}, {"page_id": "2510_1", "page_pdf": 2510, "page_book": 38, "page_kind": "body", "sigel": "AA VII, 38", "units": [{"type": "paragraph", "text": "I. Schriftstellen, welche gewisse theoretische, für heilig angekündigte, aber allen (selbst den moralischen) Vernunftbegriff übersteigende Lehren enthalten, dürfen, diejenige aber, welche der praktischen Vernunft widersprechende Sätze enthalten, müssen zum Vortheil der letzteren ausgelegt werden. – Folgendes enthält hiezu einige Beispiele. _a_) Aus der Dreieinigkeitslehre, nach dem Buchstaben genommen, läßt sich schlechterdings nichts fürs Praktische machen, wenn man sie gleich zu verstehen glaubte, noch weniger aber wenn man inne wird, daß"}], "markers": [{"system": "AA", "band": "VII", "page": 38, "ref": "VII38"}], "running_header": "II. Philosophische Grundsätze der Schriftauslegung zur Beilegung des Streits"}, {"page_id": "2510_2", "page_pdf": 2510, "page_book": 39, "page_kind": "body", "sigel": "AA VII, 39", "units": [{"type": "paragraph", "text": "sie gar alle unsere Begriffe übersteigt. – Ob wir in der Gottheit drei oder zehn Personen zu verehren haben, wird der Lehrling mit gleicher Leichtigkeit aufs Wort annehmen, weil er von einem Gott in mehreren Personen (Hypostasen) gar keinen Begriff hat, noch mehr aber weil er aus dieser Verschiedenheit für seinen Lebenswandel gar keine verschiedene Regeln ziehen kann. Dagegen wenn man in Glaubenssätzen einen moralischen Sinn hereinträgt (wie ich es: Religion innerhalb den Gränzen etc. versucht habe), er nicht einen folgeleeren, sondern auf unsere moralische Bestimmung bezogenen verständlichen Glauben enthalten würde. Eben so ist es mit der Lehre der Menschwerdung einer Person der Gottheit bewandt. Denn wenn dieser Gottmensch nicht als die in Gott von Ewigkeit her liegende Idee der Menschheit in ihrer ganzen ihm wohlgefälligen moralischen Vollkommenheit* (ebendaselbst S.73f.), sondern als die in einem wirklichen Menschen »leibhaftig wohnende« und als zweite Natur in ihm wirkende Gottheit vorgestellt wird: so ist aus diesem Geheimnisse gar nichts Praktisches für uns zu machen, weil wir doch von uns nicht verlangen können, daß wir es einem Gotte gleich thun sollen, er also in so fern kein Beispiel für uns werden kann, ohne noch die Schwierigkeit in Anregung zu bringen, warum, wenn solche Vereinigung einmal möglich ist, die Gottheit nicht alle Menschen derselben hat theilhaftig werden lassen, welche alsdann unausbleiblich ihm alle wohlgefällig geworden wären. – Ein Ähnliches kann von der Auferstehungs- und Himmelfahrtsgeschichte eben desselben gesagt werden."}], "markers": [{"system": "AA", "band": "VII", "page": 39, "ref": "VII39"}], "running_header": "II. Philosophische Grundsätze der Schriftauslegung zur Beilegung des Streits"}, {"page_id": "2510_3", "page_pdf": 2510, "page_book": 40, "page_kind": "body", "sigel": "AA VII, 40", "units": [{"type": "paragraph", "text": "Ob wir künftig blos der Seele nach leben, oder ob dieselbe Materie, daraus unser Körper hier bestand, zur Identität unserer Person in der andern Welt erforderlich, die Seele also keine besondere Substanz sei, unser Körper selbst müsse auferweckt werden, das kann uns in praktischer Absicht ganz gleichgültig sein; denn wem ist wohl sein Körper so lieb, daß er ihn gern in Ewigkeit mit sich schleppen möchte, wenn er seiner entübrigt sein kann? Des Apostels Schluß also: »Ist Christus nicht auferstanden (dem Körper nach lebendig geworden), so werden wir auch nicht auferstehen (nach dem Tode gar nicht mehr leben)« ist nicht bündig. Er mag es aber auch nicht sein (denn dem Argumentiren wird man doch nicht auch eine Inspiration zum Grunde legen), so hat er doch hiemit nur sagen wollen, daß wir Ursache haben zu glauben, Christus lebe noch, und unser Glaube sei eitel, wenn selbst ein so vollkommner Mensch nicht nach dem (leiblichen) Tode leben sollte, welcher Glaube, den ihm (wie allen Menschen) die Vernunft eingab, ihn zum historischen Glauben an eine öffentliche Sache bewog, die er treuherzig für wahr annahm und sie zum Beweisgrunde eines moralischen Glaubens des künftigen Lebens brauchte, ohne inne zu werden, daß er selbst dieser Sage ohne den letzteren schwerlich würde Glauben beigemessen haben. Die moralische Absicht wurde hiebei erreicht, wenn gleich die Vorstellungsart das Merkmal der Schulbegriffe an sich trug, in denen er war erzogen worden. – Übrigens stehen jener Sache wichtige Einwürfe entgegen: die Einsetzung des Abendmahls (einer traurigen Unterhaltung) zum Andenken an ihn sieht einem förmlichen Abschied (nicht blos aufs baldige Wiedersehen) ähnlich. Die klagende Worte am Kreuz drücken eine fehlgeschlagene Absicht aus (die Juden noch bei seinem Leben zur wahren Religion zu bringen), da doch eher das Frohsein über eine vollzogne Absicht hätte erwartet werden sollen. Endlich der Ausdruck der Jünger bei dem Lucas: »Wir dachten, er solle Israel erlösen« läßt auch nicht abnehmen, daß sie"}], "markers": [{"system": "AA", "band": "VII", "page": 40, "ref": "VII40"}], "running_header": "II. Philosophische Grundsätze der Schriftauslegung zur Beilegung des Streits"}, {"page_id": "2511_0", "page_pdf": 2511, "page_book": 40, "page_kind": "body", "sigel": "AA VII, 40", "units": [{"type": "paragraph", "text": "auf ein in drei Tagen erwartetes Wiedersehen vorbereitet waren, noch weniger, daß ihnen von seiner Auferstehung etwas zu Ohren gekommen sei. – Aber warum sollten wir wegen einer Geschichtserzählung, die wir immer an ihren Ort (unter die Adiaphora) gestellt sein lassen sollen, uns in so viel gelehrte Untersuchungen und Streitigkeiten verflechten, wenn es um Religion zu thun ist, welcher der Glaube in praktischer Beziehung, den die Vernunft uns einflößt, schon für sich hinreichend ist. _b_) In der Auslegung der Schriftstellen, in welchen der Ausdruck unserm"}], "running_header": "II. Philosophische Grundsätze der Schriftauslegung zur Beilegung des Streits"}, {"page_id": "2511_1", "page_pdf": 2511, "page_book": 41, "page_kind": "body", "sigel": "AA VII, 41", "units": [{"type": "paragraph", "text": "Vernunftbegriff von der göttlichen Natur und seinem Willen widerstreitet, haben biblische Theologen sich längst zur Regel gemacht, daß, was menschlicherweise (anjðrwpopajðwV) ausgedrückt ist, nach einem gottwürdigen Sinne (jðeoprepwV) müsse ausgelegt werden; wodurch sie dann ganz deutlich das Bekenntniß ablegten, die Vernunft sei in Religionssachen die oberste Auslegerin der Schrift. – Daß aber selbst, wenn man dem heil. Schriftsteller keinen andern Sinn, den er wirklich mit seinen Ausdrücken verband, unterlegen kann, als einen solchen, der mit unserer Vernunft gar in Widerspruche steht, die Vernunft sich doch berechtigt fühle, seine Schriftstelle so auszulegen, wie sie es ihren Grundsätzen gemäß findet, und nicht dem Buchstaben nach auslegen solle, wenn sie jenen nicht gar eines Irrthums beschuldigen will, das scheint ganz und gar wider die oberste Regeln der Interpretation zu verstoßen, und gleichwohl ist es noch immer mit Beifall von den belobtesten Gottesgelehrten geschehen. – So ist es mit St. Paulus’ Lehre von der Gnadenwahl gegangen, aus welcher aufs deutlichste erhellt, daß seine Privatmeinung die Prädestination im strengsten Sinne des Worts gewesen sein muß, welche darum auch von einer großen protestantischen Kirche in ihren Glauben aufgenommen worden, in der Folge aber von einem großen Theil derselben wieder verlassen, oder, so gut wie man konnte, anders gedeutet worden ist, weil die Vernunft sie mit der Lehre von der Freiheit, der Zurechnung der Handlungen und so mit der ganzen Moral unvereinbar findet. – Auch wo der Schriftglaube in keinen Verstoß gewisser Lehren wider sittliche Grundsätze, sondern nur wider die Vernunftmaxime in Beurtheilung physischer Erscheinungen geräth, haben Schriftausleger mit fast allgemeinem Beifall manche biblische Geschichtserzählungen, z.B. von den Besessenen (dämonischen Leuten), ob sie zwar in demselben historischen Tone wie die übrige heil. Geschichte in der Schrift vorgetragen worden und fast nicht zu zweifeln ist, daß ihre Schriftsteller sie buchstäblich für wahr gehalten haben, doch so ausgelegt, daß die Vernunft dabei bestehen könnte (um nicht allem Aberglauben und Betrug freien Eingang zu verschaffen), ohne daß man ihnen diese Befugniß bestritten hat. II. Der Glaube an Schriftlehren, die eigentlich haben offenbart werden müssen, wenn sie haben gekannt werden sollen, hat an sich kein Verdienst , und der Mangel desselben, ja sogar der ihm entgegenstehende Zweifel ist an sich keine Verschuldung , sondern alles kommt in der Religion aufs Thun an, und diese Endabsicht, mithin auch ein"}], "markers": [{"system": "AA", "band": "VII", "page": 41, "ref": "VII41"}], "running_header": "II. Philosophische Grundsätze der Schriftauslegung zur Beilegung des Streits"}, {"page_id": "2511_2", "page_pdf": 2511, "page_book": 42, "page_kind": "body", "sigel": "AA VII, 42", "units": [{"type": "paragraph", "text": "dieser gemäßer Sinn muß allen biblischen Glaubenslehren untergelegt werden. Unter Glaubenssätzen versteht man nicht, was geglaubt werden soll (denn das Glauben verstattet keinen Imperativ), sondern das, was in praktischer (moralischer) Absicht anzunehmen möglich und zweckmäßig, obgleich nicht eben erweislich ist, mithin nur geglaubt werden kann. Nehme ich das Glauben ohne diese moralische Rücksicht blos in der Bedeutung eines theoretischen Fürwahrhaltens, z.B. dessen, was sich auf dem Zeugniß anderer geschichtmäßig gründet, oder auch, weil ich mir gewisse gegebene Erscheinungen nicht anders als unter dieser oder jener Voraussetzung erklären kann, zu einem Princip an, so ist ein solcher Glaube, weil er weder einen besseren Menschen macht noch einen solchen beweiset, gar kein Stück der Religion; ward er aber nur als durch Furcht und Hoffnung aufgedrungen in der Seele erkünstelt, so ist er der Aufrichtigkeit, mithin auch der Religion zuwider. – Lauten also Spruchstellen so, als ob sie das Glauben einer Offenbarungslehre nicht allein als an sich verdienstlich ansähen, sondern wohl gar über moralisch-gute Werke erhöben, so müssen sie so ausgelegt werden, als ob nur der"}], "markers": [{"system": "AA", "band": "VII", "page": 42, "ref": "VII42"}], "running_header": "II. Philosophische Grundsätze der Schriftauslegung zur Beilegung des Streits"}, {"page_id": "2512_0", "page_pdf": 2512, "page_book": 42, "page_kind": "body", "sigel": "AA VII, 42", "units": [{"type": "paragraph", "text": "moralische, die Seele durch Vernunft bessernde und erhebende Glaube dadurch gemeint sei; gesetzt auch, der buchstäbliche Sinn, z.B. wer da glaubet und getaufet wird, wird selig etc., lautete dieser Auslegung zuwider. Der Zweifel über jene statutarische Dogmen und ihre Authenticität kann also eine moralische, wohlgesinnte Seele nicht beunruhigen. – Eben dieselben Sätze können gleichwohl als wesentliche Erfordernisse zum Vortrag eines gewissen Kirchenglaubens angesehen werden, der aber, weil er nur Vehikel des Religionsglaubens, mithin an sich veränderlich ist und einer allmähligen Reinigung bis zur Congruenz mit dem letzteren fähig bleiben muß, nicht zum Glaubensartikel selbst gemacht, obzwar doch auch in Kirchen nicht öffentlich angegriffen oder auch mit trockenem Fuß übergangen werden darf, weil er unter der Gewahrsame der Regierung steht, die für öffentliche Eintracht und Frieden Sorge trägt, indessen daß es des Lehrers Sache ist davor zu warnen, ihm nicht eine für sich bestehende Heiligkeit beizulegen, sondern ohne Verzug zu dem dadurch eingeleiteten Religionsglauben überzugehen. III. Das Thun muß als aus des Menschen eigenem Gebrauch seiner moralischen Kräfte entspringend und nicht als Wirkung vom Einfluß einer äußeren höheren wirkenden Ursache, in Ansehung deren der Mensch"}], "running_header": "II. Philosophische Grundsätze der Schriftauslegung zur Beilegung des Streits"}, {"page_id": "2512_1", "page_pdf": 2512, "page_book": 43, "page_kind": "body", "sigel": "AA VII, 43", "units": [{"type": "paragraph", "text": "sich leidend verhielte, vorgestellt werden; die Auslegung der Schriftstellen, welche buchstäblich das letztere zu enthalten scheinen, muß also auf die Übereinstimmung mit dem ersteren Grundsatze absichtlich gerichtet werden. Wenn unter Natur das im Menschen herrschende Princip der Beförderung seiner Glückseligkeit, unter Gnade aber die in uns liegende unbegreifliche moralische Anlage, d.i. das Princip der reinen Sittlichkeit, verstanden wird, so sind Natur und Gnade nicht allein von einander unterschieden, sondern auch oft gegen einander in Widerstreit. Wird aber unter Natur (in praktischer Bedeutung) das Vermögen aus eigenen Kräften überhaupt gewisse Zwecke auszurichten verstanden, so ist Gnade nichts anders als Natur des Menschen, so fern er durch sein eigenes inneres, aber übersinnliches Princip (die Vorstellung seiner Pflicht) zu Handlungen bestimmt wird, welches, weil wir uns es erklären wollen, gleichwohl aber weiter keinen Grund davon wissen, von uns als von der Gottheit in uns gewirkter Antrieb zum Guten, dazu wir die Anlage in uns nicht selbst gegründet haben, mithin als Gnade vorgestellt wird. – Die Sünde nämlich (die Bösartigkeit in der menschlichen Natur) hat das Strafgesetz (gleich als für Knechte) nothwendig gemacht, die Gnade aber (d.i. die durch den Glauben an die ursprüngliche Anlage zum Guten in uns und die durch das Beispiel der Gott wohlgefälligen Menschheit an dem Sohne Gottes lebendig werdende Hoffnung der Entwickelung dieses Guten) kann und soll in uns (als Freien) noch mächtiger werden, wenn wir sie nur in uns wirken, d.h. die Gesinnungen eines jenem heil. Beispiel ähnlichen Lebenswandels thätig werden lassen. – Die Schriftstellen also, die eine blos passive Ergebung an eine äußere in uns Heiligkeit wirkende Macht zu enthalten scheinen, müssen so ausgelegt werden, daß daraus erhelle, wir müssen an der Entwickelung jener moralischen Anlage in uns selbst arbeiten, ob sie zwar selber eine Göttlichkeit eines Ursprungs beweiset, der höher ist als alle Vernunft (in der theoretischen Nachforschung der Ursache), und daher, sie besitzen, nicht Verdienst, sondern Gnade ist. IV. Wo das eigene Thun zur Rechtfertigung des Menschen vor seinem eigenen (strenge richtenden) Gewissen nicht zulangt, da ist die Vernunft befugt allenfalls eine übernatürliche Ergänzung seiner mangelhaften Gerechtigkeit (auch ohne daß sie bestimmen darf, worin sie bestehe) gläubig anzunehmen. Diese Befugniß ist für sich selbst klar; denn was der Mensch nach seiner Bestimmung sein soll (nämlich dem heil. Gesetz angemessen), das"}], "markers": [{"system": "AA", "band": "VII", "page": 43, "ref": "VII43"}], "running_header": "II. Philosophische Grundsätze der Schriftauslegung zur Beilegung des Streits"}, {"page_id": "2512_2", "page_pdf": 2512, "page_book": 44, "page_kind": "body", "sigel": "AA VII, 44", "units": [{"type": "paragraph", "text": "muß er auch werden können, und ist es nicht durch eigene Kräfte natürlicherweise möglich, so darf er hoffen, daß es durch äußere göttliche Mitwirkung (auf welche Art es auch sei) geschehen werde. – Man kann noch hinzusetzen, daß der Glaube an diese Ergänzung seligmachend sei, weil er dadurch allein zum gottwohlgefälligen Lebenswandel (als der einzigen Bedingung der Hoffnung der Seligkeit) Muth und feste Gesinnung fassen kann, daß er am Gelingen seiner"}], "markers": [{"system": "AA", "band": "VII", "page": 44, "ref": "VII44"}], "running_header": "II. Philosophische Grundsätze der Schriftauslegung zur Beilegung des Streits"}, {"page_id": "2513_0", "page_pdf": 2513, "page_book": 44, "page_kind": "body", "sigel": "AA VII, 44", "units": [{"type": "paragraph", "text": "Endabsicht (Gott wohlgefällig zu werden) nicht verzweifelt. – Daß er aber wissen und bestimmt müsse angeben können, worin das Mittel dieses Ersatzes (welches am Ende doch überschwenglich und bei allem, was uns Gott darüber selbst sagen möchte, für uns unbegreiflich ist) bestehe, das ist eben nicht nothwendig, ja, auf diese Kenntniß auch nur Anspruch zu machen, Vermessenheit. – Die Schriftstellen also, die eine solche specifische Offenbarung zu enthalten scheinen, müssen so ausgelegt werden, daß sie nur das Vehikel jenes moralischen Glaubens für ein Volk nach dessen bisher bei ihm im Schwang gewesenen Glaubenslehren betreffen und nicht Religionsglauben (für alle Menschen), mithin blos den Kirchenglauben (z.B. für Judenchristen) angehen, welcher historischer Beweise bedarf, deren nicht jedermann theilhaftig werden kann; statt dessen Religion (als auf moralische Begriffe gegründet) für sich vollständig und zweifelsfrei sein muß."}, {"type": "paragraph", "text": "* * *"}, {"type": "paragraph", "text": "Aber selbst wider die Idee einer philosophischen Schriftauslegung höre ich die vereinigte Stimme der biblischen Theologen sich erheben: sie hat, sagt man, erstlich eine naturalistische Religion und nicht Christenthum zur Absicht. Antwort: das Christenthum ist die Idee von der Religion, die überhaupt auf Vernunft gegründet und so fern natürlich sein muß. Es enthält aber ein Mittel der Einführung derselben unter Menschen, die Bibel, deren Ursprung für übernatürlich gehalten wird, die (ihr Ursprung mag sein, welcher er wolle), so fern sie den moralischen Vorschriften der Vernunft in Ansehung ihrer öffentlichen Ausbreitung und inniglicher Belebung beförderlich ist, als Vehikel zur Religion gezählt werden kann und als ein solches auch für übernatürliche Offenbarung angenommen werden mag. Nun kann man eine Religion nur naturalistisch nennen, wenn sie es zum Grundsatze macht, keine solche Offenbarung einzuräumen. Also ist das Christenthum darum nicht eine naturalistische"}], "running_header": "II. Philosophische Grundsätze der Schriftauslegung zur Beilegung des Streits"}, {"page_id": "2513_1", "page_pdf": 2513, "page_book": 45, "page_kind": "body", "sigel": "AA VII, 45", "units": [{"type": "paragraph", "text": "Religion, obgleich es blos eine natürliche ist, weil es nicht in Abrede ist, daß die Bibel nicht ein übernatürliches Mittel der Introduction der letzteren und der Stiftung einer sie öffentlich lehrenden und bekennenden Kirche sein möge, sondern nur auf diesen Ursprung, wenn es auf Religionslehre ankommt, nicht Rücksicht nimmt."}, {"type": "paragraph", "text": "Anmerkungen: * Die Schwärmerei des Postellus in Venedig über diesen Punkt im 16ten Jahrhundert ist von so originaler Art und dient so gut zum Beispiel, in welche Verirrungen, und zwar mit Vernunft zu rasen, man gerathen kann, wenn man die Versinnlichung einer reinen Vernunftidee in die Vorstellung eines Gegenstandes der Sinne verwandelt. Denn wenn unter jener Idee nicht das Abstractum der Menschheit, sondern ein Mensch verstanden wird, so muß dieser von irgend einem Geschlecht sein. Ist dieser von Gott Gezeugte männlichen Geschlechts (ein Sohn), hat die Schwachheit der Menschen getragen und ihre Schuld auf sich genommen, so sind die Schwachheiten sowohl als die Übertretungen des anderen Geschlechts doch von denen des männlichen specifisch unterschieden, und man wird nicht ohne Grund versucht anzunehmen, daß dieses auch seine besondere Stellvertreterin (gleichsam eine göttliche Tochter) als Versöhnerin werde bekommen haben; und diese glaubte Postell in der Person einer frommen Jungfrau in Venedig gefunden zu haben."}], "markers": [{"system": "AA", "band": "VII", "page": 45, "ref": "VII45"}], "running_header": "II. Philosophische Grundsätze der Schriftauslegung zur Beilegung des Streits"}, {"page_id": "2514_0", "page_pdf": 2514, "page_book": 45, "page_kind": "body", "sigel": "AA VII, 45", "units": [{"type": "paragraph", "text": "III. Einwürfe und Beantwortung derselben, die Grundsätze der Schriftauslegung betreffend."}], "running_header": "III. Einwürfe und Beantwortung derselben, die Grundsätze der Schriftauslegung betreffend"}, {"page_id": "2514_1", "page_pdf": 2514, "page_book": 45, "page_kind": "body", "sigel": "AA VII, 45", "units": [{"type": "paragraph", "text": "Wider diese Auslegungsregeln höre ich ausrufen: erstlich: das sind ja insgesammt Urtheile der philosophischen Facultät, welche sich also in das Geschäft des biblischen Theologen Eingriffe erlaubt. – Antwort: zum Kirchenglauben wird historische Gelehrsamkeit, zum Religionsglauben blos Vernunft erfordert. Jenen als Vehikel des letzteren auszulegen ist freilich eine Forderung der Vernunft, aber wo ist eine solche rechtmäßiger, als wo etwas nur als Mittel zu etwas Anderem als Endzweck (dergleichen die Religion ist) einen Werth hat, und giebt es überall wohl ein höheres Princip der Entscheidung, wenn über Wahrheit gestritten wird, als die Vernunft? Es thut auch der theologischen Facultät keinesweges Abbruch, wenn die philosophische sich der Statuten derselben bedient, ihre eigene Lehre durch Einstimmung mit derselben zu bestärken; man sollte vielmehr denken, daß jener dadurch eine Ehre widerfahre. Soll aber doch, was die Schriftauslegung betrifft, durchaus Streit zwischen beiden sein, so weiß ich keinen andern Vergleich als diesen: wenn der biblische Theolog aufhören wird sich der Vernunft zu seinem Behuf zu bedienen, so wird der philosophische auch aufhören zu Bestätigung seiner Sätze die Bibel zu gebrauchen. Ich zweifle aber sehr, daß der erstere sich auf diesen Vertrag einlassen dürfte. – Zweitens: jene Auslegungen sind allegorisch-mystisch, mithin weder biblisch noch philosophisch. Antwort: Es ist gerade das Gegentheil, nämlich daß, wenn der biblische Theolog die Hülle der Religion für die Religion selbst nimmt, er z.B. das ganze alte Testament für eine fortgehende Allegorie (von Vorbildern und symbolischen Vorstellungen) des noch kommenden Religionszustandes erklären muß, wenn er nicht annehmen will, das wäre damals schon wahre Religion gewesen (die doch nicht noch wahrer als wahr sein kann), wodurch dann das neue entbehrlich gemacht"}], "markers": [{"system": "AA", "band": "VII", "page": 45, "ref": "VII45"}], "running_header": "III. Einwürfe und Beantwortung derselben, die Grundsätze der Schriftauslegung betreffend"}, {"page_id": "2514_2", "page_pdf": 2514, "page_book": 46, "page_kind": "body", "sigel": "AA VII, 46", "units": [{"type": "paragraph", "text": "würde. Was aber die vorgebliche Mystik der Vernunftauslegungen betrifft, wenn die Philosophie in Schriftstellen einen moralischen Sinn aufgespäht, ja gar ihn dem Texte aufdringt, so ist diese gerade das einzige Mittel, die Mystik (z.B. eines Swedenborgs) abzuhalten. Denn die Phantasie verläuft sich bei Religionsdingen unvermeidlich ins Überschwengliche, wenn sie das Übersinnliche (was in allem, was Religion heißt, gedacht werden muß) nicht an bestimmte Begriffe der Vernunft, dergleichen die moralische sind, knüpft, und führt zu einem Illuminatism innerer Offenbarungen, deren ein jeder alsdann seine eigene hat und kein öffentlicher Probirstein der Wahrheit mehr Statt findet. Es giebt aber noch Einwürfe, die die Vernunft ihr selbst gegen die Vernunftauslegung der Bibel macht, die wir nach der Reihe oben angeführter Auslegungsregeln kürzlich bemerken und zu heben suchen wollen. _a_) Einwurf: Als Offenbarung muß die Bibel aus sich selbst und nicht durch die Vernunft gedeutet werden; denn der Erkenntnißquell selbst liegt anderswo als in der Vernunft. Antwort: Eben darum, weil jenes Buch als göttliche Offenbarung angenommen wird, muß sie nicht blos nach Grundsätzen der Geschichtslehren (mit sich selbst zusammen zu stimmen) theoretisch, sondern nach Vernunftbegriffen praktisch ausgelegt werden; denn daß eine Offenbarung göttlich sei, kann nie durch Kennzeichen, welche die Erfahrung an die Hand giebt, eingesehen werden. Ihr Charakter (wenigstens als _conditio sine qua non_) ist immer die Übereinstimmung mit dem, was die Vernunft für Gott anständig erklärt. – _b_) Einwurf: Vor allem Praktischen muß doch immer eine Theorie vorhergehen, und da diese als Offenbarungslehre vielleicht Absichten des Willens Gottes, die wir nicht durchdringen können, für uns aber verbindend sein dürften, sie zu befördern, enthalten könnten, so scheint das Glauben an dergleichen theoretische Sätze für sich selbst eine Verbindlichkeit, mithin das Bezweifeln derselben eine Schuld zu enthalten. Antwort: Man kann dieses einräumen, wenn vom Kirchenglauben die Rede ist, bei dem es auf keine andere Praxis als die der angeordneten Gebräuche angesehen ist, wo die, so sich zu einer Kirche bekennen, zum Fürwahrnehmen nichts"}], "markers": [{"system": "AA", "band": "VII", "page": 46, "ref": "VII46"}], "running_header": "III. Einwürfe und Beantwortung derselben, die Grundsätze der Schriftauslegung betreffend"}, {"page_id": "2515_0", "page_pdf": 2515, "page_book": 46, "page_kind": "body", "sigel": "AA VII, 46", "units": [{"type": "paragraph", "text": "mehr, als daß die Lehre nicht unmöglich sei, bedürfen; dagegen zum Religionsglauben Überzeugung von der Wahrheit erforderlich ist, welche aber durch Statute (daß sie göttliche Sprüche sind) nicht beurkundigt werden kann, weil, daß sie es sind, nur immer wiederum durch Geschichte bewiesen werden müßte, die sich selbst für göttliche Offenbarung auszugeben nicht"}], "running_header": "III. Einwürfe und Beantwortung derselben, die Grundsätze der Schriftauslegung betreffend"}, {"page_id": "2515_1", "page_pdf": 2515, "page_book": 47, "page_kind": "body", "sigel": "AA VII, 47", "units": [{"type": "paragraph", "text": "befugt ist. Daher bei diesem, der gänzlich auf Moralität des Lebenswandels, aufs Thun, gerichtet ist, das Fürwahrhalten historischer, obschon biblischer Lehren an sich keinen moralischen Werth oder Unwerth hat und unter die Adiaphora gehört. – _c_) Einwurf: Wie kann man einem Geistlichtodten das »Stehe auf und wandle!« zurufen, wenn diesen Zuruf nicht zugleich eine übernatürliche Macht begleitet, die Leben in ihn hineinbringt? Antwort: Der Zuruf geschieht an den Menschen durch seine eigene Vernunft, sofern sie das übersinnliche Princip des moralischen Lebens in sich selbst hat. Durch dieses kann der Mensch zwar vielleicht nicht sofort zum Leben und um von selbst aufzustehen, aber doch sich zu regen und zur Bestrebung eines guten Lebenswandels erweckt werden (wie einer, bei dem die Kräfte nur schlafen, aber darum nicht erloschen sind), und das ist schon ein Thun, welches keines äußeren Einflusses bedarf und, fortgesetzt, den beabsichtigten Wandel bewirken kann. – _d_) Einwurf: Der Glaube an eine uns unbekannte Ergänzungsart des Mangels unserer eigenen Gerechtigkeit, mithin als Wohlthat eines Anderen ist eine umsonst angenommene Ursache (_petitio principii_) zu Befriedigung des von uns gefühlten Bedürfnisses. Denn was wir von der Gnade eines Oberen erwarten, davon können wir nicht, als ob es sich von selbst verstände, annehmen, daß es uns zu Theil werden müsse, sondern nur, wenn es uns wirklich versprochen worden, und daher nur durch Acceptation eines uns geschehenen bestimmten Versprechens, wie durch einen förmlichen Vertrag. Also können wir, wie es scheint, jene Ergänzung nur, sofern sie durch göttliche Offenbarung wirklich zugesagt worden, und nicht auf gut Glück hin hoffen und voraussetzen. Antwort: Eine unmittelbare göttliche Offenbarung in dem tröstenden Ausspruch: »Dir sind deine Sünden vergeben,« wäre eine übersinnliche Erfahrung, welche unmöglich ist. Aber diese ist auch in Ansehung dessen, was (wie die Religion) auf moralischen Vernunftgründen beruht und dadurch _a priori_, wenigstens in praktischer Absicht, gewiß ist, nicht nöthig. Von einem heiligen und gütigen Gesetzgeber kann man sich die Decrete in Ansehung gebrechlicher, aber Alles, was sie für Pflicht erkennen, nach ihrem ganzen Vermögen zu befolgen strebender Geschöpfe nicht anders denken, und selbst der Vernunftglaube und das Vertrauen auf eine solche Ergänzung, ohne daß eine bestimmte empirisch ertheilte Zusage dazu kommen darf, beweiset mehr die ächte moralische Gesinnung und hiemit die Empfänglichkeit für jene gehoffte Gnadenbezeigung, als es ein empirischer Glaube thun kann."}, {"type": "paragraph", "text": "* * *"}], "markers": [{"system": "AA", "band": "VII", "page": 47, "ref": "VII47"}], "running_header": "III. Einwürfe und Beantwortung derselben, die Grundsätze der Schriftauslegung betreffend"}, {"page_id": "2515_2", "page_pdf": 2515, "page_book": 48, "page_kind": "body", "sigel": "AA VII, 48", "units": [{"type": "paragraph", "text": "Auf solche Weise müssen alle Schriftauslegungen, so fern sie die Religion betreffen, nach dem Princip der in der Offenbarung abgezweckten Sittlichkeit gemacht werden und sind ohne das entweder praktisch leer oder gar Hindernisse des Guten. – Auch sind sie alsdann nur eigentlich authentisch, d.i. der Gott in uns ist selbst der Ausleger, weil wir niemand verstehen als den, der durch unsern eigenen Verstand und unsere eigene Vernunft mit uns redet, die Göttlichkeit einer an uns ergangenen Lehre also durch nichts, als durch Begriffe unserer Vernunft, so fern sie rein-moralisch und hiemit untrüglich sind, erkannt werden kann."}], "markers": [{"system": "AA", "band": "VII", "page": 48, "ref": "VII48"}], "running_header": "III. Einwürfe und Beantwortung derselben, die Grundsätze der Schriftauslegung betreffend"}, {"page_id": "2516_0", "page_pdf": 2516, "page_book": 48, "page_kind": "body", "sigel": "AA VII, 48", "units": [{"type": "heading", "text": "Allgemeine Anmerkung.", "level": 2}, {"type": "paragraph", "text": "Von Religionssecten."}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2516_1", "page_pdf": 2516, "page_book": 48, "page_kind": "body", "sigel": "AA VII, 48", "units": [{"type": "paragraph", "text": "In dem, was eigentlich Religion genannt zu werden verdient, kann es keine Sectenverschiedenheit geben (denn sie ist einig, allgemein und nothwendig, mithin unveränderlich), wohl aber in dem, was den Kirchenglauben betrifft, er mag nun blos auf die Bibel, oder auch auf Tradition gegründet sein: so fern der Glaube an das, was blos Vehikel der Religion ist, für Artikel derselben gehalten wird. Es wäre Herculische und dabei undankbare Arbeit, nur blos die Secten des Christenthums, wenn man unter ihm den messianischen Glauben versteht, alle aufzuzählen; denn da ist jenes blos eine Secte*[1] des letztern, so daß es dem Judenthum in engerer Bedeutung (in dem letzten Zeitpunkt seiner ungetheilten Herrschaft über das Volk) entgegengesetzt wird, wo die Frage ist: »Bist du es, der da kommen soll, oder sollen"}], "markers": [{"system": "AA", "band": "VII", "page": 48, "ref": "VII48"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2516_2", "page_pdf": 2516, "page_book": 49, "page_kind": "body", "sigel": "AA VII, 49", "units": [{"type": "paragraph", "text": "wir eines Anderen warten?«, wofür es auch anfänglich die Römer nahmen. In dieser Bedeutung aber würde das Christenthum ein gewisser auf Satzungen und Schrift gegründeter Volksglaube sein, von dem man nicht wissen könnte, ob er gerade für alle Menschen gültig oder der letzte Offenbarungsglaube sein dürfte, bei dem es forthin bleiben müßte, oder ob nicht künftig andere göttliche Statuten, die dem Zweck noch näher träten, zu erwarten wären. Um also ein bestimmtes Schema der Eintheilung einer Glaubenslehre in Secten zu haben, können wir nicht von empirischen Datis, sondern wir müssen von Verschiedenheiten anfangen, die sich _a priori _durch die Vernunft denken lassen, um in der Stufenreihe der Unterschiede der Denkungsart in Glaubenssachen die Stufe auszumachen, in der die Verschiedenheit zuerst einen Sectenunterschied begründen würde. In Glaubenssachen ist das Princip der Eintheilung nach der angenommenen Denkungsart entweder Religion oder Heidenthum (die einander wie _A_ und _non A_ entgegen sind). Die Bekenner der ersteren werden gewöhnlich Gläubige, die des zweiten Ungläubige genannt. Religion ist derjenige Glaube, der das Wesentliche aller Verehrung Gottes in der Moralität des Menschen setzt: Heidenthum, der es nicht darin setzt; entweder weil es ihm gar an dem Begriffe eines übernatürlichen und moralischen Wesens mangelt (_Ethnicismus brutus_), oder weil er etwas Anderes als die Gesinnung eines sittlich wohlgeführten Lebenswandels, also das Nichtwesentliche der Religion, zum Religionsstück macht (_Ethnicismus speciosus_). Glaubenssätze, welche zugleich als göttliche Gebote gedacht werden sollen, sind nun entweder blos statutarisch, mithin für uns zufällig und Offenbarungslehren, oder moralisch, mithin mit dem Bewußtsein ihrer Nothwendigkeit verbunden und _a priori _erkennbar, d.i. Vernunftlehren des Glaubens. Der Inbegriff der ersteren Lehren macht den Kirchen-, der anderen aber den reinen Religionsglauben aus.*[2] Allgemeinheit für einen Kirchenglauben zu fordern (_catholicismus hierarchicus_) ist ein Widerspruch, weil unbedingte Allgemeinheit Nothwendigkeit voraus setzt, die nur da Statt findet, wo die Vernunft selbst die Glaubenssätze hinreichend begründet, mithin diese nicht bloße Statute"}], "markers": [{"system": "AA", "band": "VII", "page": 49, "ref": "VII49"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2516_3", "page_pdf": 2516, "page_book": 50, "page_kind": "body", "sigel": "AA VII, 50", "units": [{"type": "paragraph", "text": "sind. Dagegen hat der reine Religionsglaube rechtmäßigen Anspruch auf Allgemeingültigkeit (_catholicismus rationalis_)_. _Die Sectirerei in Glaubenssachen wird also bei dem letztern nie Statt finden, und wo sie angetroffen wird, da entspringt sie immer aus einem Fehler des Kirchenglaubens: seine Statute (selbst göttliche Offenbarungen) für wesentliche Stücke der Religion zu halten, mithin den Empirism in Glaubenssachen dem Rationalism unterzuschieben und so das blos Zufällige für an sich nothwendig auszugeben. Da nun in zufälligen Lehren es vielerlei einander widerstreitende, theils Satzungen, theils Auslegung von Satzungen, geben kann: so ist leicht einzusehen, daß der bloße Kirchenglaube, ohne durch den reinen Religionsglauben geläutert zu sein, eine reiche Quelle unendlich vieler Secten in Glaubenssachen sein werde. Um diese Läuterung, worin sie bestehe, bestimmt anzugeben, scheint mir der zum Gebrauch"}], "markers": [{"system": "AA", "band": "VII", "page": 50, "ref": "VII50"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2517_0", "page_pdf": 2517, "page_book": 50, "page_kind": "body", "sigel": "AA VII, 50", "units": [{"type": "paragraph", "text": "schicklichste Probirstein der Satz zu sein: ein jeder Kirchenglaube, so fern er blos statutarische Glaubenslehren für wesentliche Religionslehren ausgiebt, hat eine gewisse Beimischung von Heidenthum; denn dieses besteht darin, das Äußerliche (Außerwesentliche) der Religion für wesentlich auszugeben. Diese Beimischung kann gradweise so weit gehen, daß die ganze Religion darüber in einen bloßen Kirchenglauben, Gebräuche für Gesetze auszugeben, übergeht und alsdann baares Heidenthum wird,*[3] wider welchen Schimpfnamen es nichts verschlägt zu sagen, daß jene Lehren doch göttliche Offenbarungen seien; denn nicht jene statutarische Lehren und Kirchenpflichten selbst, sondern der unbedingte ihnen beigelegte Werth (nicht etwa blos Vehikel, sondern selbst Religionsstücke zu sein, ob sie zwar keinen inneren moralischen Gehalt bei sich führen, also nicht die Materie der Offenbarung, sondern die Form ihrer Aufnahme in seine praktische Gesinnung) ist das, was auf eine solche Glaubensweise den Namen des Heidenthums mit Recht fallen läßt. Die kirchliche Autorität, nach einem solchen Glauben selig zu sprechen oder zu verdammen, würde das Pfaffenthum genannt werden, von welchem Ehrennamen sich so nennende Protestanten nicht auszuschließen sind, wenn sie das Wesentliche"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2517_1", "page_pdf": 2517, "page_book": 51, "page_kind": "body", "sigel": "AA VII, 51", "units": [{"type": "paragraph", "text": "ihrer Glaubenslehre in Glauben an Sätze und Observanzen, von denen ihnen die Vernunft nichts sagt, und welche zu bekennen und zu beobachten der schlechteste, nichtswürdigste Mensch in eben demselben Grade tauglich ist als der beste, zu setzen bedacht sind: sie mögen auch einen noch so großen Nachtrapp von Tugenden, als die aus der wundervollen Kraft der ersteren entsprängen (mithin ihre eigene Wurzel nicht haben), anhängen, als sie immer wollen. Von dem Punkte also, wo der Kirchenglaube anfängt, für sich selbst mit Autorität zu sprechen, ohne auf seine Rectification durch den reinen Religionsglauben zu achten, hebt auch die Sectirerei an; denn da dieser (als praktischer Vernunftglaube) seinen Einfluß auf die menschliche Seele nicht verlieren kann, der mit dem Bewußtsein der Freiheit verbunden ist, indessen daß der Kirchenglaube über die Gewissen Gewalt ausübt: so sucht ein jeder etwas für seine eigene Meinung in den Kirchenglauben hinein oder aus ihm heraus zu bringen. Diese Gewalt veranlaßt entweder bloße Absonderung von der Kirche (Separatism), d.i. Enthaltung von der öffentlichen Gemeinschaft mit ihr, oder öffentliche Spaltung der in Ansehung der kirchlichen Form Andersdenkenden, ob sie zwar der Materie nach sich zu eben derselben bekennen (Schismatiker), oder Zusammentretung der Dissidenten in Ansehung gewisser Glaubenslehren in besondere, nicht immer geheime, aber doch vom Staat nicht sanctionirte Gesellschaften (Sectirer), deren einige noch besondere, nicht fürs große Publicum gehörende, geheime Lehren aus eben demselben Schatz her holen (gleichsam Clubbisten der Frömmigkeit), endlich auch falsche Friedensstifter, die durch die Zusammenschmelzung verschiedener Glaubensarten allen genug zu thun meinen (Synkretisten); die dann noch schlimmer sind als Sectirer, weil Gleichgültigkeit in Ansehung der Religion überhaupt zum Grunde liegt und, weil einmal doch ein Kirchenglaube im Volk sein müsse, einer so gut wie der andere sei, wenn er sich nur durch die Regierung zu ihren Zwecken gut handhaben läßt; ein Grundsatz, der im Munde des Regenten, als eines solchen, zwar ganz richtig, auch sogar weise ist, im Urtheile des Unterthanen selbst aber, der diese Sache aus seinem eigenen und zwar moralischen Interesse zu erwägen hat, die äußerste Geringschätzung der Religion verrathen würde; indem, wie selbst das Vehikel der Religion beschaffen sei, was jemand in seinen Kirchenglauben aufnimmt, für die Religion keine gleichgültige Sache ist. In Ansehung der Sectirerei (welche auch wohl ihr Haupt bis zur"}], "markers": [{"system": "AA", "band": "VII", "page": 51, "ref": "VII51"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2517_2", "page_pdf": 2517, "page_book": 52, "page_kind": "body", "sigel": "AA VII, 52", "units": [{"type": "paragraph", "text": "Vermannigfaltigung der Kirchen erhebt, wie es bei den Protestanten geschehen ist) pflegt man zwar zu sagen: es ist gut, daß es vielerlei Religionen (eigentlich kirchliche Glaubensarten in einem Staate) giebt, und so fern ist dieses auch richtig, als es ein gutes Zeichen ist: nämlich daß Glaubensfreiheit dem Volke gelassen worden; aber das ist eigentlich nur ein Lob für die Regierung. An sich aber ist ein solcher öffentlicher Religionszustand doch nicht gut, dessen Princip so beschaffen ist, daß es nicht, wie es doch der Begriff einer Religion erfordert, Allgemeinheit und Einheit der wesentlichen Glaubensmaximen bei sich führt und den Streit, der"}], "markers": [{"system": "AA", "band": "VII", "page": 52, "ref": "VII52"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2518_0", "page_pdf": 2518, "page_book": 52, "page_kind": "body", "sigel": "AA VII, 52", "units": [{"type": "paragraph", "text": "von dem Außerwesentlichen herrührt, nicht von jenem unterscheidet. Der Unterschied der Meinungen in Ansehung der größeren oder minderen Schicklichkeit oder Unschicklichkeit des Vehikels der Religion zu dieser als Endabsicht selbst (nämlich die Menschen moralisch zu bessern) mag also allenfalls Verschiedenheit der Kirchensecten, darf aber darum nicht Verschiedenheit der Religionssecten bewirken, welche der Einheit und Allgemeinheit der Religion (also der unsichtbaren Kirche) gerade zuwider ist. Aufgeklärte Katholiken und Protestanten werden also einander als Glaubensbrüder ansehen können, ohne sich doch zu vermengen, beide in der Erwartung (und Bearbeitung zu diesem Zweck): daß die Zeit unter Begünstigung der Regierung nach und nach die Förmlichkeiten des Glaubens (der freilich alsdann nicht ein Glaube sein muß, Gott sich durch etwas anders, als durch reine moralische Gesinnung günstig zu machen oder zu versöhnen) der Würde ihres Zwecks, nämlich der Religion selbst, näher bringen werde. – Selbst in Ansehung der Juden ist dieses ohne die Träumerei einer allgemeinen Judenbekehrung*[4] (zum Christenthum als einem messianischen Glauben) möglich, wenn unter ihnen, wie jetzt geschieht, geläuterte Religionsbegriffe erwachen und das Kleid des nunmehr zu nichts dienenden, vielmehr alle"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2518_1", "page_pdf": 2518, "page_book": 53, "page_kind": "body", "sigel": "AA VII, 53", "units": [{"type": "paragraph", "text": "wahre Religionsgesinnung verdrängenden alten Cultus abwerfen. Da sie nun so lange das Kleid ohne Mann (Kirche ohne Religion) gehabt haben, gleichwohl aber der Mann ohne Kleid (Religion ohne Kirche) auch nicht gut verwahrt ist, sie also gewisse Förmlichkeiten einer Kirche, die dem Endzweck in ihrer jetzigen Lage am angemessensten wäre, bedürfen: so kann man den Gedanken eines sehr guten Kopfs dieser Nation, Bendavid’s , die Religion Jesu (vermuthlich mit ihrem Vehikel, dem Evangelium) öffentlich anzunehmen, nicht allein für sehr glücklich, sondern auch für den einzigen Vorschlag halten, dessen Ausführung dieses Volk, auch ohne sich mit andern in Glaubenssachen zu vermischen, bald als ein gelehrtes, wohlgesittetes und aller Rechte des bürgerlichen Zustandes fähiges Volk, dessen Glaube auch von der Regierung sanctionirt werden könnte, bemerklich machen würde; wobei freilich ihr die Schriftauslegung (der Thora und des Evangeliums) frei gelassen werden müßte, um die Art, wie Jesus als Jude zu Juden, von der Art, wie er als moralischer Lehrer zu Menschen überhaupt redete, zu unterscheiden. – Die Euthanasie des Judenthums ist die reine moralische Religion mit Verlassung aller alten Satzungslehren, deren einige doch im Christenthum (als messianischen Glauben) noch zurück behalten bleiben müssen: welcher Sectenunterschied endlich doch auch verschwinden muß und so das, was man als den Beschluß des großen Drama des Religionswechsels auf Erden nennt, (die Wiederbringung aller Dinge) wenigstens im Geiste herbeiführt, da nur ein Hirt und eine Heerde Statt findet."}, {"type": "paragraph", "text": "* * *"}, {"type": "paragraph", "text": "Wenn aber gefragt wird: nicht blos was Christenthum sei, sondern wie es der Lehrer desselben anzufangen habe, damit ein solches in den Herzen der Menschen wirklich angetroffen werde (welches mit der Aufgabe einerlei ist: was ist zu thun, damit der Religionsglaube zugleich bessere Menschen mache?), so ist der Zweck zwar einerlei und kann keinen Sectenunterschied veranlassen, aber die Wahl des Mittels zu demselben kann diesen doch herbei führen, weil zu einer und derselben Wirkung sich mehr wie eine Ursache denken läßt und sofern also Verschiedenheit und Streit der Meinungen, ob das eine oder das andere demselben angemessen und göttlich sei, mithin eine Trennung in Principien bewirken kann, die selbst"}], "markers": [{"system": "AA", "band": "VII", "page": 53, "ref": "VII53"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2518_2", "page_pdf": 2518, "page_book": 54, "page_kind": "body", "sigel": "AA VII, 54", "units": [{"type": "paragraph", "text": "das Wesentliche (in subjectiver Bedeutung) der Religion überhaupt angehen. Da die Mittel zu diesem Zwecke nicht empirisch sein können – weil dies allenfalls wohl auf die That, aber nicht auf die Gesinnung hinwirken –, so muß für den, der alles Übersinnliche zugleich für übernatürlich hält, die obige Aufgabe sich in die Frage verwandeln: wie ist die Wiedergeburt (als die Folge der Bekehrung, wodurch jemand ein anderer, neuer Mensch wird) durch göttlichen unmittelbaren Einfluß möglich, und was hat der Mensch zu thun, um diesen"}], "markers": [{"system": "AA", "band": "VII", "page": 54, "ref": "VII54"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2519_0", "page_pdf": 2519, "page_book": 54, "page_kind": "body", "sigel": "AA VII, 54", "units": [{"type": "paragraph", "text": "herbei zu ziehen? Ich behaupte, daß, ohne die Geschichte zu Rathe zu ziehen (als welche zwar Meinungen, aber nicht die Nothwendigkeit derselben vorstellig machen kann), man _a priori _ einen unausbleiblichen Sectenunterschied, den blos diese Aufgabe bei denen bewirkt, welchen es eine Kleinigkeit ist, zu einer natürlichen Wirkung übernatürliche Ursachen herbei zu rufen, vorher sagen kann, ja daß diese Spaltung auch die einzige sei, welche zur Benennung zweier verschiedener Religionssecten berechtigt; denn die anderen, welche man fälschlich so benennt, sind nur Kirchensecten und gehen das Innere der Religion nicht an. – Ein jedes Problem aber besteht erstlich aus der Quästion der Aufgabe, zweitens der Auflösung und drittens dem Beweis, daß das Verlangte durch die letztere geleistet werde. Also: 1) Die Aufgabe (die der wackere Spener mit Eifer allen Lehrern der Kirche zurief) ist: der Religionsvortrag muß zum Zweck haben, aus uns andere, nicht blos bessere Menschen (gleich als ob wir so schon gute, aber nur dem Grade nach vernachlässigte wären) zu machen. Dieser Satz ward den Orthodoxisten (ein nicht übel ausgedachter Name) in den Weg geworfen, welche in dem Glauben an die reine Offenbarungslehre und den von der Kirche vorgeschriebenen Observanzen (dem Beten, dem Kirchengehen und den Sacramenten) neben dem ehrbaren (zwar mit Übertretungen untermengten, durch jene aber immer wieder gut zu machenden) Lebenswandel die Art setzten, Gott wohlgefällig zu werden. – Die Aufgabe ist also ganz in der Vernunft gegründet. 2) Die Auflösung aber ist völlig mystisch ausgefallen: so wie man es vom Supernaturalism in Principien der Religion erwarten konnte, der, weil der Mensch von Natur in Sünden todt sei, keine Besserung aus eigenen Kräften hoffen lasse, selbst nicht aus der ursprünglichen unverfälschbaren moralischen Anlage in seiner Natur, die, ob sie gleich übersinnlich ist, dennoch Fleisch genannt wird, darum weil ihre Wirkung nicht zugleich"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2519_1", "page_pdf": 2519, "page_book": 55, "page_kind": "body", "sigel": "AA VII, 55", "units": [{"type": "paragraph", "text": "übernatürlich ist, als in welchem Falle die unmittelbare Ursache derselben allein der Geist (Gottes) sein würde. – Die mystische Auflösung jener Aufgabe theilt nun die Gläubigen in zwei Secten des Gefühls übernatürlicher Einflüsse: die eine, wo das Gefühl als von herzzermalmender (zerknirschender), die andere, wo es von herzzerschmelzender (in die selige Gemeinschaft mit Gott sich auflösender) Art sein müsse, so daß die Auflösung des Problems (aus bösen Menschen gute zu machen) von zwei entgegengesetzten Standpunkten ausgeht (»wo das Wollen zwar gut ist, aber das Vollbringen mangelt«). In der einen Secte kommt es nämlich nur darauf an, von der Herrschaft des Bösen in sich los zu kommen, worauf dann das gute Princip sich von selbst einfinden würde: in der andern, das gute Princip in seine Gesinnung aufzunehmen, worauf vermittelst eines übernatürlichen Einflusses das Böse für sich keinen Platz mehr finden und das Gute allein herrschend sein würde. Die Idee von einer moralischen, aber nur durch übernatürlichen Einfluß möglichen Metamorphose des Menschen mag wohl schon längst in den Köpfen der Gläubigen rumort haben: sie ist aber in neueren Zeiten allererst recht zur Sprache gekommen und hat den Spener-Franckischen und den Mährisch-Zinzendorfschen Sectenunterschied (den Pietism und Moravianism) in der Bekehrungslehre hervorgebracht. Nach der ersteren Hypothese geschieht die Scheidung des Guten vom Bösen (womit die menschliche Natur amalgamirt ist) durch eine übernatürliche Operation, die Zerknirschung und Zermalmung des Herzens in der Buße, als einem nahe an Verzweiflung grenzenden, aber doch auch nur durch den Einfluß eines himmlischen Geistes in seinem nöthigen Grade erreichbaren Gram (_maeror animi_), um welchen der Mensch selbst bitten müsse, indem er sich selbst darüber grämt, daß er sich nicht genug gräme (mithin das Leidsein ihm doch nicht so ganz von Herzen gehen kann). Diese »Höllenfahrt des Selbsterkenntnisses bahnt nun, wie der sel. Hamann sagt, den Weg zur Vergötterung«. Nämlich nachdem diese Glut der Buße ihre größte Höhe erreicht hat, geschehe der Durchbruch, und der Regulus des Wiedergebornen glänze unter den Schlacken, die ihn zwar umgeben, aber nicht verunreinigen, tüchtig zu dem Gott wohlgefälligen Gebrauch in einem guten Lebenswandel. – Diese radicale Veränderung fängt also mit einem"}], "markers": [{"system": "AA", "band": "VII", "page": 55, "ref": "VII55"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2520_0", "page_pdf": 2520, "page_book": 55, "page_kind": "body", "sigel": "AA VII, 55", "units": [{"type": "paragraph", "text": "Wunder an und endigt mit dem, was man sonst als natürlich anzusehen pflegt, weil es die Vernunft vorschreibt, nämlich mit dem moralisch-guten Lebenswandel. Weil man aber selbst"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2520_1", "page_pdf": 2520, "page_book": 56, "page_kind": "body", "sigel": "AA VII, 56", "units": [{"type": "paragraph", "text": "beim höchsten Fluge einer mystisch-gestimmten Einbildungskraft den Menschen doch nicht von allem Selbstthun lossprechen kann, ohne ihn gänzlich zur Maschine zu machen, so ist das anhaltende inbrünstige Gebet das, was ihm noch zu thun obliegt, (wofern man es überhaupt für ein Thun will gelten lassen) und wovon er sich jene übernatürliche Wirkung allein versprechen kann; wobei doch auch der Scrupel eintritt: daß, da das Gebet, wie es heißt, nur sofern erhörlich ist, als es im Glauben geschieht, dieser selbst aber eine Gnadenwirkung ist, d.i. etwas, wozu der Mensch aus eigenen Kräften nicht gelangen kann, er mit seinen Gnadenmitteln im Cirkel geführt wird und am Ende eigentlich nicht weiß, wie er das Ding angreifen solle. Nach der zweiten Secte Meinung geschieht der erste Schritt, den der sich seiner sündigen Beschaffenheit bewußt werdende Mensch zum Besseren thut, ganz natürlich, durch die Vernunft, die, indem sie ihm im moralischen Gesetz den Spiegel vorhält, worin er seine Verwerflichkeit erblickt, die moralische Anlage zum Guten benutzt, um ihn zur Entschließung zu bringen, es fortmehr zu seiner Maxime zu machen: aber die Ausführung dieses Vorsatzes ist ein Wunder . Er wendet sich nämlich von der Fahne des bösen Geistes ab und begiebt sich unter die des guten, welches eine leichte Sache ist. Aber nun bei dieser zu beharren, nicht wieder ins Böse zurück zu fallen, vielmehr im Guten immer mehr fortzuschreiten, das ist die Sache, wozu er natürlicher Weise unvermögend sei, vielmehr nichts Geringeres als Gefühl einer übernatürlichen Gemeinschaft und sogar das Bewußtsein eines continuirlichen Umganges mit einem himmlischen Geiste erfordert werde; wobei es zwischen ihm und dem letzteren zwar auf einer Seite nicht an Verweisen, auf der andern nicht an Abbitten fehlen kann: doch ohne daß eine Entzweiung oder Rückfall (aus der Gnade) zu besorgen ist; wenn er nur darauf Bedacht nimmt, diesen Umgang, der selbst ein continuirliches Gebet ist, ununterbrochen zu cultiviren. Hier ist nun eine zwiefache mystische Gefühlstheorie zum Schlüssel der Aufgabe: ein neuer Mensch zu werden, vorgelegt, wo es nicht um das Object und den Zweck aller Religion (den Gott gefälligen Lebenswandel, denn darüber stimmen beide Theile überein), sondern um die subjective Bedingungen zu thun ist, unter denen wir allein Kraft dazu bekommen, jene Theorie in uns zur Ausführung zu bringen; wobei dann von Tugend (die ein leerer Name sei) nicht die Rede sein kann, sondern nur von der Gnade, weil beide Parteien darüber einig sind, daß es hiemit"}], "markers": [{"system": "AA", "band": "VII", "page": 56, "ref": "VII56"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2520_2", "page_pdf": 2520, "page_book": 57, "page_kind": "body", "sigel": "AA VII, 57", "units": [{"type": "paragraph", "text": "nicht natürlich zugehen könne, sich aber wieder darin von einander trennen, daß der eine Theil den fürchterlichen Kampf mit dem bösen Geiste, um von dessen Gewalt los zu kommen, bestehen muß, der andere aber dieses gar nicht nöthig, ja als Werkheiligkeit verwerflich findet, sondern geradezu mit dem guten Geiste Allianz schließt, weil die vorige mit dem bösen (als _pactum turpe_) gar keinen Einspruch dagegen verursachen kann; da dann die Wiedergeburt als einmal für allemal vorgehende übernatürliche und radicale Revolution im Seelenzustande auch wohl äußerlich einen Sectenunterschied aus so sehr gegen einander abstechenden Gefühlen beider Parteien, kennbar machen dürfte.*[5] 3) Der Beweis: daß, wenn, was Nr. 2 verlangt worden, geschehen, die Aufgabe Nr. 1 dadurch aufgelöset sein werde. – Dieser Beweis ist unmöglich. Denn der Mensch müßte beweisen, daß in ihm eine übernatürliche Erfahrung, die an sich selbst ein Widerspruch ist, vorgegangen sei. Es könnte allenfalls eingeräumt werden, daß der Mensch in sich eine Erfahrung (z.B. von neuen und besseren Willensbestimmungen) gemacht hätte, von einer Veränderung, die er sich nicht anders als durch ein Wunder zu erklären weiß, also von etwas Übernatürlichem. Aber eine Erfahrung, von der er sich sogar nicht einmal, daß sie in der That Erfahrung sei, überführen kann, weil sie (als übernatürlich) auf keine Regel der Natur unseres Verstandes zurückgeführt und dadurch bewährt werden kann, ist eine Ausdeutung gewisser Empfindungen, von denen man nicht weiß, was man aus ihnen machen soll, ob sie als zum Erkenntniß gehörig einen wirklichen Gegenstand haben, oder bloße Träumereien sein mögen. Den"}], "markers": [{"system": "AA", "band": "VII", "page": 57, "ref": "VII57"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2521_0", "page_pdf": 2521, "page_book": 58, "page_kind": "body", "sigel": "AA VII, 58", "units": [{"type": "paragraph", "text": "unmittelbaren Einfluß der Gottheit als einer solchen fühlen wollen, ist, weil die Idee von dieser blos in der Vernunft liegt, eine sich selbst widersprechende Anmaßung. – Also ist hier eine Aufgabe sammt ihrer Auflösung ohne irgend einen möglichen Beweis; woraus denn auch nie etwas Vernünftiges gemacht werden wird. Es kommt nun noch darauf an, nachzusuchen, ob die Bibel nicht noch ein anderes Princip der Auflösung jenes Spenerischen Problems, als die zwei angeführte sectenmäßige enthalte, welches die Unfruchtbarkeit des kirchlichen Grundsatzes der bloßen Orthodoxie ersetzen könne. In der That ist nicht allein in die Augen fallend, daß ein solches in der Bibel anzutreffen sei, sondern auch überzeugend gewiß, daß nur durch dasselbe und das in diesem Princip enthaltene Christenthum dieses Buch seinen so weit ausgebreiteten Wirkungskreis und dauernden Einfluß auf die Welt hat erwerben können, eine Wirkung, die keine Offenbarungslehre (als solche), kein Glaube an Wunder, keine vereinigte Stimme vieler Bekenner je hervorgebracht hätte, weil sie nicht aus der Seele des Menschen selbst geschöpft gewesen wäre und ihm also immer hätte fremd bleiben müssen. Es ist nämlich etwas in uns, was zu bewundern wir niemals aufhören können, wenn wir es einmal ins Auge gefaßt haben, und dieses ist zugleich dasjenige, was die Menschheit in der Idee zu einer Würde erhebt, die man am Menschen als Gegenstande der Erfahrung nicht vermuthen sollte. Daß wir den moralischen Gesetzen unterworfene und zu deren Beobachtung selbst mit Aufopferung aller ihnen widerstreitenden Lebensannehmlichkeiten durch unsere Vernunft bestimmte Wesen sind, darüber wundert man sich nicht, weil es objectiv in der natürlichen Ordnung der Dinge als Objecte der reinen Vernunft liegt, jenen Gesetzen zu gehorchen: ohne daß es dem gemeinen und gesunden Verstande nur einmal einfällt, zu fragen, woher uns jene Gesetze kommen mögen, um vielleicht, bis wir ihren Ursprung wissen, die Befolgung derselben aufzuschieben, oder wohl gar ihre Wahrheit zu bezweifeln. – Aber daß wir auch das Vermögen dazu haben, der Moral mit unserer sinnlichen Natur so große Opfer zu bringen, daß wir das auch können, wovon wir ganz leicht und klar begreifen, daß wir es sollen, diese Überlegenheit des übersinnlichen Menschen in uns über den sinnlichen, desjenigen, gegen den der letztere (wenn es zum Widerstreit kommt) nichts ist, ob dieser zwar in seinen eigenen Augen Alles ist, diese moralische, von der Menschheit unzertrennliche Anlage in uns ist ein Gegenstand der höchsten Bewunderung,"}], "markers": [{"system": "AA", "band": "VII", "page": 58, "ref": "VII58"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2521_1", "page_pdf": 2521, "page_book": 59, "page_kind": "body", "sigel": "AA VII, 59", "units": [{"type": "paragraph", "text": "die, je länger man dieses wahre (nicht erdachte) Ideal ansieht, nur immer desto höher steigt: so daß diejenigen wohl zu entschuldigen sind, welche, durch die Unbegreiflichkeit desselben verleitet, dieses Übersinnliche in uns, weil es doch praktisch ist, für übernatürlich, d.i. für etwas, was gar nicht in unserer Macht steht und uns als eigen zugehört, sondern vielmehr für den Einfluß von einem andern und höheren Geiste halten; worin sie aber sehr fehlen: weil die Wirkung dieses Vermögens alsdann nicht unsere That sein, mithin uns auch nicht zugerechnet werden könnte, das Vermögen dazu also nicht das unsrige sein würde. – Die Benutzung der Idee dieses uns unbegreiflicher Weise beiwohnenden Vermögens und in Ansherzlegung derselben von der frühesten Jugend an und fernerhin im öffentlichen Vortrage enthält nun die ächte Auflösung jenes Problems (vom neuen Menschen), und selbst die Bibel scheint nichts anders vor Augen gehabt zu haben, nämlich nicht auf übernatürliche Erfahrungen und schwärmerische Gefühle hin zu weisen, die statt der Vernunft diese Revolution bewirken sollten: sondern auf den Geist Christi, um ihn, so wie er ihn in Lehre und Beispiel bewies, zu dem unsrigen zu machen, oder vielmehr, da er mit der ursprünglichen moralischen Anlage schon in uns liegt, ihm nur Raum zu verschaffen. Und so ist zwischen dem seelenlosen Orthodoxism und dem vernunfttödtenden Mysticism die biblische Glaubenslehre, so wie sie vermittelst der Vernunft aus uns selbst entwickelt werden kann, die mit göttlicher Kraft auf aller Menschen Herzen zur gründlichen Besserung hinwirkende und sie in einer allgemeinen (obzwar unsichtbaren) Kirche vereinigende, auf dem Kriticism der praktischen Vernunft gegründete wahre Religionslehre."}], "markers": [{"system": "AA", "band": "VII", "page": 59, "ref": "VII59"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2522_0", "page_pdf": 2522, "page_book": 59, "page_kind": "body", "sigel": "AA VII, 59", "units": [{"type": "paragraph", "text": "* * *"}, {"type": "paragraph", "text": "Das aber, worauf es in dieser Anmerkung eigentlich ankommt, ist die Beantwortung der Frage: ob die Regierung wohl einer Secte des Gefühlglaubens die Sanction einer Kirche könne angedeihen lassen; oder ob sie eine solche zwar dulden und schützen, mit jenem Prärogativ aber nicht beehren könne, ohne ihrer eigenen Absicht zuwider zu handeln. Wenn man annehmen darf (wie man es denn mit Grunde thun kann), daß es der Regierung Sache gar nicht sei, für die künftige Seligkeit der Unterthanen Sorge zu tragen und ihnen den Weg dazu anzuweisen (denn das muß sie wohl diesen selbst überlassen, wie denn auch der Regent selbst"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2522_1", "page_pdf": 2522, "page_book": 60, "page_kind": "body", "sigel": "AA VII, 60", "units": [{"type": "paragraph", "text": "seine eigene Religion gewöhnlicher Weise vom Volk und dessen Lehrern her hat): so kann ihre Absicht nur sein, auch durch dieses Mittel (den Kirchenglauben) lenksame und moralisch-gute Unterthanen zu haben. Zu dem Ende wird sie erstlich keinen Naturalism (Kirchenglauben ohne Bibel) sanctioniren, weil es bei dem gar keine dem Einfluß der Regierung unterworfene kirchliche Form geben würde, welches der Voraussetzung widerspricht. – Die biblische Orthodoxie würde also das sein, woran sie die öffentliche Volkslehrer bände, in Ansehung deren diese wiederum unter der Beurtheilung der Facultäten stehen würden, die es angeht, weil sonst ein Pfaffenthum, d.i. eine Herrschaft der Werkleute des Kirchenglaubens, entstehen würde, das Volk nach ihren Absichten zu beherrschen. Aber den Orthodoxism, d.i. die Meinung von der Hinlänglichkeit des Kirchenglaubens zur Religion, würde sie durch ihre Autorität nicht bestätigen: weil diese die natürliche Grundsätze der Sittlichkeit zur Nebensache macht, da sie vielmehr die Hauptstütze ist, worauf die Regierung muß rechnen können, wenn sie in ihr Volk Vertrauen setzen soll. *[6] Endlich kann sie am wenigsten den Mysticism als Meinung des Volks, übernatürlicher Inspiration selbst theilhaftig werden zu können, zum Rang eines öffentlichen Kirchenglaubens erheben, weil er gar nichts Öffentliches ist und sich also dem Einfluß der Regierung gänzlich entzieht."}, {"type": "paragraph", "text": "Anmerkungen: *[1] Es ist eine Sonderbarkeit des deutschen Sprachgebrauchs (oder Mißbrauchs), daß sich die Anhänger unserer Religion Christen nennen; gleich als ob es mehr als einen Christus gebe und jeder Gläubige ein Christus wäre. Sie müßten sich Christianer nennen. – Aber dieser Name würde sofort wie ein Sectenname angesehen werden von Leuten, denen man (wie im Peregrinus Proteus geschieht) viel Übels nachsagen kann: welches in Ansehung des Christen nicht Statt findet. – So verlangte ein Recensent in der Hallischen gel. Zeitung, daß der Name Jehovah durch Jahwoh ausgesprochen werden sollte. Aber diese Veränderung würde eine bloße Nationalgottheit, nicht den Herrn der Welt zu bezeichnen scheinen. *[2] Diese Eintheilung, welche ich nicht für präcis und dem gewöhnlichen Redegebrauch angemessen ausgebe, mag einstweilen hier gelten. *[3] Heidenthum (_Paganismus_) ist der Worterklärung nach der religiöse Aberglaube des Volks in Wäldern (Heiden), d.i. einer Menge, deren Religionsglaube noch ohne alle kirchliche Verfassung, mithin ohne öffentliches Gesetz ist. Juden aber, Mohammedaner und Indier halten das für kein Gesetz, was nicht das ihrige ist, und benennen andere Völker, die nicht eben dieselbe kirchliche Observanzen haben, mit dem Titel der Verwerfung (Goj, Dschaur u.s.w.), nämlich der Ungläubigen. *[4] Moses Mendelssohn wies dieses Ansinnen auf eine Art ab, die seiner Klugheit Ehre macht (durch eine _argumentatio ad hominem_). So lange (sagt er) als nicht Gott vom Berge Sinai eben so feierlich unser Gesetz aufhebt, als er es (unter Donner und Blitz) gegeben, d.i. bis zum Nimmertag, sind wir daran gebunden; womit er wahrscheinlicher Weise sagen wollte: Christen, schafft ihr erst das Judenthum aus Eurem eigenen Glauben weg: so werden wir auch das unsrige verlassen. – Daß er aber seinen eignen Glaubensgenossen durch diese harte Forderung die Hoffnung zur mindesten Erleichterung der sie drückenden Lasten abschnitt, ob er zwar wahrscheinlich die wenigsten derselben für wesentlich seinem Glauben angehörig hielt, ob das seinem guten Willen Ehre mache, mögen diese selbst entscheiden."}], "markers": [{"system": "AA", "band": "VII", "page": 60, "ref": "VII60"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2523", "page_pdf": 2523, "page_book": 60, "page_kind": "body", "sigel": "AA VII, 60", "units": [{"type": "paragraph", "text": "*[5] Welche Nationalphysiognomie möchte wohl ein ganzes Volk, welches (wenn dergleichen möglich wäre) in einer dieser Secten erzogen wäre, haben? Denn daß eine solche sich zeigen würde, ist wohl nicht zu zweifeln: weil oft wiederholte, vornehmlich widernatürliche Eindrücke aufs Gemüth sich in Geberdung und Ton der Sprache äußeren, und Mienen endlich stehende Gesichtszüge werden. Beate, oder wie sie Hr. Nicolai nennt, gebenedeiete Gesichter würden es von anderen gesitteten und aufgeweckten Völkern (eben nicht zu seinem Vortheil) unterscheiden; denn es ist Zeichnung der Frömmigkeit in Caricatur. Aber nicht die Verachtung der Frömmigkeit ist es, was den Namen der Pietisten zum Sectennamen gemacht hat (mit dem immer eine gewisse Verachtung verbunden ist), sondern die phantastische und bei allem Schein der Demuth stolze Anmaßung sich als übernatürlich-begünstigte Kinder des Himmels auszuzeichnen, wenn gleich ihr Wandel, so viel man sehen kann, vor dem der von ihnen so benannten Weltkinder in der Moralität nicht den mindesten Vorzug zeigt. *[6] Was den Staat in Religionsdingen allein interessiren darf, ist: wozu die Lehrer derselben anzuhalten sind, damit er nützliche Bürger, gute Soldaten und überhaupt getreue Unterthanen habe. Wenn er nun dazu die Einschärfung der Rechtgläubigkeit in statutarischen Glaubenslehren und eben solcher Gnadenmittel wählt, so kann er hiebei sehr übel fahren. Denn da das Annehmen dieser Statute eine leichte und dem schlechtdenkendsten Menschen weit leichtere Sache ist als dem Guten, dagegen die moralische Besserung der Gesinnung viel und lange Mühe macht, er aber von der ersteren hauptsächlich seine Seligkeit zu hoffen gelehrt worden ist, so darf er sich eben kein groß Bedenken machen, seine Pflicht (doch behutsam) zu übertreten, weil er ein unfehlbares Mittel bei der Hand hat, der göttlichen Strafgerechtigkeit (nur daß er sich nicht verspäten muß) durch seinen rechten Glauben an alle Geheimnisse und inständige Benutzung der Gnadenmittel zu entgehen; dagegen, wenn jene Lehre der Kirche geradezu auf die Moralität gerichtet sein würde, das Urtheil seines Gewissens ganz anders lauten würde: nämlich daß, so viel er von dem Bösen, was er that, nicht ersetzen kann, dafür müsse er einem künftigen Richter antworten, und dieses Schicksal abzuwenden, vermöge kein kirchliches Mittel, kein durch Angst herausgedrängter Glaube, noch ein solches Gebet (_desine fata deum flecti sperare precando_)_. – _Bei welchem Glauben ist nun der Staat sicherer?"}], "running_header": "Allgemeine Anmerkung. Von Religionssecten"}, {"page_id": "2524_0", "page_pdf": 2524, "page_book": 60, "page_kind": "body", "sigel": "AA VII, 60", "units": [{"type": "paragraph", "text": "Friedens-Abschluß und Beilegung des Streits der Facultäten."}], "running_header": "Friedens-Abschluß und Beilegung des Streits der Facultäten"}, {"page_id": "2524_1", "page_pdf": 2524, "page_book": 61, "page_kind": "body", "sigel": "AA VII, 61", "units": [{"type": "paragraph", "text": "In Streitigkeiten, welche blos die reine, aber praktische Vernunft angehen, hat die philosophische Facultät ohne Widerrede das Vorrecht, den Vortrag zu thun und, was das Formale betrifft, den Proceß zu instruiren; was aber das Materiale anlangt, so ist die theologische im Besitz den Lehnstuhl, der den Vorrang bezeichnet, einzunehmen, nicht weil sie etwa in Sachen der Vernunft auf mehr Einsicht Anspruch machen kann als die übrigen, sondern weil es die wichtigste menschliche Angelegenheit betrifft, und führt daher den Titel der obersten Facultät (doch nur als _prima inter pares_)_. – _Sie spricht aber nicht nach Gesetzen der reinen und _a priori _erkennbaren Vernunftreligion (denn da würde sie sich erniedrigen und auf die philosophische Bank herabsetzen), sondern nach statutarischen, in einem Buche, vorzugsweise Bibel genannt, enthaltenen Glaubensvorschriften, d.i. in einem Codex der Offenbarung eines vor viel hundert Jahren geschlossenen alten und neuen Bundes der Menschen mit Gott, dessen Authenticität als eines Geschichtsglaubens (nicht eben des moralischen; denn der würde auch aus der Philosophie gezogen werden können) doch mehr von der Wirkung, welche die Lesung der Bibel auf das Herz der Menschen thun mag, als von mit kritischer Prüfung der darin enthaltenen Lehren und Erzählungen aufgestellten Beweisen erwartet werden darf, dessen Auslegung auch nicht der natürlichen Vernunft der Laien, sondern nur der Scharfsinnigkeit der Schriftgelehrten überlassen wird.*[1]"}], "markers": [{"system": "AA", "band": "VII", "page": 61, "ref": "VII61"}], "running_header": "Friedens-Abschluß und Beilegung des Streits der Facultäten"}, {"page_id": "2524_2", "page_pdf": 2524, "page_book": 62, "page_kind": "body", "sigel": "AA VII, 62", "units": [{"type": "paragraph", "text": "Der biblische Glaube ist ein messianischer Geschichtsglaube, dem ein Buch des Bundes Gottes mit Abraham zum Grunde liegt, und besteht aus einem mosaisch-messianischen und einem evangelisch-messianischen Kirchenglauben, der den Ursprung und die Schicksale des Volks Gottes so vollständig erzählt, daß er, von dem, was in der Weltgeschichte überhaupt das oberste ist, und wobei kein Mensch zugegen war, nämlich dem Weltanfang (in der Genesis), anhebend, sie bis zum Ende aller Dinge (in der Apokalypsis) verfolgt, – welches freilich von keinem Andern, als einem göttlich-inspirirten Verfasser erwartet werden darf; – wobei sich doch eine bedenkliche Zahlen-Kabbala in Ansehung der wichtigsten Epochen der heiligen Chronologie darbietet, welche den Glauben an die Authenticität dieser biblischen Geschichtserzählung etwas schwächen dürfte.*[2]"}], "markers": [{"system": "AA", "band": "VII", "page": 62, "ref": "VII62"}], "running_header": "Friedens-Abschluß und Beilegung des Streits der Facultäten"}, {"page_id": "2524_3", "page_pdf": 2524, "page_book": 63, "page_kind": "body", "sigel": "AA VII, 63", "units": [{"type": "paragraph", "text": "Ein Gesetzbuch des nicht aus der menschlichen Vernunft gezogenen, aber doch mit ihr, als moralisch-praktischer Vernunft, dem Endzwecke nach vollkommen einstimmigen statutarischen (mithin aus einer Offenbarung hervorgehenden) göttlichen Willens, die Bibel, würde nun das kräftigste Organ der Leitung des Menschen und des Bürgers zum zeitlichen und ewigen Wohl sein, wenn sie nur als Gottes Wort beglaubigt und ihre Authenticität documentirt werden könnte. – Diesem Umstande aber stehen viele Schwierigkeiten entgegen. Denn wenn Gott zum Menschen wirklich spräche, so kann dieser doch niemals wissen, daß es Gott sei, der zu ihm spricht. Es ist schlechterdings unmöglich, daß der Mensch durch seine Sinne den Unendlichen fassen, ihn von Sinnenwesen unterscheiden und ihn woran kennen solle. – Daß es aber nicht Gott sein könne, dessen Stimme er zu hören glaubt, davon kann er sich wohl in einigen Fällen überzeugen; denn wenn das, was ihm durch sie geboten wird, dem moralischen Gesetz zuwider ist, so mag die Erscheinung ihm noch so majestätisch und die ganze Natur überschreitend dünken: er muß sie doch für Täuschung halten.*[3] Die Beglaubigung der Bibel nun, als eines in Lehre und Beispiel zur Norm dienenden evangelisch-messianischen Glaubens, kann nicht aus der Gottesgelahrtheit ihrer Verfasser (denn der war immer ein dem möglichen Irrthum ausgesetzter Mensch), sondern muß aus der Wirkung ihres Inhalts auf die Moralität des Volks von Lehrern aus diesem Volk selbst, als Idioten (im Wissenschaftlichen), an sich, mithin als aus dem reinen Quell der allgemeinen, jedem gemeinen Menschen beiwohnenden Vernunftreligion geschöpft betrachtet werden, die eben durch diese Einfalt auf die"}], "markers": [{"system": "AA", "band": "VII", "page": 63, "ref": "VII63"}], "running_header": "Friedens-Abschluß und Beilegung des Streits der Facultäten"}, {"page_id": "2524_4", "page_pdf": 2524, "page_book": 64, "page_kind": "body", "sigel": "AA VII, 64", "units": [{"type": "paragraph", "text": "Herzen desselben den ausgebreitetsten und kräftigsten Einfluß haben mußte. – Die Bibel war das"}], "markers": [{"system": "AA", "band": "VII", "page": 64, "ref": "VII64"}], "running_header": "Friedens-Abschluß und Beilegung des Streits der Facultäten"}, {"page_id": "2525_0", "page_pdf": 2525, "page_book": 64, "page_kind": "body", "sigel": "AA VII, 64", "units": [{"type": "paragraph", "text": "Vehikel derselben vermittelst gewisser statutarischer Vorschriften, welche der Ausübung der Religion in der bürgerlichen Gesellschaft eine Form als einer Regierung gab, und die Authenticität dieses Gesetzbuchs als eines göttlichen (des Inbegriffs aller unserer Pflichten als göttlicher Gebote) beglaubigt also und documentirt sich selbst, was den Geist desselben (das Moralische) betrifft; was aber den Buchstaben (das Statutarische) desselben anlangt, so bedürfen die Satzungen in diesem Buche keiner Beglaubigung, weil sie nicht zum Wesentlichen (_principale_), sondern nur zum Beigesellten (_accessorium_) desselben gehören. – – Den Ursprung aber dieses Buchs auf Inspiration seiner Verfasser (_deus ex machina_) zu gründen, um auch die unwesentliche Statute desselben zu heiligen, muß eher das Zutrauen zu seinem moralischen Werth schwächen, als es stärken. Die Beurkundung einer solchen Schrift, als einer göttlichen, kann von keiner Geschichtserzählung, sondern nur von der erprobten Kraft derselben, Religion in menschlichen Herzen zu gründen und, wenn sie durch mancherlei (alte oder neue) Satzungen verunartet wäre, sie durch ihre Einfalt selbst wieder in ihre Reinigkeit herzustellen, abgeleitet werden, welches Werk darum nicht aufhört, Wirkung der Natur und Erfolg der fortschreitenden moralischen Cultur in dem allgemeinen Gange der Vorsehung zu sein, und als eine solche erklärt zu werden bedarf, damit die Existenz dieses Buchs nicht ungläubisch dem bloßen Zufall, oder abergläubisch einem Wunder zugeschrieben werde, und die Vernunft in beiden Fällen auf den Strand gerathe. Der Schluß hieraus ist nun dieser: Die Bibel enthält in sich selbst einen in praktischer Absicht hinreichenden Beglaubigungsgrund ihrer (moralischen) Göttlichkeit durch den Einfluß, den sie als Text einer systematischen Glaubenslehre von jeher sowohl in katechetischem als homiletischem Vortrage auf das Herz der Menschen ausgeübt hat, um sie als Organ nicht allein der allgemeinen und inneren Vernunftreligion, sondern auch als Vermächtniß (neues Testament) einer statutarischen, auf unabsehliche Zeiten zum Leitfaden dienenden Glaubenslehre aufzubehalten: es mag ihr auch in theoretischer Rücksicht für Gelehrte, die ihren Ursprung theoretisch und historisch nachsuchen, und für die kritische Behandlung ihrer Geschichte an Beweisthümern viel oder wenig abgehen. – Die Göttlichkeit ihres moralischen Inhalts entschädigt"}], "running_header": "Friedens-Abschluß und Beilegung des Streits der Facultäten"}, {"page_id": "2525_1", "page_pdf": 2525, "page_book": 65, "page_kind": "body", "sigel": "AA VII, 65", "units": [{"type": "paragraph", "text": "die Vernunft hinreichend wegen der Menschlichkeit der Geschichtserzählung, die, gleich einem alten Pergamente hin und wieder unleserlich, durch Accommodationen und Conjecturen im Zusammenhange mit dem Ganzen muß verständlich gemacht werden, und berechtigt dabei doch zu dem Satz: daß die Bibel, gleich als ob sie eine göttliche Offenbarung wäre, aufbewahrt, moralisch benutzt und der Religion als ihr Leitmittel untergelegt zu werden verdiene. Die Keckheit der Kraftgenies, welche diesem Leitbande des Kirchenglaubens sich jetzt schon entwachsen zu sein wähnen, sie mögen nun als Theophilanthropen in öffentlichen dazu errichteten Kirchen, oder als Mystiker bei der Lampe innerer Offenbarungen schwärmen, würde die Regierung bald ihre Nachsicht bedauren machen, jenes große Stiftungs- und Leitungsmittel der bürgerlichen Ordnung und Ruhe vernachlässigt und leichtsinnigen Händen überlassen zu haben. – Auch ist nicht zu erwarten, daß, wenn die Bibel, die wir haben, außer Credit kommen sollte, eine andere an ihrer Stelle emporkommen würde; denn öffentliche Wunder machen sich nicht zum zweitenmale in derselben Sache: weil das Fehlschlagen des vorigen in Absicht auf die Dauer dem folgenden allen Glauben benimmt; – wiewohl doch auch andererseits auf das Geschrei der Alarmisten (das Reich ist in Gefahr) nicht zu achten ist, wenn in gewissen Statuten der Bibel, welche mehr die Förmlichkeiten als den inneren Glaubensgehalt der Schrift betreffen, selbst an den Verfassern derselben einiges gerügt werden sollte: weil das Verbot der Prüfung einer Lehre der Glaubensfreiheit zuwider ist. – Daß aber ein Geschichtsglaube Pflicht sei und zur Seligkeit gehöre, ist Aberglaube.*[4]"}], "markers": [{"system": "AA", "band": "VII", "page": 65, "ref": "VII65"}], "running_header": "Friedens-Abschluß und Beilegung des Streits der Facultäten"}, {"page_id": "2525_2", "page_pdf": 2525, "page_book": 66, "page_kind": "body", "sigel": "AA VII, 66", "units": [{"type": "paragraph", "text": "Von der biblischen Auslegungskunst (_hermeneutica sacra_), da sie nicht den Laien überlassen werden kann (denn sie betrifft ein wissenschaftliches System), darf nun lediglich in"}], "markers": [{"system": "AA", "band": "VII", "page": 66, "ref": "VII66"}], "running_header": "Friedens-Abschluß und Beilegung des Streits der Facultäten"}, {"page_id": "2526_0", "page_pdf": 2526, "page_book": 66, "page_kind": "body", "sigel": "AA VII, 66", "units": [{"type": "paragraph", "text": "Ansehung dessen, was in der Religion statutarisch ist, verlangt werden: daß der Ausleger sich erkläre, ob sein Ausspruch als authentisch, oder als doctrinal verstanden werden solle. – Im ersteren Falle muß die Auslegung dem Sinne des Verfassers buchstäblich (philologisch) angemessen sein; im zweiten aber hat der Schriftsteller die Freiheit, der Schriftstelle (philosophisch) denjenigen Sinn unterzulegen, den sie in moralisch-praktischer Absicht (zur Erbauung des Lehrlings) in der Exegese annimmt; denn der Glaube an einen bloßen Geschichtssatz ist todt an ihm selber. – Nun mag wohl die erstere für den Schriftgelehrten und indirect auch für das Volk in gewisser pragmatischen Absicht wichtig genug sein, aber der eigentliche Zweck der Religionslehre, moralisch bessere Menschen zu bilden, kann auch dabei nicht allein verfehlt, sondern wohl gar verhindert werden. – Denn die heilige Schriftsteller können als Menschen auch geirrt haben (wenn man nicht ein durch die Bibel beständig fortlaufendes Wunder annimmt), wie z.B. der h. Paul mit seiner Gnadenwahl, welche er aus der mosaisch- messianischen Schriftlehre in die evangelische treuherzig überträgt, ob er zwar über die Unbegreiflichkeit der Verwerfung gewisser Menschen, ehe sie noch geboren waren, sich in großer Verlegenheit befindet und so, wenn man die Hermeneutik der Schriftgelehrten als continuirlich dem"}], "running_header": "Friedens-Abschluß und Beilegung des Streits der Facultäten"}, {"page_id": "2526_1", "page_pdf": 2526, "page_book": 67, "page_kind": "body", "sigel": "AA VII, 67", "units": [{"type": "paragraph", "text": "Ausleger zu Theil gewordene Offenbarung annimmt, der Göttlichkeit der Religion beständig Abbruch thun muß. – Also ist nur die doctrinale Auslegung, welche nicht (empirisch) zu wissen verlangt, was der heilige Verfasser mit seinen Worten für einen Sinn verbunden haben mag, sondern was die Vernunft (_a_ _priori_) in moralischer Rücksicht bei Veranlassung einer Spruchstelle als Text der Bibel für eine Lehre unterlegen kann, die einzige evangelisch-biblische Methode der Belehrung des Volks in der wahren, inneren und allgemeinen Religion, die von dem particulären Kirchenglauben als Geschichtsglauben – unterschieden ist; wobei dann alles mit Ehrlichkeit und Offenheit, ohne Täuschung zugeht, da hingegen das Volk, mit einem Geschichtsglauben, den keiner desselben sich zu beweisen vermag, statt des moralischen (allein seligmachenden), den ein jeder faßt, in seiner Absicht (die es haben muß) getäuscht, seinen Lehrer anklagen kann. In Absicht auf die Religion eines Volks, das eine heilige Schrift zu verehren gelehrt worden ist, ist nun die doctrinale Auslegung derselben, welche sich auf sein (des Volks) moralisches Interesse – der Erbauung, sittlichen Besserung und so der Seligwerdung – bezieht, zugleich die authentische: d.i. so will Gott seinen in der Bibel geoffenbarten Willen verstanden wissen. Denn es ist hier nicht von einer bürgerlichen, das Volk unter Disciplin haltenden (politischen), sondern einer auf das Innere der moralischen Gesinnung abzweckenden (mithin göttlichen) Regierung die Rede. Der Gott, der durch unsere eigene (moralisch-praktische) Vernunft spricht, ist ein untrüglicher, allgemein verständlicher Ausleger dieses seines Worts, und es kann auch schlechterdings keinen anderen (etwa auf historische Art) beglaubigten Ausleger seines Worts geben: weil Religion eine reine Vernunftsache ist."}, {"type": "paragraph", "text": "* * *"}, {"type": "paragraph", "text": "Und so haben die Theologen der Facultät die Pflicht auf sich, mithin auch die Befugniß, den Bibelglauben aufrecht zu erhalten: doch unbeschadet der Freiheit der Philosophen, ihn jederzeit der Kritik der Vernunft zu unterwerfen, welche im Falle einer Dictatur (des Religionsedicts), die jener oberen etwa auf kurze Zeit eingeräumt werden dürfte, sich durch die solenne Formel bestens verwahren: _Provideant consules, ne quid respublica detrimenti capiat. _"}, {"type": "paragraph", "text": "Anmerkungen:"}], "markers": [{"system": "AA", "band": "VII", "page": 67, "ref": "VII67"}], "running_header": "Friedens-Abschluß und Beilegung des Streits der Facultäten"}, {"page_id": "2527", "page_pdf": 2527, "page_book": 63, "page_kind": "body", "sigel": "AA VII, 63", "units": [{"type": "paragraph", "text": "*[1] Im römisch-katholischen System des Kirchenglaubens ist diesen Punkt (das Bibellesen) betreffend mehr Consequenz als im protestantischen. – Der reformirte Prediger La Coste sagt zu seinen Glaubensgenossen: »Schöpft das göttliche Wort aus der Quelle (der Bibel) selbst, wo ihr es dann lauter und unverfälscht einnehmen könnt; aber ihr müßt ja nichts anders in der Bibel finden, als was wir darin finden. – Nun, lieben Freunde, sagt uns lieber, was ihr in der Bibel findet, damit wir nicht unnöthiger Weise darin selbst suchen und am Ende, was wir darin gefunden zu haben vermeinten, von euch für unrichtige Auslegung derselben erklärt werde.« – Auch spricht die katholische Kirche in dem Satze: »Außer der Kirche (der katholischen) ist kein Heil«, consequenter als die protestantische, wenn diese sagt: daß man auch als Katholik selig werden könne. Denn wenn das ist (sagt Bossuet), so wählt man ja am sichersten, sich zur ersteren zu schlagen. Denn noch seliger als selig kann doch kein Mensch zu werden verlangen. *[2] 70 apokalyptische Monate (deren es in diesem Cyklus 4 giebt), jeden zu 29½ Jahren, geben 2065 Jahr. Davon jedes 49ste Jahr, als das große Ruhejahr, (deren in diesem Zeitlaufe 42 sind) abgezogen: bleiben gerade 2023, als das Jahr, da Abraham aus dem Lande Kanaan, das ihm Gott geschenkt hatte, nach Ägypten ging. – Von da an bis zur Einnahme jenes Landes durch die Kinder Israel 70 apokalyptische Wochen (= 490 Jahr) – und so 4 mal solcher Jahrwochen zusammengezählt (= 1960) und mit 2023 addirt, geben nach P.Petau’s Rechnung das Jahr der Geburt Christi (= 3983) so genau, daß auch nicht ein Jahr daran fehlt. – Siebzig Jahr hernach die Zerstörung Jerusalems (auch eine mystische Epoche). – – Aber Bengel,_ in ordine temporum pag. _ 9._ it. p. _218_ seqq._, bringt 3939 als die Zahl der Geburt Christi heraus? Aber das ändert nichts an der Heiligkeit des Numerus septenarius. Denn die Zahl der Jahre vom Rufe Gottes an Abraham bis zur Geburt Christi ist 1960, welches 4 apokalyptische Perioden austrägt, jeden zu 490, oder auch 40 apok. Perioden, jeden zu 7 mal 7 = 49 Jahr. Zieht man nun von jedem neunundvierzigsten das große Ruhejahr und von jedem größten Ruhejahr, welches das 490ste ist, eines ab (zusammen 44), so bleibt gerade 3939. – Also sind die Jahreszahlen 3983 und 3939, als das verschieden angegebene Jahr der Geburt Christi, nur darin unterschieden: daß die letztere entspringt, wenn in der Zeit der ersteren das, was zur Zeit der 4 großen Epochen gehört, um die Zahl der Ruhejahre vermindert wird. Nach Bengeln würde die Tafel der heil. Geschichte so aussehen: 2023: Verheißung an Abraham, das Land Kanaan zu besitzen; 2502: Besitzerlangung desselben; 2981: Einweihung des ersten Tempels; 3460: Gegebener Befehl zur Erbauung des zweiten Tempels; 3939: Geburt Christi. Auch das Jahr der Sündfluth läßt sich so _a priori _ausrechnen. Nämlich 4 Epochen zu 490 (= 70 × 7) Jahr machen 1960. Davon jedes 7te (= 280) abgezogen, bleiben 1680. Von diesen 1680 jedes darin enthaltene 70ste Jahr abgezogen (= 24), bleiben 1656, als das Jahr der Sündfluth. – Auch von dieser bis zum R.G. an Abraham sind 366 volle Jahre, davon eins ein Schaltjahr ist. Was soll man nun hiezu sagen? Haben die heiligen Zahlen etwa den Weltlauf bestimmt? – Frank’s _Cyclus _ _iobilaeus _dreht sich ebenfalls um diesen Mittelpunkt der mystischen Chronologie herum. *[3] Zum Beispiel kann die Mythe von dem Opfer dienen, das Abraham auf göttlichen Befehl durch Abschlachtung und Verbrennung seines einzigen Sohnes – (das arme Kind trug unwissend noch das Holz hinzu) – bringen wollte. Abraham hätte auf diese vermeinte göttliche Stimme antworten müssen: »Daß ich meinen guten Sohn nicht tödten solle, ist ganz gewiß; daß aber du, der du mir erscheinst, Gott sei, davon bin ich nicht gewiß und kann es auch nicht werden«, wenn sie auch vom (sichtbaren) Himmel herabschallte."}], "markers": [{"system": "AA", "band": "VII", "page": 63, "ref": "VII63"}], "running_header": "Friedens-Abschluß und Beilegung des Streits der Facultäten"}, {"page_id": "2528", "page_pdf": 2528, "page_book": 66, "page_kind": "body", "sigel": "AA VII, 66", "units": [{"type": "paragraph", "text": "*[4] Aberglaube ist der Hang in das, was als nicht natürlicher Weise zugehend vermeint wird, ein größeres Vertrauen zu setzen, als was sich nach Naturgesetzen erklären läßt – es sei im Physischen oder Moralischen. – Man kann also die Frage aufwerfen: ob der Bibelglaube (als empirischer), oder ob umgekehrt die Moral (als reiner Vernunft- und Religionsglaube) dem Lehrer zum Leitfaden dienen solle; mit anderen Worten: ist die Lehre von Gott, weil sie in der Bibel steht, oder steht sie in der Bibel, weil sie von Gott ist? – Der erstere Satz ist augenscheinlich inconsequent: weil das göttliche Ansehen des Buchs hier vorausgesetzt werden muß, um die Göttlichkeit der Lehre desselben zu beweisen. Also kann nur der zweite Satz Statt finden, der aber schlechterdings keines Beweises fähig ist (_Supernaturalium non datur scientia_)_. – – _Hievon ein Beispiel. _– _Die Jünger des mosaisch-messianischen Glaubens sahen ihre Hoffnung aus dem Bunde Gottes mit Abraham nach Jesu Tode ganz sinken (wir hofften, er würde Israel erlösen); denn nur den Kindern Abrahams war in ihrer Bibel das Heil verheißen. Nun trug es sich zu, daß, da am Pfingstfeste die Jünger versammelt waren, einer derselben auf den glücklichen, der subtilen jüdischen Auslegungskunst angemessenen Einfall gerieth, daß auch die Heiden (Griechen und Römer) als in diesen Bund aufgenommen betrachtet werden könnten: wenn sie an das Opfer, welches Abraham Gotte mit seinem einzigen Sohne bringen wollte (als dem Sinnbilde des einigen Opfers des Weltheilandes) glaubten; denn da wären sie Kinder Abrahams im Glauben (zuerst unter, dann aber auch ohne die Beschneidung). – Es ist kein Wunder, daß diese Entdeckung, die in einer großen Volksversammlung eine so unermeßliche Aussicht eröffnete, mit dem größten Jubel, und als ob sie unmittelbare Wirkung des heil. Geistes gewesen wäre, aufgenommen und für ein Wunder gehalten wurde und als ein solches in die biblische (Apostel-) Geschichte kam, bei der es aber gar nicht zur Religion gehört, sie als Factum zu glauben und diesen Glauben der natürlichen Menschenvernunft aufzudringen. Der durch Furcht abgenöthigte Gehorsam in Ansehung eines solchen Kirchenglaubens, als zur Seligkeit erforderlich, ist also Aberglaube."}], "markers": [{"system": "AA", "band": "VII", "page": 66, "ref": "VII66"}], "running_header": "Friedens-Abschluß und Beilegung des Streits der Facultäten"}, {"page_id": "2529_0", "page_pdf": 2529, "page_book": 67, "page_kind": "body", "sigel": "AA VII, 67", "units": [{"type": "paragraph", "text": "Anhang biblisch-historischer Fragen über die praktische Benutzung und muthmaßliche Zeit der Fortdauer dieses heiligen Buchs."}], "running_header": "Anhang biblisch-historischer Fragen [...]"}, {"page_id": "2529_1", "page_pdf": 2529, "page_book": 68, "page_kind": "body", "sigel": "AA VII, 68", "units": [{"type": "paragraph", "text": "Daß es bei allem Wechsel der Meinungen noch lange Zeit im Ansehen bleiben werde, dafür bürgt die Weisheit der Regierung, als deren Interesse in Ansehung der Eintracht und Ruhe des Volks in einem Staat hiemit in enger Verbindung steht. Aber ihm die Ewigkeit zu verbürgen, oder auch es chiliastisch in ein neues Reich Gottes auf Erden übergehen zu lassen, das übersteigt unser ganzes Vermögen der Wahrsagung. – Was würde also geschehen, wenn der Kirchenglaube dieses große Mittel der Volksleitung einmal entbehren müßte? Wer ist der Redacteur der biblischen Bücher (alten und neuen Testaments), und zu welcher Zeit ist der Kanon zu Stande gekommen? Werden philologisch-antiquarische Kenntnisse immer zur Erhaltung der einmal angenommenen Glaubensnorm nöthig sein, oder wird die Vernunft den Gebrauch derselben zur Religion dereinst von selbst und mit allgemeiner Einstimmung anzuordnen im Stande sein? Hat man hinreichende Documente der Authenticität der Bibel nach den sogenannten 70 Dolmetschern, und von welcher Zeit kann man sie mit Sicherheit datiren? u.s.w. __________"}, {"type": "paragraph", "text": "Die praktische, vornehmlich öffentliche Benutzung dieses Buchs in Predigten ist ohne Zweifel diejenige, welche zur Besserung der Menschen und Belebung ihrer moralischen Triebfedern (zur Erbauung) beiträgt. Alle andere Absicht muß ihr nachstehen, wenn sie hiemit in Collision kommt. – Man muß sich daher wundern: daß diese Maxime noch hat bezweifelt werden können, und eine paraphrastische Behandlung eines Texts der paränetischen, wenn gleich nicht vorgezogen, doch durch die erstere wenigstens hat in Schatten gestellt werden sollen. – Nicht die Schriftgelahrtheit, und was man vermittelst ihrer aus der Bibel durch philologische Kenntnisse, die oft nur verunglückte Conjecturen sind, herauszieht, sondern was man mit moralischer Denkungsart (also nach dem Geiste Gottes) in sie hineinträgt, und Lehren, die nie trügen, auch nie ohne heilsame Wirkung sein können, das muß diesem Vortrage ans Volk die"}], "markers": [{"system": "AA", "band": "VII", "page": 68, "ref": "VII68"}], "running_header": "Anhang biblisch-historischer Fragen [...]"}, {"page_id": "2529_2", "page_pdf": 2529, "page_book": 69, "page_kind": "body", "sigel": "AA VII, 69", "units": [{"type": "paragraph", "text": "Leitung geben: nämlich den Text nur (wenigstens hauptsächlich) als Veranlassung zu allem Sittenbessernden, was sich dabei denken läßt, zu behandeln, ohne was die heil. Schriftsteller dabei selbst im Sinne gehabt haben möchten, nachforschen zu dürfen. – Eine auf Erbauung als Endzweck gerichtete Predigt (wie denn das eine jede sein soll) muß die Belehrung aus den Herzen der Zuhörer, nämlich der natürlichen moralischen Anlage, selbst des unbelehrtesten Menschen, entwickeln, wenn die dadurch zu bewirkende Gesinnung lauter sein soll. Die damit verbundene Zeugnisse der Schrift sollen auch nicht die Wahrheit dieser Lehren bestätigende historische Beweisgründe sein (denn deren bedarf die sittlich-thätige Vernunft hiebei nicht: und das empirische Erkenntniß vermag es auch nicht), sondern blos Beispiele der Anwendung der praktischen Vernunftprincipien auf Facta der h. Geschichte, um ihre Wahrheit anschaulicher zu machen; welches aber auch ein sehr schätzbarer Vortheil für Volk und Staat auf der ganzen Erde ist."}], "markers": [{"system": "AA", "band": "VII", "page": 69, "ref": "VII69"}], "running_header": "Anhang biblisch-historischer Fragen [...]"}, {"page_id": "2530_0", "page_pdf": 2530, "page_book": 69, "page_kind": "body", "sigel": "AA VII, 69", "units": [{"type": "paragraph", "text": "Anhang Von einer reinen Mystik in der Religion. *"}], "running_header": "Anhang. Von einer reinen Mystik in der Religion"}, {"page_id": "2530_1", "page_pdf": 2530, "page_book": 69, "page_kind": "body", "sigel": "AA VII, 69", "units": [{"type": "paragraph", "text": "Ich habe aus der Kritik der reinen Vernunft gelernt, daß Philosophie nicht etwa eine Wissenschaft der Vorstellungen, Begriffe und Ideen, oder eine Wissenschaft aller Wissenschaften, oder sonst etwas Ähnliches sei; sondern eine Wissenschaft des Menschen, seines Vorstellens, Denkens und Handelns; – sie soll den Menschen nach allen seinen Bestandtheilen darstellen, wie er ist und sein soll, d.h. sowohl nach seinen Naturbestimmungen, als auch nach seinem Moralitäts- und Freiheitsverhältniß. Hier wies nun die alte Philosophie dem Menschen einen ganz unrichtigen Standpunkt in der Welt an, indem sie ihn in dieser zu einer Maschine machte, die als solche gänzlich von der Welt oder von den Außendingen und Umständen abhängig sein mußte; sie machte also den Menschen zu einem beinahe"}], "markers": [{"system": "AA", "band": "VII", "page": 69, "ref": "VII69"}], "running_header": "Anhang. Von einer reinen Mystik in der Religion"}, {"page_id": "2530_2", "page_pdf": 2530, "page_book": 70, "page_kind": "body", "sigel": "AA VII, 70", "units": [{"type": "paragraph", "text": "bloß passiven Theile der Welt. – Jetzt erschien die Kritik der Vernunft und bestimmte dem Menschen in der Welt eine durchaus active Existenz. Der Mensch selbst ist ursprünglich Schöpfer aller seiner Vorstellungen und Begriffe und soll einziger Urheber aller seiner Handlungen sein. Jenes »ist« und dieses »soll« führt auf zwei ganz verschiedene Bestimmungen am Menschen. Wir bemerken daher auch im Menschen zweierlei ganz verschiedenartige Theile, nämlich auf der einen Seite Sinnlichkeit und Verstand und auf der andern Vernunft und freien Willen, die sich sehr wesentlich von einander unterscheiden. In der Natur ist alles; es ist von keinem Soll in ihr die Rede; Sinnlichkeit und Verstand gehen aber nur immer darauf aus, zu bestimmen, was und wie es ist; sie müssen also für die Natur, für diese Erdenwelt, bestimmt sein und mithin zu ihr gehören. Die Vernunft will beständig ins Übersinnliche, wie es wohl über die sinnliche Natur hinaus beschaffen sein möchte: sie scheint also, obzwar ein theoretisches Vermögen, dennoch gar nicht für diese Sinnlichkeit bestimmt zu sein; der freie Wille aber besteht ja in einer Unabhängigkeit von den Außendingen; diese sollen nicht Triebfedern des Handlens für den Menschen sein; er kann also noch weniger zur Natur gehören. Aber wohin denn? Der Mensch muß für zwei ganz verschiedene Welten bestimmt sein, einmal für das Reich der Sinne und des Verstandes, also für diese Erdenwelt: dann aber auch noch für eine andere Welt, die wir nicht kennen, für ein Reich der Sitten. Was den Verstand betrifft, so ist dieser schon für sich durch seine Form auf diese Erdenwelt eingeschränkt; denn er besteht bloß aus Kategorien, d.h. Äußerungsarten, die bloß auf sinnliche Dinge sich beziehen können. Seine Gränzen sind ihm also scharf gesteckt. Wo die Kategorien aufhören, da hört auch der Verstand auf: weil sie ihn erst bilden und zusammensetzen. [Ein Beweis für die bloß irdische oder Naturbestimmung des Verstandes scheint mir auch dieses zu sein, daß wir in Rücksicht der Verstandeskräfte eine Stufenleiter in der Natur finden, vom klügsten Menschen bis zum dümmsten Thiere (indem wir doch den Instinct auch als eine Art von Verstand ansehen können, in sofern zum bloßen Verstande der freie Wille nicht gehört).] Aber nicht so in Rücksicht der Moralität, die da aufhört, wo die Menschheit aufhört, und die in allen Menschen ursprünglich dasselbe Ding ist. Der Verstand muß also bloß zur Natur gehören, und wenn der Mensch bloß Verstand hätte ohne Vernunft und freien Willen, oder ohne Moralität, so würde er sich in nichts von den Thieren unterscheiden und"}], "markers": [{"system": "AA", "band": "VII", "page": 70, "ref": "VII70"}], "running_header": "Anhang. Von einer reinen Mystik in der Religion"}, {"page_id": "2530_3", "page_pdf": 2530, "page_book": 71, "page_kind": "body", "sigel": "AA VII, 71", "units": [{"type": "paragraph", "text": "vielleicht bloß an der Spitze ihrer Stufenleiter stehen, da er hingegen jetzt, im Besitz der Moralität, als freies Wesen, durchaus und wesentlich von den Thieren verschieden ist, auch von dem klügsten (dessen Instinct oft deutlicher und bestimmter wirkt, als der Verstand der Menschen). – Dieser Verstand aber ist ein gänzlich actives Vermögen des Menschen; alle seine Vorstellungen und Begriffe sind bloß seine Geschöpfe, der Mensch denkt mit seinem Verstande ursprünglich, und er schafft sich also seine Welt. Die Außendinge sind nur Gelegenheitsursachen der Wirkung des Verstandes, sie reizen ihn zur Action, und das Product dieser Action sind Vorstellungen und Begriffe. Die Dinge also, worauf sich diese Vorstellungen und Begriffe beziehen, können nicht das sein, was unser Verstand vorstellt; denn der Verstand kann nur"}], "markers": [{"system": "AA", "band": "VII", "page": 71, "ref": "VII71"}], "running_header": "Anhang. Von einer reinen Mystik in der Religion"}, {"page_id": "2531_0", "page_pdf": 2531, "page_book": 71, "page_kind": "body", "sigel": "AA VII, 71", "units": [{"type": "paragraph", "text": "Vorstellungen und seine Gegenstände, nicht aber wirkliche Dinge schaffen, d.h. die Dinge können unmöglich durch diese Vorstellungen und Begriffe vom Verstande als solche, wie sie an sich sein mögen, erkannt werden; die Dinge, die unsere Sinne und unser Verstand darstellen, sind vielmehr an sich nur Erscheinungen, d.i. Gegenstände unserer Sinne und unseres Verstandes, die das Product aus dem Zusammentreffen der Gelegenheitsursachen und der Wirkung des Verstandes sind, die aber deswegen doch nicht Schein sind, sondern die wir im praktischen Leben für uns als wirkliche Dinge und Gegenstände unserer Vorstellungen ansehen können; eben weil wir die wirklichen Dinge als jene Gelegenheitsursachen supponiren müssen. Ein Beispiel giebt die Naturwissenschaft. Außendinge wirken auf einen actionsfähigen Körper und reizen diesen dadurch zur Action; das Product hievon ist Leben. – Was ist aber Leben? Physisches Anerkennen seiner Existenz in der Welt und seines Verhältnisses zu den Außendingen; der Körper lebt dadurch, daß er auf die Außendinge reagirt, sie als seine Welt ansieht und sie zu seinem Zweck gebraucht, ohne sich weiter um ihr Wesen zu bekümmern. Ohne Außendinge wäre dieser Körper kein lebender Körper, und ohne Actionsfähigkeit des Körpers wären die Außendinge nicht seine Welt. Eben so mit dem Verstande. Erst durch sein Zusammentreffen mit den Außendingen entsteht diese seine Welt; ohne Außendinge wäre er todt, – ohne Verstand aber wären keine Vorstellungen, ohne Vorstellungen keine Gegenstände und ohne diese nicht diese seine Welt; so wie mit einem anderen Verstande auch eine andere Welt da sein würde, welches durch das Beispiel von Wahnsinnigen klar wird. Also der Verstand ist Schöpfer seiner Gegenstände und der Welt, die aus ihnen besteht; aber so, daß wirkliche"}], "running_header": "Anhang. Von einer reinen Mystik in der Religion"}, {"page_id": "2531_1", "page_pdf": 2531, "page_book": 72, "page_kind": "body", "sigel": "AA VII, 72", "units": [{"type": "paragraph", "text": "Dinge die Gelegenheitsursachen seiner Action und also der Vorstellungen sind. Dadurch unterscheiden sich nun diese Naturkräfte des Menschen wesentlich von der Vernunft und dem freien Willen. Beide machen zwar auch active Vermögen aus, aber die Gelegenheitsursachen ihrer Action sollen nicht aus dieser Sinnenwelt genommen sein. Die Vernunft als theoretisches Vermögen kann also hier gar keine Gegenstände haben, ihre Wirkungen können nur Ideen sein, d.h. Vorstellungen der Vernunft, denen keine Gegenstände entsprechen, weil nicht wirkliche Dinge, sondern etwa nur Spiele des Verstandes die Gelegenheitsursachen ihrer Action sind. Also kann die Vernunft als theoretisches, speculatives Vermögen hier in dieser Sinnenwelt gar nicht gebraucht werden (und muß folglich, weil sie doch einmal als solches da ist, für eine andere Welt bestimmt sein), sondern nur als praktisches Vermögen zum Behuf des freien Willens. Dieser nun ist bloß und allein praktisch; das Wesentliche desselben besteht darin, daß seine Action nicht Reaction, sondern eine reine objective Handlung sein soll, oder daß die Triebfedern seiner Action nicht mit den Gegenständen derselben zusammenfallen sollen; daß er also unabhängig von den Vorstellungen des Verstandes, weil dieses eine verkehrte und verderbte Wirkungsart derselben veranlassen würde, als auch unabhängig von den Ideen der speculativen Vernunft handeln soll, weil diese, da ihnen nichts Wirkliches entspricht, leicht eine falsche und grundlose Willensbestimmung verursachen könnten. Also muß die Triebfeder der Action des freien Willens etwas sein, was im innern Wesen des Menschen selbst gegründet und von der Freiheit des Willens selbst unzertrennlich ist. Dieses ist nun das moralische Gesetz, welches uns durchaus so aus der Natur herausreißt und über sie erhebt, daß wir als moralische Wesen die Naturdinge weder zu Ursachen und Triebfedern der Action des Willens bedürfen, noch sie als Gegenstände unseres Wollens ansehen können, in deren Stelle vielmehr nur die moralische Person der Menschheit tritt. Jenes Gesetz sichert uns also eine bloß dem Menschen eigenthümliche und ihn von allen übrigen Naturtheilen unterscheidende Eigenschaft, die Moralität, vermöge welcher wir unabhängige und freie Wesen sind, und die selbst wieder durch diese Freiheit begründet ist. – Diese Moralität und nicht der Verstand ist es also, was den Menschen erst zum Menschen macht. So sehr auch der Verstand ein völlig actives und in sofern selbstständiges Vermögen ist, so bedarf er doch zu seiner Action der Außendinge und ist auch zugleich auf sie"}], "markers": [{"system": "AA", "band": "VII", "page": 72, "ref": "VII72"}], "running_header": "Anhang. Von einer reinen Mystik in der Religion"}, {"page_id": "2531_2", "page_pdf": 2531, "page_book": 73, "page_kind": "body", "sigel": "AA VII, 73", "units": [{"type": "paragraph", "text": "eingeschränkt; da hingegen der freie Wille völlig unabhängig ist und einzig durch das innere"}], "markers": [{"system": "AA", "band": "VII", "page": 73, "ref": "VII73"}], "running_header": "Anhang. Von einer reinen Mystik in der Religion"}, {"page_id": "2532_0", "page_pdf": 2532, "page_book": 73, "page_kind": "body", "sigel": "AA VII, 73", "units": [{"type": "paragraph", "text": "Gesetz bestimmt werden soll: d.h. der Mensch bloß durch sich selbst, sofern er sich nur zu seiner ursprünglichen Würde und Unabhängigkeit von allem, was nicht das Gesetz ist, erhoben hat. Wenn also dieser unser Verstand ohne diese seine Außendinge nichts, wenigstens nicht dieser Verstand sein würde, so bleiben Vernunft und freier Wille dieselben, ihr Wirkungskreis sei, welcher er wolle. (Sollte hier der freilich hyperphysische Schluß wohl mit einiger Wahrscheinlichkeit gemacht werden können: »daß mit dem Tode des Menschenkörpers auch dieser sein Verstand stirbt und verloren geht mit allen seinen irdischen Vorstellungen, Begriffen und Kenntnissen: weil doch dieser Verstand immer nur für irdische, sinnliche Dinge brauchbar ist, und, sobald der Mensch ins Übersinnliche sich versteigen will, hier sogleich aller Verstandesgebrauch aufhört, und der Vernunftgebrauch dagegen eintritt«? Es ist dieses eine Idee, die ich nachher auch bei den Mystikern, aber nur dunkel gedacht, nicht behauptet gefunden habe, und die gewiß zur Beruhigung und vielleicht auch moralischen Verbesserung vieler Menschen beitragen würde. Der Verstand hängt so wenig wie der Körper vom Menschen selbst ab. Bei einem fehlerhaften Körperbau beruhigt man sich, weil man weiß, er ist nichts Wesentliches – ein gutgebaueter Körper hat nur hier auf der Erde seine Vorzüge. Gesetzt, die Idee würde allgemein, daß es mit dem Verstande eben so wäre, sollte das nicht für die Moralität der Menschen ersprießlich sein? Die neuere Naturlehre des Menschen harmonirt sehr mit dieser Idee, indem sie den Verstand bloß als etwas vom Körper Abhängiges und als ein Product der Gehirnwirkung ansieht. S. Reils physiologische Schriften. Auch die ältern Meinungen von der Materialität der Seele ließen sich hierdurch auf etwas Reales zurückbringen.) – Der fernere Verlauf der kritischen Untersuchung der menschlichen Seelenvermögen stellte die natürliche Frage auf: hat die unvermeidliche und nicht zu unterdrückende Idee der Vernunft von einem Urheber des Weltalls und also unserer selbst und des moralischen Gesetzes auch wohl einen gültigen Grund, da jeder theoretische Grund seiner Natur nach untauglich zur Befestigung und Sicherstellung jener Idee ist? Hieraus entstand der so schöne moralische Beweis für das Dasein Gottes, der jedem, auch wenn er nicht wollte, doch insgeheim auch deutlich und hinlänglich beweisend sein muß. Aus der durch ihn nun begründeten Idee von einem Weltschöpfer aber ging endlich die praktische Idee hervor von einem allgemeinen"}], "running_header": "Anhang. Von einer reinen Mystik in der Religion"}, {"page_id": "2532_1", "page_pdf": 2532, "page_book": 74, "page_kind": "body", "sigel": "AA VII, 74", "units": [{"type": "paragraph", "text": "moralischen Gesetzgeber für alle unsere Pflichten, als Urheber des uns inwohnenden moralischen Gesetzes. Diese Idee bietet dem Menschen eine ganz neue Welt dar. Er fühlt sich für ein anderes Reich geschaffen, als für das Reich der Sinne und des Verstandes, – nämlich für ein moralisches Reich, für ein Reich Gottes. Er erkennt nun seine Pflichten zugleich als göttliche Gebote, und es entsteht in ihm ein neues Erkenntniß, ein neues Gefühl, nämlich Religion. – So weit, ehrwürdiger Vater, war ich in dem Studio Ihrer Schriften gekommen, als ich eine Classe von Menschen kennen lernte, die man Separatisten nennt, die aber sich selbst Mystiker nennen, bei welchen ich fast buchstäblich Ihre Lehre in Ausübung gebracht fand. Es hielt freilich anfangs schwer, diese in der mystischen Sprache dieser Leute wieder zu finden; aber es gelang mir nach anhaltendem Suchen. Es fiel mir auf, daß diese Menschen ganz ohne Gottesdienst lebten; alles verwarfen, was Gottesdienst heißt und nicht in Erfüllung seiner Pflichten besteht; daß sie sich für religiöse Menschen, ja für Christen hielten und doch die Bibel nicht als ihr Gesetzbuch ansahen, sondern nur von einem inneren, von Ewigkeit her in uns einwohnenden Christenthum sprachen. – Ich forschte nach dem Lebenswandel dieser Leute und fand (räudige Schafe ausgenommen, die man in jeder Heerde ihres Eigennutzes wegen findet) bei ihnen reine moralische Gesinnungen und eine beinahe stoische Consequenz in ihren Handlungen. Ich untersuchte ihre Lehre und ihre Grundsätze und fand im Wesentlichen ganz Ihre Moral und Religionslehre wieder, jedoch immer mit dem Unterschiede, daß sie das innere Gesetz, wie sie es nennen, für eine innere Offenbarung und also bestimmt Gott für den Urheber desselben halten. Es ist wahr, sie halten die Bibel für ein Buch, welches auf irgend eine Art, worauf sie sich nicht weiter einlassen, göttlichen Ursprungs ist; aber wenn man genauer forscht, so findet man, daß sie diesen Ursprung der Bibel erst aus der Übereinstimmung der Bibel, der in ihr enthaltenen Lehren, mit ihrem inneren Gesetze schließen:"}], "markers": [{"system": "AA", "band": "VII", "page": 74, "ref": "VII74"}], "running_header": "Anhang. Von einer reinen Mystik in der Religion"}, {"page_id": "2533_0", "page_pdf": 2533, "page_book": 74, "page_kind": "body", "sigel": "AA VII, 74", "units": [{"type": "paragraph", "text": "denn wenn man sie z.B. fragt: warum? so ist ihre Antwort: sie legitimirt sich in meinem Inneren, und ihr werdet es eben so finden, wenn ihr der Weisung eures inneren Gesetzes oder den Lehren der Bibel Folge leistet. Eben deswegen halten sie sie auch nicht für ihr Gesetzbuch, sondern nur für eine historische Bestätigung, worin sie das, was in ihnen selbst ursprünglich gegründet ist, wiederfinden. Mit einem Worte, diese Leute würden (verzeihen Sie mir den Ausdruck!) wahre Kantianer sein, wenn sie Philosophen wären. Aber"}], "running_header": "Anhang. Von einer reinen Mystik in der Religion"}, {"page_id": "2533_1", "page_pdf": 2533, "page_book": 75, "page_kind": "body", "sigel": "AA VII, 75", "units": [{"type": "paragraph", "text": "sie sind größtentheils aus der Classe der Kaufleute, Handwerker und Landbauern; doch habe ich hin und wieder auch in höheren Ständen und unter den Gelehrten einige gefunden; aber nie einen Theologen, denen diese Leute ein wahrer Dorn im Auge sind, weil sie ihren Gottesdienst nicht von ihnen unterstützt sehen und ihnen doch wegen ihres exemplarischen Lebenswandels und Unterwerfung in jede bürgerliche Ordnung durchaus nichts anhaben können. Von den Quäkern unterscheiden sich diese Separatisten nicht in ihren Religionsgrundsätzen, aber wohl in der Anwendung derselben aufs gemeine Leben. Denn sie kleiden sich z.B., wie es gerade Sitte ist, und bezahlen alle sowohl Staats- als kirchliche Abgaben. Bei dem gebildeten Theile derselben habe ich nie Schwärmerei gefunden, sondern freies, vorurtheilloses Räsonnement und Urtheil über religiöse Gegenstände."}, {"type": "paragraph", "text": "Anmerkungen: * In einem seiner Dissertation:_ De similitudine inter Mysticismum purum et Kantianam religionis doctrinam. _ _Auctore Carol. Arnold. Wilmans , Bielefelda-Guestphalo, Halis Saxonum _1797. beigefügten Briefe, welchen ich mit seiner Erlaubniß und mit Weglassung der Einleitungs- und Schlußhöflichkeitsstellen hiemit liefere, und welcher diesen jetzt der Arzneiwissenschaft sich widmenden jungen Mann als einen solchen bezeichnet, von dem sich auch in anderen Fächern der Wissenschaft viel erwarten läßt. Wobei ich gleichwohl jene Ähnlichkeit meiner Vorstellungsart mit der seinigen unbedingt einzugestehen nicht gemeint bin."}], "markers": [{"system": "AA", "band": "VII", "page": 75, "ref": "VII75"}], "running_header": "Anhang. Von einer reinen Mystik in der Religion"}, {"page_id": "2534_0", "page_pdf": 2534, "page_book": 76, "page_kind": "title_page", "sigel": "AA VII, 76", "units": [{"type": "paragraph", "text": "Zweiter Abschnitt. Der Streit der philosophischen Facultät mit der juristischen."}]}, {"page_id": "2534_1", "page_pdf": 2534, "page_book": 77, "page_kind": "title_page", "sigel": "AA VII, 77", "units": [], "markers": [{"system": "AA", "band": "VII", "page": 77, "ref": "VII77"}]}, {"page_id": "2534_2", "page_pdf": 2534, "page_book": 79, "page_kind": "title_page", "sigel": "AA VII, 79", "units": [{"type": "paragraph", "text": "Erneuerte Frage: Ob das menschliche Geschlecht im beständigen Fortschreiten zum Besseren sei."}], "markers": [{"system": "AA", "band": "VII", "page": 79, "ref": "VII79"}]}, {"page_id": "2535_0", "page_pdf": 2535, "page_book": 79, "page_kind": "body", "sigel": "AA VII, 79", "units": [{"type": "paragraph", "text": "1. Was will man hier wissen?"}], "running_header": "1. Was will man hier wissen?"}, {"page_id": "2535_1", "page_pdf": 2535, "page_book": 79, "page_kind": "body", "sigel": "AA VII, 79", "units": [{"type": "paragraph", "text": "Man verlangt ein Stück von der Menschengeschichte und zwar nicht das von der vergangenen, sondern der künftigen Zeit, mithin eine vorhersagende, welche, wenn sie nicht nach bekannten Naturgesetzen (wie Sonnen- und Mondfinsternisse) geführt wird, wahrsagend und doch natürlich, kann sie aber nicht anders, als durch übernatürliche Mittheilung und Erweiterung der Aussicht in die künftige Zeit erworben werden, weissagend (prophetisch) genannt wird.* – Übrigens ist es hier auch nicht um die Naturgeschichte des Menschen (ob etwa künftig neue Racen derselben entstehen möchten), sondern um die Sittengeschichte und zwar nicht nach dem Gattungsbegriff (_singulorum_), sondern dem Ganzen der gesellschaftlich auf Erden vereinigten, in Völkerschaften vertheilten Menschen (_universorum_) zu thun, wenn gefragt wird: ob das menschliche Geschlecht (im Großen) zum Besseren beständig fortschreite."}, {"type": "paragraph", "text": "Anmerkungen: * Wer ins Wahrsagen pfuschert (es ohne Kenntniß oder Ehrlichkeit thut), von dem heißt es: er wahrsagert, von der Pythia an bis zur Zigeunerin."}], "markers": [{"system": "AA", "band": "VII", "page": 79, "ref": "VII79"}], "running_header": "1. Was will man hier wissen?"}, {"page_id": "2536_0", "page_pdf": 2536, "page_book": 79, "page_kind": "body", "sigel": "AA VII, 79", "units": [{"type": "paragraph", "text": "2. Wie kann man es wissen?"}], "running_header": "2. Wie kann man es wissen?"}, {"page_id": "2536_1", "page_pdf": 2536, "page_book": 79, "page_kind": "body", "sigel": "AA VII, 79", "units": [{"type": "paragraph", "text": "Als wahrsagende Geschichtserzählung des Bevorstehenden in der künftigen Zeit: mithin als eine _a priori _mögliche Darstellung der Begebenheiten, die da kommen sollen. – Wie ist aber eine Geschichte _a priori_"}], "markers": [{"system": "AA", "band": "VII", "page": 79, "ref": "VII79"}], "running_header": "2. Wie kann man es wissen?"}, {"page_id": "2536_2", "page_pdf": 2536, "page_book": 80, "page_kind": "body", "sigel": "AA VII, 80", "units": [{"type": "paragraph", "text": "möglich? – Antwort: wenn der Wahrsager die Begebenheiten selber macht und veranstaltet, die er zum Voraus verkündigt. Jüdische Propheten hatten gut weissagen, daß über kurz oder lang nicht bloß Verfall, sondern gänzliche Auflösung ihrem Staat bevorstehe; denn sie waren selbst die Urheber dieses ihres Schicksals. – Sie hatten als Volksleiter ihre Verfassung mit so viel kirchlichen und daraus abfließenden bürgerlichen Lasten beschwert, daß ihr Staat völlig untauglich wurde, für sich selbst, vornehmlich mit benachbarten Völkern zusammen zu bestehen, und die Jeremiaden ihrer Priester mußten daher natürlicher Weise vergeblich in der Luft verhallen: weil diese hartnäckicht auf ihrem Vorsatz einer unhaltbaren, von ihnen selbst gemachten Verfassung beharrten, und so von ihnen selbst der Ausgang mit Unfehlbarkeit vorausgesehen werden konnte. Unsere Politiker machen, so weit ihr Einfluß reicht, es eben so und sind auch im Wahrsagen eben so glücklich. – Man muß, sagen sie, die Menschen nehmen, wie sie sind, nicht wie der Welt unkundige Pedanten oder gutmüthige Phantasten träumen, daß sie sein sollten. Das wie sie sind aber sollte heißen: wozu wir sie durch ungerechten Zwang, durch verrätherische, der Regierung an die Hand gegebene Anschläge gemacht haben, nämlich halsstarrig und zur Empörung geneigt; wo dann freilich, wenn sie ihre Zügel ein wenig sinken läßt, sich traurige Folgen eräugnen, welche die Prophezeiung jener vermeintlich-klugen Staatsmänner wahrmachen. Auch Geistliche weissagen gelegentlich den gänzlichen Verfall der Religion und die nahe Erscheinung des Antichrists, während dessen sie gerade das thun, was erforderlich ist, ihn einzuführen: indem sie nämlich ihrer Gemeine nicht sittliche Grundsätze ans Herz zu legen bedacht sind, die geradezu aufs Bessern führen, sondern Observanzen und historischen Glauben zur wesentlichen Pflicht machen, die es indirect bewirken sollen, woraus zwar mechanische Einhelligkeit als in einer bürgerlichen Verfassung, aber keine in der moralischen Gesinnung erwachsen kann; alsdann aber über Irreligiosität klagen, welche sie selber gemacht haben, die sie also auch ohne besondere Wahrsagergabe vorherverkündigen konnten."}], "markers": [{"system": "AA", "band": "VII", "page": 80, "ref": "VII80"}], "running_header": "2. Wie kann man es wissen?"}, {"page_id": "2537_0", "page_pdf": 2537, "page_book": 80, "page_kind": "body", "sigel": "AA VII, 80", "units": [{"type": "paragraph", "text": "3. Eintheilung des Begriffs von dem, was man für die Zukunft vorherwissen will."}], "running_header": "3. Eintheilung des Begriffs von dem, was man für die Zukunft vorherwissen will"}, {"page_id": "2537_1", "page_pdf": 2537, "page_book": 81, "page_kind": "body", "sigel": "AA VII, 81", "units": [{"type": "paragraph", "text": "Der Fälle, die eine Vorhersagung enthalten können, sind drei. Das menschliche Geschlecht ist entweder im continuirlichen Rückgange zum Argeren, oder im beständigen Fortgange zum Besseren in seiner moralischen Bestimmung, oder im ewigen Stillstande auf der jetzigen Stufe seines sittlichen Werths unter den Gliedern der Schöpfung (mit welchem die ewige Umdrehung im Kreise um denselben Punkt einerlei ist). Die erste Behauptung kann man den moralischen Terrorismus, die zweite den Eudämonismus (der, das Ziel des Fortschreitens im weiten Prospect gesehen, auch Chiliasmus genannt werden würde), die dritte aber den Abderitismus nennen: weil, da ein wahrer Stillstand im Moralischen nicht möglich ist, ein beständig wechselndes Steigen und eben so öfteres und tiefes Zurückfallen (gleichsam ein ewiges Schwanken) nichts mehr austrägt, als ob das Subject auf derselben Stelle und im Stillstande geblieben wäre."}, {"type": "paragraph", "text": "_a_. Von der terroristischen Vorstellungsart der Menschengeschichte. Der Verfall ins Ärgere kann im menschlichen Geschlechte nicht beständig fortwährend sein; denn bei einem gewissen Grade desselben würde es sich selbst aufreiben. Daher beim Anwachs großer, wie Berge sich aufthürmenden Greuelthaten und ihnen angemessenen Übel gesagt wird: nun kann es nicht mehr ärger werden; der jüngste Tag ist vor der Thür, und der fromme Schwärmer träumt nun schon von der Wiederbringung aller Dinge und einer erneuerten Welt, nachdem diese im Feuer untergegangen ist."}, {"type": "paragraph", "text": "_b_. Von der eudämonistischen Vorstellungsart der Menschengeschichte. Daß die Masse des unserer Natur angearteten Guten und Bösen in der Anlage immer dieselbe bleibe und in demselben Individuum weder"}], "markers": [{"system": "AA", "band": "VII", "page": 81, "ref": "VII81"}], "running_header": "3. Eintheilung des Begriffs von dem, was man für die Zukunft vorherwissen will"}, {"page_id": "2537_2", "page_pdf": 2537, "page_book": 82, "page_kind": "body", "sigel": "AA VII, 82", "units": [{"type": "paragraph", "text": "vermehrt noch vermindert werden könne, mag immer eingeräumt werden; – und wie sollte sich auch dieses Quantum des Guten in der Anlage vermehren lassen, da es durch die Freiheit des Subjects geschehen müßte, wozu dieses aber wiederum eines größeren Fonds des Guten bedürfen würde, als es einmal hat? – Die Wirkungen können das Vermögen der wirkenden Ursache nicht übersteigen; und so kann das Quantum des mit dem Bösen im Menschen vermischten Guten ein gewisses Maß des letzteren nicht überschreiten, über welches er sich emporarbeiten und so auch immer zum noch Besseren fortschreiten könnte. Der Eudämonism mit seinen sanguinischen Hoffnungen scheint also unhaltbar zu sein und zu Gunsten einer weissagenden Menschengeschichte in Ansehung des immerwährenden weitern Fortschreitens auf der Bahn des Guten wenig zu versprechen."}, {"type": "paragraph", "text": "_c_. Von der Hypothese des Abderitisms des Menschengeschlechts zur Vorherbestimmung seiner Geschichte. Diese Meinung möchte wohl die Mehrheit der Stimmen auf ihrer Seite haben. Geschäftige Thorheit ist der Charakter unserer Gattung: in die Bahn des Guten schnell einzutreten, aber darauf nicht zu beharren, sondern, um ja nicht an einen einzigen Zweck gebunden zu sein, wenn es auch nur der Abwechselung wegen geschähe, den Plan des Fortschritts umzukehren, zu bauen, um niederreißen zu können, und sich selbst die hoffnungslose Bemühung aufzulegen, den Stein des Sisyphus bergan zu wälzen, um ihn wieder zurückrollen zu lassen. – Das Princip des Bösen in der Naturanlage des menschlichen Geschlechts scheint also hier mit dem des Guten nicht sowohl amalgamirt (verschmolzen), als vielmehr Eines durchs Andere neutralisirt zu sein, welches"}], "markers": [{"system": "AA", "band": "VII", "page": 82, "ref": "VII82"}], "running_header": "3. Eintheilung des Begriffs von dem, was man für die Zukunft vorherwissen will"}, {"page_id": "2538", "page_pdf": 2538, "page_book": 82, "page_kind": "body", "sigel": "AA VII, 82", "units": [{"type": "paragraph", "text": "Thatlosigkeit zu Folge haben würde (die hier der Stillstand heißt): eine leere Geschäftigkeit, das Gute mit dem Bösen durch Vorwärts und Rückwärts gehen so abwechseln zu lassen, daß das ganze Spiel des Verkehrs unserer Gattung mit sich selbst auf diesem Glob als ein bloßes Possenspiel angesehen werden müßte, was ihr keinen größeren Werth in den Augen der Vernunft verschaffen kann, als den die andere Thiergeschlechter haben, die dieses Spiel mit weniger Kosten und ohne Verstandesaufwand treiben."}], "running_header": "3. Eintheilung des Begriffs von dem, was man für die Zukunft vorherwissen will"}, {"page_id": "2539_0", "page_pdf": 2539, "page_book": 82, "page_kind": "body", "sigel": "AA VII, 82", "units": [{"type": "paragraph", "text": "4. Durch Erfahrung unmittelbar ist die Aufgabe des Fortschreitens nicht aufzulösen."}], "running_header": "4. Durch Erfahrung unmittelbar ist die Aufgabe des Fortschreitens nicht aufzulösen"}, {"page_id": "2539_1", "page_pdf": 2539, "page_book": 83, "page_kind": "body", "sigel": "AA VII, 83", "units": [{"type": "paragraph", "text": "Wenn das menschliche Geschlecht, im Ganzen betrachtet, eine noch so lange Zeit vorwärts gehend und im Fortschreiten begriffen gewesen zu sein befunden würde, so kann doch niemand dafür stehen, daß nun nicht gerade jetzt vermöge der physischen Anlage unserer Gattung die Epoche seines Rückganges eintrete; und umgekehrt, wenn es rücklings und mit beschleunigtem Falle zum Ärgeren geht, so darf man nicht verzagen, daß nicht eben da der Umwendungspunkt (_punctum flexus contrarii_) anzutreffen wäre, wo vermöge der moralischen Anlage in unserem Geschlecht der Gang desselben sich wiederum zum Besseren wendete. Denn wir haben es mit freihandelnden Wesen zu thun, denen sich zwar vorher dictiren läßt, was sie thun sollen, aber nicht vorhersagen läßt, was sie thun werden, und die aus dem Gefühl der Übel, die sie sich selbst zufügten, wenn es recht böse wird, eine verstärkte Triebfeder zu nehmen wissen, es nun doch besser zu machen, als es vor jenem Zustande war. – Aber »arme Sterbliche (sagt der Abt Coyer), unter euch ist nichts beständig, als die Unbeständigkeit!« Vielleicht liegt es auch an unserer unrecht genommenen Wahl des Standpunkts, aus dem wir den Lauf menschlicher Dinge ansehen, daß dieser uns so widersinnisch scheint. Die Planeten, von der Erde aus gesehen, sind bald rückgängig, bald stillstehend, bald fortgängig. Den Standpunkt aber von der Sonne aus genommen, welches nur die Vernunft thun kann, gehen sie nach der Kopernikanischen Hypothese beständig ihren regelmäßigen Gang fort. Es gefällt aber einigen sonst nicht Unweisen, steif auf ihrer Erklärungsart der Erscheinungen und dem Standpunkte zu beharren, den sie einmal genommen haben: sollten sie sich darüber auch in Tychonische Cyklen und Epicyklen bis zur Ungereimtheit verwickeln. – Aber das ist eben das Unglück, daß wir uns in diesen Standpunkt, wenn es die Vorhersagung freier Handlungen angeht, zu versetzen nicht vermögend sind. Denn das wäre der Standpunkt der Vorsehung , der über alle menschliche Weisheit hinausliegt, welche sich auch auf freie Handlungen des Menschen erstreckt, die von diesem zwar gesehen, aber mit Gewißheit nicht vorhergesehen werden können (für das göttliche Auge"}], "markers": [{"system": "AA", "band": "VII", "page": 83, "ref": "VII83"}], "running_header": "4. Durch Erfahrung unmittelbar ist die Aufgabe des Fortschreitens nicht aufzulösen"}, {"page_id": "2539_2", "page_pdf": 2539, "page_book": 84, "page_kind": "body", "sigel": "AA VII, 84", "units": [{"type": "paragraph", "text": "ist hier kein Unterschied), weil er zu dem letzteren den Zusammenhang nach Naturgesetzen bedarf, in Ansehung der künftigen freien Handlungen aber dieser Leitung oder Hinweisung entbehren muß. Wenn man den Menschen einen angebornen und unveränderlich-guten, obzwar eingeschränkten Willen beilegen dürfte, so würde er dieses Fortschreiten seiner Gattung zum Besseren mit Sicherheit vorhersagen können: weil es eine Begebenheit träfe, die er selbst machen kann. Bei der Mischung des Bösen aber mit dem Guten in der Anlage, deren Maß er nicht kennt, weiß er selbst nicht, welcher Wirkung er sich davon gewärtigen könne."}], "markers": [{"system": "AA", "band": "VII", "page": 84, "ref": "VII84"}], "running_header": "4. Durch Erfahrung unmittelbar ist die Aufgabe des Fortschreitens nicht aufzulösen"}, {"page_id": "2540_0", "page_pdf": 2540, "page_book": 84, "page_kind": "body", "sigel": "AA VII, 84", "units": [{"type": "paragraph", "text": "5. An irgend eine Erfahrung muß doch die wahrsagende Geschichte des Menschengeschlechts angeknüpft werden."}], "running_header": "5. An irgend eine Erfahrung muß doch die wahrsagende Geschichte des Menschengeschlechts angeknüpft werden"}, {"page_id": "2540_1", "page_pdf": 2540, "page_book": 84, "page_kind": "body", "sigel": "AA VII, 84", "units": [{"type": "paragraph", "text": "Es muß irgend eine Erfahrung im Menschengeschlechte vorkommen, die als Begebenheit auf eine Beschaffenheit und ein Vermögen desselben hinweiset, Ursache von dem Fortrücken desselben zum Besseren und (da dieses die That eines mit Freiheit begabten Wesens sein soll) Urheber desselben zu sein; aus einer gegebenen Ursache aber läßt sich eine Begebenheit als Wirkung vorhersagen, wenn sich die Umstände eräugnen, welche dazu mitwirkend sind. Daß diese letztere sich aber irgend einmal eräugnen müssen, kann wie beim Calcul der Wahrscheinlichkeit im Spiel wohl im Allgemeinen vorhergesagt, aber nicht bestimmt werden, ob es sich in meinem Leben zutragen und ich die Erfahrung davon haben werde, die jene Vorhersagung bestätigte. – Also muß eine Begebenheit nachgesucht werden, welche auf das Dasein einer solchen Ursache und auch auf den Act ihrer Causalität im Menschengeschlechte unbestimmt in Ansehung der Zeit hinweise, und die auf das Fortschreiten zum Besseren als unausbleibliche Folge schließen ließe, welcher Schluß dann auch auf die Geschichte der vergangenen Zeit (daß es immer im Fortschritt gewesen sei) ausgedehnt werden könnte, doch so, daß jene Begebenheit nicht selbst als Ursache des letzteren, sondern nur als hindeutend, als Geschichtszeichen (_signum rememorativum, demonstrativum, prognostikon_), angesehen werden müsse und so die Tendenz des menschlichen Geschlechts im Ganzen, d.i. nicht nach den Individuen betrachtet (denn das würde eine nicht zu beendigende Aufzählung und Berechnung abgeben), sondern wie es in Völkerschaften und Staaten getheilt auf Erden angetroffen wird, beweisen könnte."}], "markers": [{"system": "AA", "band": "VII", "page": 84, "ref": "VII84"}], "running_header": "5. An irgend eine Erfahrung muß doch die wahrsagende Geschichte des Menschengeschlechts angeknüpft werden"}, {"page_id": "2541_0", "page_pdf": 2541, "page_book": 84, "page_kind": "body", "sigel": "AA VII, 84", "units": [{"type": "paragraph", "text": "6. Von einer Begebenheit unserer Zeit, welche diese moralische Tendenz des Menschengeschlechts beweiset."}], "running_header": "6. Von einer Begebenheit unserer Zeit, welche diese moralische Tendenz des Menschengeschlechts beweiset"}, {"page_id": "2541_1", "page_pdf": 2541, "page_book": 85, "page_kind": "body", "sigel": "AA VII, 85", "units": [{"type": "paragraph", "text": "Diese Begebenheit besteht nicht etwa in wichtigen, von Menschen verrichteten Thaten oder Unthaten, wodurch, was groß war, unter Menschen klein oder, was klein war, groß gemacht wird, und wie gleich als durch Zauberei alte, glänzende Staatsgebäude verschwinden, und andere an deren Statt wie aus den Tiefen der Erde hervorkommen. Nein: nichts von allem dem. Es ist bloß die Denkungsart der Zuschauer, welche sich bei diesem Spiele großer Umwandlungen öffentlich verräth und eine so allgemeine und doch uneigennützige Theilnehmung der Spielenden auf einer Seite gegen die auf der andern, selbst mit Gefahr, diese Parteilichkeit könne ihnen sehr nachtheilig werden, dennoch laut werden läßt, so aber (der Allgemeinheit wegen) einen Charakter des Menschengeschlechts im Ganzen und zugleich (der Uneigennützigkeit wegen) einen moralischen Charakter desselben wenigstens in der Anlage beweiset, der das Fortschreiten zum Besseren nicht allein hoffen läßt, sondern selbst schon ein solches ist, so weit das Vermögen desselben für jetzt zureicht. Die Revolution eines geistreichen Volks, die wir in unseren Tagen haben vor sich gehen sehen, mag gelingen oder scheitern; sie mag mit Elend und Greuelthaten dermaßen angefüllt sein, daß ein wohldenkender Mensch sie, wenn er sie zum zweitenmale unternehmend glücklich auszuführen hoffen könnte, doch das Experiment auf solche Kosten zu machen nie beschließen würde, – diese Revolution, sage ich, findet doch in den Gemüthern aller Zuschauer (die nicht selbst in diesem Spiele mit verwickelt sind) eine Theilnehmung dem Wunsche nach, die nahe an Enthusiasm grenzt, und deren Äußerung selbst mit Gefahr verbunden war, die also keine andere als eine moralische Anlage im Menschengeschlecht zur Ursache haben kann. Diese moralische einfließende Ursache ist zwiefach: erstens die des Rechts, daß ein Volk von anderen Mächten nicht gehindert werden müsse, sich eine bürgerliche Verfassung zu geben, wie sie ihm selbst gut zu sein dünkt; zweitens die des Zwecks (der zugleich Pflicht ist), daß diejenige Verfassung eines Volks allein an sich rechtlich und moralisch-gut sei, welche ihrer Natur nach so beschaffen ist, den Angriffskrieg nach Grundsätzen zu meiden, welche keine andere als die republicanische Verfassung,"}], "markers": [{"system": "AA", "band": "VII", "page": 85, "ref": "VII85"}], "running_header": "6. Von einer Begebenheit unserer Zeit, welche diese moralische Tendenz des Menschengeschlechts beweiset"}, {"page_id": "2541_2", "page_pdf": 2541, "page_book": 86, "page_kind": "body", "sigel": "AA VII, 86", "units": [{"type": "paragraph", "text": "wenigstens der Idee nach, sein kann,*[1] mithin in die Bedingung einzutreten, wodurch der Krieg (der Quell aller Übel und Verderbniß der Sitten) abgehalten und so dem Menschengeschlechte bei aller seiner Gebrechlichkeit der Fortschritt zum Besseren negativ gesichert wird, im Fortschreiten wenigstens nicht gestört zu werden. Dies also und die Theilnehmung am Guten mit Affect, der Enthusiasm, ob er zwar, weil aller Affect als ein solcher Tadel verdient, nicht ganz zu billigen ist, giebt doch vermittelst dieser Geschichte zu der für die Anthropologie wichtigen Bemerkung Anlaß: daß wahrer Enthusiasm nur immer aufs Idealische und zwar rein Moralische geht, dergleichen der Rechtsbegriff ist, und nicht auf den Eigennutz gepfropft werden kann. Durch Geldbelohnungen konnten die Gegner der Revolutionirenden zu dem Eifer und der Seelengröße nicht gespannt werden, den der bloße Rechtsbegriff in ihnen hervorbrachte, und selbst der Ehrbegriff des alten kriegerischen Adels (ein Analogon des Enthusiasm) verschwand vor den Waffen derer, welche das Recht des Volks, wozu sie gehörten, ins Auge gefaßt hatten**[2] und sich als Beschützer desselben dachten; mit welcher"}], "markers": [{"system": "AA", "band": "VII", "page": 86, "ref": "VII86"}], "running_header": "6. Von einer Begebenheit unserer Zeit, welche diese moralische Tendenz des Menschengeschlechts beweiset"}, {"page_id": "2541_3", "page_pdf": 2541, "page_book": 87, "page_kind": "body", "sigel": "AA VII, 87", "units": [{"type": "paragraph", "text": "Exaltation das äußere, zuschauende Publicum dann ohne die mindeste Absicht der Mitwirkung sympathisirte."}, {"type": "paragraph", "text": "Anmerkungen:"}], "markers": [{"system": "AA", "band": "VII", "page": 87, "ref": "VII87"}], "running_header": "6. Von einer Begebenheit unserer Zeit, welche diese moralische Tendenz des Menschengeschlechts beweiset"}, {"page_id": "2542", "page_pdf": 2542, "page_book": 87, "page_kind": "body", "sigel": "AA VII, 87", "units": [{"type": "paragraph", "text": "*[1] Es ist aber hiemit nicht gemeint, daß ein Volk, welches eine monarchische Constitution hat, sich damit das Recht anmaße, ja auch nur in sich geheim den Wunsch hege, sie abgeändert zu wissen; denn seine vielleicht sehr verbreitete Lage in Europa kann ihm jene Verfassung als die einzige anempfehlen, bei der es sich zwischen mächtigen Nachbaren erhalten kann. Auch ist das Murren der Unterthanen nicht des Innern der Regierung halber, sondern wegen des Benehmens derselben gegen Auswärtige, wenn sie diese etwa am Republicanisiren hinderte, gar kein Beweis der Unzufriedenheit des Volks mit seiner eigenen Verfassung, sondern vielmehr der Liebe für dieselbe, weil es wider eigene Gefahr desto mehr gesichert ist, je mehr sich andere Völker republicanisiren. – Dennoch haben verläumderische Sykophanten, um sich wichtig zu machen, diese unschuldige Kannegießerei für Neuerungssucht, Jacobinerei und Rottirung, die dem Staat Gefahr drohe, auszugeben gesucht: indessen daß auch nicht der mindeste Grund zu diesem Vorgeben da war, vornehmlich nicht in einem Lande, was vom Schauplatz der Revolution mehr als hundert Meilen entfernt war. **[2] Von einem solchen Enthusiasm der Rechtsbehauptung für das menschliche Geschlecht kann man sagen: _postquam ad arma Vulcania ventum est, – mortalis mucro glacies ceu futilis ictu dissiluit. – _Warum hat es noch nie ein Herrscher gewagt, frei herauszusagen, daß er gar kein Recht des Volks gegen ihn anerkenne; daß dieses seine Glückseligkeit bloß der Wohlthätigkeit einer Regierung, die diese ihm angedeihen läßt, verdanke, und alle Anmaßung des Unterthans zu einem Recht gegen dieselbe (weil dieses den Begriff eines erlaubten Widerstands in sich enthält) ungereimt, ja gar strafbar sei? – Die Ursache ist: weil eine solche öffentliche Erklärung alle Unterthanen gegen ihn empören würde, ob sie gleich, wie folgsame Schafe von einem gütigen und verständigen Herren geleitet, wohlgefüttert und kräftig beschützt, über nichts, was ihrer Wohlfahrt abginge, zu klagen hätten. – Denn mit Freiheit begabten Wesen gnügt nicht der Genuß der Lebensannehmlichkeit, die ihm auch von Anderen (und hier von der Regierung) zu Theil werden kann; sondern auf das Princip kommt es an, nach welchem es sich solche verschafft. Wohlfahrt aber hat kein Princip, weder für den, der sie empfängt, noch der sie austheilt (der eine setzt sie hierin, der andere darin): weil es dabei auf das Materiale des Willens ankommt, welches empirisch und so der Allgemeinheit einer Regel unfähig ist. Ein mit Freiheit begabtes Wesen kann und soll also im Bewußtsein dieses seines Vorzuges vor dem vernunftlosen Thier nach dem formalen Princip seiner Willkür keine andere Regierung für das Volk, wozu es gehört, verlangen, als eine solche, in welcher dieses mit gesetzgebend ist: d.i. das Recht der Menschen, welche gehorchen sollen, muß nothwendig vor aller Rücksicht auf Wohlbefinden vorhergehen, und dieses ist ein Heiligthum, das über allen Preis (der Nützlichkeit) erhaben ist, und welches keine Regierung, so wohlthätig sie auch immer sein mag, antasten darf. – Aber dieses Recht ist doch immer nur eine Idee, deren Ausführung auf die Bedingung der Zusammenstimmung ihrer Mittel mit der Moralität eingeschränkt ist, welche das Volk nicht überschreiten darf; welches nicht durch Revolution, die jederzeit ungerecht ist, geschehen darf. – Autokratisch herrschen und dabei doch republicanisch, d.h. im Geiste des Republicanism und nach einer Analogie mit demselben, regieren, ist das, was ein Volk mit seiner Verfassung zufrieden macht."}], "markers": [{"system": "AA", "band": "VII", "page": 87, "ref": "VII87"}], "running_header": "6. Von einer Begebenheit unserer Zeit, welche diese moralische Tendenz des Menschengeschlechts beweiset"}, {"page_id": "2543_0", "page_pdf": 2543, "page_book": 87, "page_kind": "body", "sigel": "AA VII, 87", "units": [{"type": "paragraph", "text": "7. Wahrsagende Geschichte der Menschheit."}], "running_header": "7. Wahrsagende Geschichte der Menschheit"}, {"page_id": "2543_1", "page_pdf": 2543, "page_book": 87, "page_kind": "body", "sigel": "AA VII, 87", "units": [{"type": "paragraph", "text": "Es muß etwas Moralisches im Grundsatze sein, welches die Vernunft als rein, zugleich aber auch wegen des großen und Epoche machenden Einflusses als etwas, das die dazu anerkannte Pflicht der Seele des Menschen vor Augen stellt, und das menschliche Geschlecht im Ganzen seiner Vereinigung (_non singulorum, sed universorum_) angeht, dessen verhofftem Gelingen und den Versuchen zu demselben es mit so allgemeiner und uneigennütziger Theilnehmung zujauchzt. – Diese Begebenheit ist das Phänomen nicht einer Revolution, sondern (wie es Hr. Erhard ausdrückt) der Evolution einer naturrechtlichen Verfassung, die zwar nur unter wilden Kämpfen noch nicht selbst errungen wird – indem der"}], "markers": [{"system": "AA", "band": "VII", "page": 87, "ref": "VII87"}], "running_header": "7. Wahrsagende Geschichte der Menschheit"}, {"page_id": "2543_2", "page_pdf": 2543, "page_book": 88, "page_kind": "body", "sigel": "AA VII, 88", "units": [{"type": "paragraph", "text": "Krieg von innen und außen alle bisher bestandene statutarische zerstört – , die aber doch dahin führt, zu einer Verfassung hinzustreben, welche nicht kriegssüchtig sein kann, nämlich der republicanischen; die es entweder selbst der Staatsform nach sein mag, oder auch nur nach der Regierungsart, bei der Einheit des Oberhaupts (des Monarchen) den Gesetzen analogisch, die sich ein Volk selbst nach allgemeinen Rechtsprincipien geben würde, den Staat verwalten zu lassen. Nun behaupte ich dem Menschengeschlechte nach den Aspecten und Vorzeichen unserer Tage die Erreichung dieses Zwecks und hiemit zugleich das von da an nicht mehr gänzlich rückgängig werdende Fortschreiten desselben zum Besseren auch ohne Sehergeist vorhersagen zu können. Denn ein solches Phänomen in der Menschengeschichte vergißt sich nicht mehr, weil es eine Anlage und ein Vermögen in der menschlichen Natur zum Besseren aufgedeckt hat, dergleichen kein Politiker aus dem bisherigen Laufe der Dinge herausgeklügelt hätte, und welches allein Natur und Freiheit, nach inneren Rechtsprincipien im Menschengeschlechte vereinigt, aber, was die Zeit betrifft, nur als unbestimmt und Begebenheit aus Zufall verheißen konnte. Aber wenn der bei dieser Begebenheit beabsichtigte Zweck auch jetzt nicht erreicht würde, wenn die Revolution oder Reform der Verfassung eines Volks gegen das Ende doch fehlschlüge, oder, nachdem diese einige Zeit gewährt hätte, doch wiederum alles ins vorige Gleis zurückgebracht würde (wie Politiker jetzt wahrsagern), so verliert jene philosophische Vorhersagung doch nichts von ihrer Kraft. – Denn jene Begebenheit ist zu groß, zu sehr mit dem Interesse der Menschheit verwebt und ihrem Einflusse nach auf die Welt in allen ihren Theilen zu ausgebreitet, als daß sie nicht den Völkern bei irgend einer Veranlassung günstiger Umstände in Erinnerung gebracht und zu Wiederholung neuer Versuche dieser Art erweckt werden sollte; da dann bei einer für das Menschengeschlecht so wichtigen Angelegenheit endlich doch zu irgend einer Zeit die beabsichtigte Verfassung diejenige Festigkeit erreichen muß, welche die Belehrung durch öftere Erfahrung in den Gemüthern Aller zu bewirken nicht ermangeln würde. Es ist also ein nicht bloß gutgemeinter und in praktischer Absicht empfehlungswürdiger, sondern allen Ungläubigen zum Trotz auch für die strengste Theorie haltbarer Satz: daß das menschliche Geschlecht im Fortschreiten zum Besseren immer gewesen sei und so fernerhin fortgehen werde,"}], "markers": [{"system": "AA", "band": "VII", "page": 88, "ref": "VII88"}], "running_header": "7. Wahrsagende Geschichte der Menschheit"}, {"page_id": "2543_3", "page_pdf": 2543, "page_book": 89, "page_kind": "body", "sigel": "AA VII, 89", "units": [{"type": "paragraph", "text": "welches, wenn man nicht bloß auf das sieht, was in irgend einem Volk geschehen kann, sondern auch auf die Verbreitung über alle Völker der Erde, die nach und nach daran Theil nehmen dürften, die Aussicht in eine unabsehliche Zeit eröffnet; wofern nicht etwa auf die erste Epoche einer Naturrevolution, die (nach Camper und Blumenbach) bloß das Thier- und Pflanzenreich, ehe noch Menschen waren, vergrub, noch eine zweite folgt, welche auch dem Menschengeschlechte eben so mitspielt, um andere Geschöpfe auf diese Bühne treten zu lassen, u.s.w. Denn für die Allgewalt der Natur, oder vielmehr ihrer uns unerreichbaren obersten Ursache ist der Mensch wiederum nur eine Kleinigkeit. Daß ihn aber auch die Herrscher von seiner eigenen Gattung dafür nehmen und als eine solche behandeln, indem sie ihn theils thierisch, als bloßes Werkzeug ihrer Absichten, belasten, theils in ihren Streitigkeiten gegen einander"}], "markers": [{"system": "AA", "band": "VII", "page": 89, "ref": "VII89"}], "running_header": "7. Wahrsagende Geschichte der Menschheit"}, {"page_id": "2544", "page_pdf": 2544, "page_book": 89, "page_kind": "body", "sigel": "AA VII, 89", "units": [{"type": "paragraph", "text": "aufstellen, um sie schlachten zu lassen, – das ist keine Kleinigkeit, sondern Umkehrung des Endzwecks der Schöpfung selbst."}], "running_header": "7. Wahrsagende Geschichte der Menschheit"}, {"page_id": "2545_0", "page_pdf": 2545, "page_book": 89, "page_kind": "body", "sigel": "AA VII, 89", "units": [{"type": "paragraph", "text": "8. Von der Schwierigkeit der auf das Fortschreiten zum Weltbesten angelegten Maximen in Ansehung ihrer Publicität."}], "running_header": "8. Von der Schwierigkeit der auf das Fortschreiten zum Weltbesten angelegten Maximen in Ansehung ihrer Publicität"}, {"page_id": "2545_1", "page_pdf": 2545, "page_book": 89, "page_kind": "body", "sigel": "AA VII, 89", "units": [{"type": "paragraph", "text": "Volksaufklärung ist die öffentliche Belehrung des Volks von seinen Pflichten und Rechten in Ansehung des Staats, dem es angehört. Weil es hier nur natürliche und aus dem gemeinen Menschenverstande hervorgehende Rechte betrifft, so sind die natürlichen Verkündiger und Ausleger derselben im Volk nicht die vom Staat bestellte amtsmäßige, sondern freie Rechtslehrer, d.i. die Philosophen, welche eben um dieser Freiheit willen, die sie sich erlauben, dem Staate, der immer nur herrschen will, anstößig sind, und werden unter dem Namen Aufklärer als für den Staat gefährliche Leute verschrieen; obzwar ihre Stimme nicht vertraulich ans Volk (als welches davon und von ihren Schriften wenig oder gar keine Notiz nimmt), sondern ehrerbietig an den Staat gerichtet und dieser jenes sein rechtliches Bedürfniß zu beherzigen angefleht wird; welches durch keinen andern Weg als den der Publicität geschehen kann, wenn ein ganzes Volk seine Beschwerde (_gravamen_) vortragen will. So verhindert das Verbot der Publicität den Fortschritt eines Volks zum Besseren, selbst in dem, was das Mindeste seiner Forderung, nämlich bloß sein natürliches Recht, angeht."}], "markers": [{"system": "AA", "band": "VII", "page": 89, "ref": "VII89"}], "running_header": "8. Von der Schwierigkeit der auf das Fortschreiten zum Weltbesten angelegten Maximen in Ansehung ihrer Publicität"}, {"page_id": "2545_2", "page_pdf": 2545, "page_book": 90, "page_kind": "body", "sigel": "AA VII, 90", "units": [{"type": "paragraph", "text": "Eine andere, obzwar leicht durchzuschauende, aber doch gesetzmäßig einem Volk befohlene Verheimlichung ist die von der wahren Beschaffenheit seiner Constitution. Es wäre Verletzung der Majestät des großbritannischen Volks, von ihm zu sagen, es sei eine unbeschränkte Monarchie: sondern man will, es soll eine durch die zwei Häuser des Parlaments, als Volksrepräsentanten, den Willen des Monarchen einschränkende Verfassung sein, und doch weiß ein jeder sehr gut, daß der Einfluß desselben auf diese Repräsentanten so groß und so unfehlbar ist, daß von gedachten Häusern nichts anderes beschlossen wird, als was Er will und durch seinen Minister anträgt; der dann auch wohl einmal auf Beschlüsse anträgt, bei denen er weiß und es auch macht, daß ihm werde widersprochen werden (z.B. wegen des Negerhandels), um von der Freiheit des Parlaments einen scheinbaren Beweis zu geben. – Diese Vorstellung der Beschaffenheit der Sache hat das Trügliche an sich, daß die wahre, zu Recht beständige Verfassung gar nicht mehr gesucht wird: weil man sie in einem schon vorhandenen Beispiel gefunden zu haben vermeint, und eine lügenhafte Publicität das Volk mit Vorspiegelung einer durch das von ihm ausgehende Gesetz eingeschränkten Monarchie* täuscht, indessen daß seine Stellvertreter, durch Bestechung gewonnen, es ingeheim einem absoluten Monarchen unterwarfen."}, {"type": "paragraph", "text": "* * *"}, {"type": "paragraph", "text": "Die Idee einer mit dem natürlichen Rechte der Menschen zusammenstimmenden Constitution: daß nämlich die dem Gesetz Gehorchenden auch"}], "markers": [{"system": "AA", "band": "VII", "page": 90, "ref": "VII90"}], "running_header": "8. Von der Schwierigkeit der auf das Fortschreiten zum Weltbesten angelegten Maximen in Ansehung ihrer Publicität"}, {"page_id": "2545_3", "page_pdf": 2545, "page_book": 91, "page_kind": "body", "sigel": "AA VII, 91", "units": [{"type": "paragraph", "text": "zugleich, vereinigt, gesetzgebend sein sollen, liegt bei allen Staatsformen zum Grunde, und das gemeine Wesen, welches, ihr gemäß durch reine Vernunftbegriffe gedacht, ein platonisches Ideal heißt (_respublica noumenon_), ist nicht ein leeres Hirngespinst, sondern die ewige Norm für alle bürgerliche Verfassung überhaupt und entfernt allen Krieg. Eine dieser gemäß organisirte bürgerliche Gesellschaft ist die Darstellung derselben nach Freiheitsgesetzen durch ein Beispiel in der Erfahrung (_respublica phaenomenon_) und kann nur nach mannigfaltigen Befehdungen und Kriegen mühsam erworben werden; ihre Verfassung aber, wenn sie im Großen einmal errungen worden, qualificirt sich zur besten unter allen, um den Krieg, den Zerstörer alles Guten, entfernt zu halten; mithin ist es Pflicht in eine solche einzutreten, vorläufig aber (weil jenes nicht so bald zu Stande kommt) Pflicht der Monarchen, ob sie gleich autokratisch herrschen, dennoch republicanisch (nicht demokratisch) zu regieren, d.i. das Volk nach Principien zu behandeln, die dem Geist der Freiheitsgesetze (wie ein Volk mit reifer Vernunft sie sich selbst vorschreiben"}], "markers": [{"system": "AA", "band": "VII", "page": 91, "ref": "VII91"}], "running_header": "8. Von der Schwierigkeit der auf das Fortschreiten zum Weltbesten angelegten Maximen in Ansehung ihrer Publicität"}, {"page_id": "2546", "page_pdf": 2546, "page_book": 91, "page_kind": "body", "sigel": "AA VII, 91", "units": [{"type": "paragraph", "text": "würde) gemäß sind, wenn gleich dem Buchstaben nach es um seine Einwilligung nicht befragt würde."}, {"type": "paragraph", "text": "Anmerkungen: * Eine Ursache, deren Beschaffenheit man nicht unmittelbar einsieht, entdeckt sich durch die Wirkung, die ihr unausbleiblich anhängt. – Was ist ein absoluter Monarch? Es ist derjenige, auf dessen Befehl, wenn er sagt: es soll Krieg sein, sofort Krieg ist. – Was ist dagegen ein eingeschränkter Monarch? Der, welcher vorher das Volk befragen muß, ob Krieg sein solle oder nicht, und sagt das Volk: es soll nicht Krieg sein, so ist kein Krieg. – Denn Krieg ist ein Zustand, in welchem dem Staatsoberhaupte alle Staatskräfte zu Gebot stehen müssen. Nun hat der großbritannische Monarch recht viel Kriege geführt, ohne dazu jene Einwilligung zu suchen. Also ist dieser König ein absoluter Monarch, der er zwar der Constitution nach nicht sein sollte; die er aber immer vorbei gehen kann, weil er eben durch jene Staatskräfte, nämlich daß er alle Ämter und Würden zu vergeben in seiner Macht hat, sich der Beistimmung der Volksrepräsentanten versichert halten kann. Dieses Bestechungssystem muß aber freilich nicht Publicität haben, um zu gelingen. Es bleibt daher unter dem sehr durchsichtigen Schleier des Geheimnisses."}], "running_header": "8. Von der Schwierigkeit der auf das Fortschreiten zum Weltbesten angelegten Maximen in Ansehung ihrer Publicität"}, {"page_id": "2547_0", "page_pdf": 2547, "page_book": 91, "page_kind": "body", "sigel": "AA VII, 91", "units": [{"type": "paragraph", "text": "9. Welchen Ertrag wird der Fortschritt zum Besseren dem Menschengeschlecht abwerfen?"}], "running_header": "9. Welchen Ertrag wird der Fortschritt zum Besseren dem Menschengeschlecht abwerfen?"}, {"page_id": "2547_1", "page_pdf": 2547, "page_book": 91, "page_kind": "body", "sigel": "AA VII, 91", "units": [{"type": "paragraph", "text": "Nicht ein immer wachsendes Quantum der Moralität in der Gesinnung, sondern Vermehrung der Producte ihrer Legalität in pflichtmäßigen Handlungen, durch welche Triebfeder sie auch veranlaßt sein mögen; d.i. in den guten Thaten der Menschen, die immer zahlreicher und besser ausfallen werden, also in den Phänomenen der sittlichen Beschaffenheit des Menschengeschlechts, wird der Ertrag (das Resultat) der Bearbeitung desselben zum Besseren allein gesetzt werden können. – Denn wir haben nur empirische Data (Erfahrungen), worauf wir diese Vorhersagung gründen: nämlich auf die physische Ursache unserer Handlungen, in sofern sie geschehen, die also selbst Erscheinungen sind, nicht die moralische, welche den Pflichtbegriff von dem enthält, was geschehen sollte, und der allein rein,_ a priori_, aufgestellt werden kann. Allmählich wird der Gewaltthätigkeit von Seiten der Mächtigen weniger, der Folgsamkeit in Ansehung der Gesetze mehr werden. Es wird etwa mehr Wohlthätigkeit, weniger Zank in Processen, mehr Zuverlässigkeit"}], "markers": [{"system": "AA", "band": "VII", "page": 91, "ref": "VII91"}], "running_header": "9. Welchen Ertrag wird der Fortschritt zum Besseren dem Menschengeschlecht abwerfen?"}, {"page_id": "2547_2", "page_pdf": 2547, "page_book": 92, "page_kind": "body", "sigel": "AA VII, 92", "units": [{"type": "paragraph", "text": "im Worthalten u.s.w. theils aus Ehrliebe, theils aus wohlverstandenem eigenen Vortheil im gemeinen Wesen entspringen und sich endlich dies auch auf die Völker im äußeren Verhältniß gegen einander bis zur weltbürgerlichen Gesellschaft erstrecken, ohne daß dabei die moralische Grundlage im Menschengeschlechte im mindesten vergrößert werden darf; als wozu auch eine Art von neuer Schöpfung (übernatürlicher Einfluß) erforderlich sein würde. – Denn wir müssen uns von Menschen in ihren Fortschritten zum Besseren auch nicht zu viel versprechen, um nicht in den Spott des Politikers mit Grunde zu verfallen, der die Hoffnung des ersteren gerne für Träumerei eines überspannten Kopfs halten möchte.*"}, {"type": "paragraph", "text": "Anmerkungen: * Es ist doch süß, sich Staatsverfassungen auszudenken, die den Forderungen der Vernunft (vornehmlich in rechtlicher Absicht) entsprechen: aber vermessen, sie vorzuschlagen, und strafbar, das Volk zur Abschaffung der jetzt bestehenden aufzuwiegeln. Platos _Atlantica_, Morus’ _Utopia_, Harringtons _Oceana _und Allais’ _Severambia _sind nach und nach auf die Bühne gebracht, aber nie (Cromwells verunglückte Mißgeburt einer despotischen Republik ausgenommen) auch nur versucht worden. – Es ist mit diesen Staatsschöpfungen wie mit der Weltschöpfung zugegangen: kein Mensch war dabei zugegen, noch konnte er bei einer solchen gegenwärtig sein, weil er sonst sein eigener Schöpfer hätte sein müssen. Ein Staatsproduct, wie man es hier denkt, als dereinst, so spät es auch sei, vollendet zu hoffen, ist ein süßer Traum; aber sich ihm immer zu näheren, nicht allein denkbar, sondern, so weit es mit dem moralischen Gesetze zusammen bestehen kann, Pflicht, nicht der Staatsbürger, sondern des Staatsoberhaupts."}], "markers": [{"system": "AA", "band": "VII", "page": 92, "ref": "VII92"}], "running_header": "9. Welchen Ertrag wird der Fortschritt zum Besseren dem Menschengeschlecht abwerfen?"}, {"page_id": "2548_0", "page_pdf": 2548, "page_book": 92, "page_kind": "body", "sigel": "AA VII, 92", "units": [{"type": "paragraph", "text": "10. In welcher Ordnung allein kann der Fortschritt zum Besseren erwartet werden?"}], "running_header": "10. In welcher Ordnung allein kann der Fortschritt zum Besseren erwartet werden?"}, {"page_id": "2548_1", "page_pdf": 2548, "page_book": 92, "page_kind": "body", "sigel": "AA VII, 92", "units": [{"type": "paragraph", "text": "Die Antwort ist: nicht durch den Gang der Dinge von unten hinauf, sondern den von oben herab. – Zu erwarten, daß durch Bildung der Jugend in häuslicher Unterweisung und weiterhin in Schulen, von den niedrigen an bis zu den höchsten, in Geistes- und moralischer, durch Religionslehre verstärkter Cultur es endlich dahin kommen werde, nicht bloß gute Staatsbürger, sondern zum Guten, was immer weiter fortschreiten und sich erhalten kann, zu erziehen, ist ein Plan, der den erwünschten Erfolg schwerlich hoffen läßt. Denn nicht allein daß das Volk dafür hält, daß die Kosten der Erziehung seiner Jugend nicht ihm, sondern dem"}], "markers": [{"system": "AA", "band": "VII", "page": 92, "ref": "VII92"}], "running_header": "10. In welcher Ordnung allein kann der Fortschritt zum Besseren erwartet werden?"}, {"page_id": "2548_2", "page_pdf": 2548, "page_book": 93, "page_kind": "body", "sigel": "AA VII, 93", "units": [{"type": "paragraph", "text": "Staate zu Lasten kommen müssen, der Staat aber dagegen seinerseits zu Besoldung tüchtiger und mit Lust ihrem Amte obliegender Lehrer kein Geld übrig hat (wie Büsching klagt), weil er alles zum Kriege braucht: sondern das ganze Maschinenwesen dieser Bildung hat keinen Zusammenhang, wenn es nicht nach einem überlegten Plane der obersten Staatsmacht und nach dieser ihrer Absicht entworfen, ins Spiel gesetzt und darin auch immer gleichförmig erhalten wird; wozu wohl gehören möchte, daß der Staat sich von Zeit zu Zeit auch selbst reformire und, statt Revolution Evolution versuchend, zum Besseren beständig fortschreite. Da es aber doch auch Menschen sind, welche diese Erziehung bewirken sollen, mithin solche, die dazu selbst haben gezogen werden müssen: so ist bei dieser Gebrechlichkeit der menschlichen Natur unter der Zufälligkeit der Umstände, die einen solchen Effect begünstigen, die Hoffnung ihres Fortschreitens nur in einer Weisheit von oben herab (welche, wenn sie uns unsichtbar ist, Vorsehung heißt) als positiver Bedingung, für das aber, was hierin von Menschen erwartet und gefordert werden kann, bloß negative Weisheit zur Beförderung dieses Zwecks zu erwarten, nämlich daß sie das größte Hinderniß des Moralischen, nämlich den Krieg, der diesen immer zurückgängig macht, erstlich nach und nach menschlicher, darauf seltener, endlich als Angriffskrieg ganz schwinden zu lassen sich genöthigt sehen werden, um eine Verfassung einzuschlagen, die ihrer Natur nach, ohne sich zu schwächen, auf ächte Rechtsprincipien gegründet, beharrlich zum Bessern fortschreiten kann."}], "markers": [{"system": "AA", "band": "VII", "page": 93, "ref": "VII93"}], "running_header": "10. In welcher Ordnung allein kann der Fortschritt zum Besseren erwartet werden?"}, {"page_id": "2549_0", "page_pdf": 2549, "page_book": 93, "page_kind": "body", "sigel": "AA VII, 93", "units": [{"type": "paragraph", "text": "Beschluß."}], "running_header": "Beschluß"}, {"page_id": "2549_1", "page_pdf": 2549, "page_book": 93, "page_kind": "body", "sigel": "AA VII, 93", "units": [{"type": "paragraph", "text": "Ein Arzt, der seine Patienten von Tag zu Tag auf baldige Genesung vertröstete: den einen, daß der Puls besser schlüge; den anderen, daß der Auswurf, den dritten, daß der Schweiß Besserung verspräche, u.s.w., bekam einen Besuch von einem seiner Freunde. Wie gehts, Freund, mit eurer Krankheit? war die erste Frage. Wie wirds gehen? Ich sterbe vor lauter Besserung! – Ich verdenke es Keinem, wenn er in Ansehung der Staatsübel an dem Heil des Menschengeschlechts und dem Fortschreiten desselben zum Besseren zu verzagen anhebt; allein ich verlasse mich auf das heroische Arzneimittel, welches Hume anführt und eine schnelle Cur bewirken dürfte. – »Wenn ich jetzt (sagt er) die Nationen im Kriege gegen einander begriffen sehe, so ist es, als ob ich zwei besoffene"}], "markers": [{"system": "AA", "band": "VII", "page": 93, "ref": "VII93"}], "running_header": "Beschluß"}, {"page_id": "2549_2", "page_pdf": 2549, "page_book": 94, "page_kind": "body", "sigel": "AA VII, 94", "units": [{"type": "paragraph", "text": "Kerle sähe, die sich in einem Porzellänladen mit Prügeln herumschlagen. Denn nicht genug, daß sie an den Beulen, die sie sich wechselseitig geben, lange zu heilen haben, so müssen sie hinterher noch allen den Schaden bezahlen, den sie anrichteten.« _Sero sapiunt Phryges. _Die Nachwehen des gegenwärtigen Krieges aber können dem politischen Wahrsager das Geständniß einer nahe bevorstehenden Wendung des menschlichen Geschlechts zum Besseren abnöthigen, das schon jetzt im Prospect ist."}], "markers": [{"system": "AA", "band": "VII", "page": 94, "ref": "VII94"}], "running_header": "Beschluß"}, {"page_id": "2550_0", "page_pdf": 2550, "page_book": 94, "page_kind": "title_page", "sigel": "AA VII, 94", "units": [{"type": "paragraph", "text": "Dritter Abschnitt. Der Streit der philosophischen Facultät mit der medicinischen."}]}, {"page_id": "2550_1", "page_pdf": 2550, "page_book": 95, "page_kind": "title_page", "sigel": "AA VII, 95", "units": [], "markers": [{"system": "AA", "band": "VII", "page": 95, "ref": "VII95"}]}, {"page_id": "2551_0", "page_pdf": 2551, "page_book": 96, "page_kind": "body", "sigel": "AA VII, 96", "units": [{"type": "paragraph", "text": "Von der Macht des Gemüths"}, {"type": "heading", "text": "durch den bloßen Vorsatz seiner krankhaften Gefühle Meister zu sein.", "level": 2}, {"type": "paragraph", "text": "Ein Antwortschreiben an Herrn Hofrath und Professor Hufeland."}], "running_header": "Von der Macht des Gemüths durch den bloßen Vorsatz seiner krankhaften Gefühle Meister zu sein"}, {"page_id": "2551_1", "page_pdf": 2551, "page_book": 97, "page_kind": "body", "sigel": "AA VII, 97", "units": [{"type": "paragraph", "text": "Daß meine Danksagung für das den 12ten Dec. 1796 an mich bestellte Geschenk Ihres lehrreichen und angenehmen Buchs »von der Kunst das menschliche Leben zu verlängern« selbst auf ein langes Leben berechnet gewesen sein dürfte, möchten Sie vielleicht aus dem Datum dieser meiner Antwort vom Januar dieses Jahres zu schließen Ursache haben, wenn das Altgewordensein nicht schon die öftere Vertagung (_procrastinatio_) wichtiger Beschlüsse bei sich führte, dergleichen doch wohl der des Todes ist, welcher sich immer zu früh für uns anmeldet, und den man warten zu lassen an Ausreden unerschöpflich ist. Sie verlangen von mir ein Urtheil über Ihr »Bestreben, das Physische im Menschen moralisch zu behandeln; den ganzen, auch physischen Menschen als ein auf Moralität berechnetes Wesen darzustellen und die moralische Kultur als unentbehrlich zur physischen Vollendung der überall nur in der Anlage vorhandenen Menschennatur zu zeigen«, und setzen hinzu: »Wenigstens kann ich versichern, daß es keine vorgefaßte Meinungen waren, sondern ich durch die Arbeit und Untersuchung selbst unwiderstehlich in diese Behandlungsart hineingezogen wurde.« – – Eine solche Ansicht der Sache verräth den Philosophen, nicht den bloßen Vernunftkünstler; einen Mann, der nicht allein gleich einem der Directoren des französischen Convents die von der Vernunft verordneten Mittel der Ausführung (technisch), wie sie die Erfahrung darbietet, zu seiner Heilkunde mit Geschicklichkeit, sondern als gesetzgebendes Glied im Corps der Ärzte aus der reinen Vernunft hernimmt, welche zu dem, was hilft, mit"}], "markers": [{"system": "AA", "band": "VII", "page": 97, "ref": "VII97"}], "running_header": "Von der Macht des Gemüths durch den bloßen Vorsatz seiner krankhaften Gefühle Meister zu sein"}, {"page_id": "2551_2", "page_pdf": 2551, "page_book": 98, "page_kind": "body", "sigel": "AA VII, 98", "units": [{"type": "paragraph", "text": "Geschicklichkeit auch das, was zugleich an sich Pflicht ist, mit Weisheit zu verordnen weiß: so daß moralisch-praktische Philosophie zugleich eine Universalmedicin abgiebt, die zwar nicht Allen für Alles hilft, aber doch in keinem Recepte mangeln kann. Dieses Universalmittel betrifft aber nur die Diätetik, d.i. es wirkt nur negativ, als Kunst, Krankheiten abzuhalten. Dergleichen Kunst aber setzt ein Vermögen voraus, das nur Philosophie, oder der Geist derselben, den man schlechthin voraussetzen muß, geben kann. Auf diesen bezieht sich die oberste diätetische Aufgabe, welche in dem Thema enthalten ist: Von der Macht des Gemüths des Menschen über seine krankhafte Gefühle durch den bloßen festen Vorsatz Meister zu sein. Die die Möglichkeit dieses Ausspruchs bestätigenden Beispiele kann ich nicht von der Erfahrung Anderer hernehmen, sondern zuerst nur von der an mir selbst angestellten, weil sie aus dem Selbstbewußtsein hervorgeht und sich nachher allererst Andere fragen läßt: ob es nicht auch sie eben so in sich wahrnehmen. – Ich sehe mich also genöthigt, mein Ich laut werden zu lassen, was im dogmatischen Vortrage* Unbescheidenheit verräth, aber Verzeihung verdient, wenn es nicht gemeine Erfahrung, sondern ein inneres Experiment oder Beobachtung betrifft, welche ich zuerst an mir selbst angestellt haben muß, um etwas, was nicht jedermann von selbst, und ohne darauf geführt zu sein, beifällt, zu seiner Beurtheilung vorzulegen. – Es würde tadelhafte Anmaßung sein, Andere mit der inneren Geschichte meines Gedankenspiels unterhalten zu wollen, welche zwar subjective Wichtigkeit (für mich), aber keine objective (für jedermann geltende) enthielte. Wenn aber dieses Aufmerken auf sich selbst und die daraus hervorgehende Wahrnehmung nicht so gemein ist, sondern, daß jeder dazu aufgefordert werde, eine Sache ist, die es bedarf und verdient, so kann dieser Übelstand mit seinen Privatempfindungen Andere zu unterhalten, wenigstens verziehen werden. Ehe ich nun mit dem Resultat meiner in Absicht auf Diätetik angestellten"}], "markers": [{"system": "AA", "band": "VII", "page": 98, "ref": "VII98"}], "running_header": "Von der Macht des Gemüths durch den bloßen Vorsatz seiner krankhaften Gefühle Meister zu sein"}, {"page_id": "2551_3", "page_pdf": 2551, "page_book": 99, "page_kind": "body", "sigel": "AA VII, 99", "units": [{"type": "paragraph", "text": "Selbstbeobachtung aufzutreten wage, muß ich noch etwas über die Art bemerken, wie Herr Hufeland die Aufgabe der Diätetik, d.i. der Kunst stellt, Krankheiten vorzubeugen, im Gegensatz mit der Therapeutik, sie zu heilen."}], "markers": [{"system": "AA", "band": "VII", "page": 99, "ref": "VII99"}], "running_header": "Von der Macht des Gemüths durch den bloßen Vorsatz seiner krankhaften Gefühle Meister zu sein"}, {"page_id": "2552_0", "page_pdf": 2552, "page_book": 99, "page_kind": "body", "sigel": "AA VII, 99", "units": [{"type": "paragraph", "text": "Sie heißt ihm »die Kunst das menschliche Leben zu verlängern.« Er nimmt seine Benennung von demjenigen her, was die Menschen am sehnsüchtigsten wünschen, ob es gleich vielleicht weniger wünschenswerth sein dürfte. Sie möchten zwar gern zwei Wünsche zugleich thun: nämlich lange zu leben und dabei gesund zu sein; aber der erstere Wunsch hat den letzteren nicht zur nothwendigen Bedingung: sondern er ist unbedingt. Laßt den Hospitalkranken Jahre lang auf seinem Lager leiden und darben und ihn oft wünschen hören, daß ihn der Tod je eher je lieber von dieser Plage erlösen möge; glaubt ihm nicht, es ist nicht sein Ernst. Seine Vernunft sagt es ihm zwar vor, aber der Naturinstinct will es anders. Wenn er dem Tode als seinem Befreier (_Jovi liberatori_) winkt, so verlangt er doch immer noch eine kleine Frist und hat immer irgend einen Vorwand zur Vertagung (_procrastinatio_) seines peremtorischen Decrets. Der in wilder Entrüstung gefaßte Entschluß des Selbstmörders, seinem Leben ein Ende zu machen, macht hievon keine Ausnahme: denn er ist die Wirkung eines bis zum Wahnsinn exaltirten Affects. – Unter den zwei Verheißungen für die Befolgung der Kindespflicht (»auf daß dir es wohlgehe, und du lange lebest auf Erden«) enthält die letztere die stärkere Triebfeder, selbst im Urtheile der Vernunft, nämlich als Pflicht, deren Beobachtung zugleich verdienstlich ist. Die Pflicht, das Alter zu ehren, gründet sich nämlich eigentlich nicht auf die billige Schonung, die man den Jüngeren gegen die Schwachheit der Alten zumuthet: denn die ist kein Grund zu einer ihnen schuldigen Achtung. Das Alter will also noch für etwas Verdienstliches angesehen werden, weil ihm eine Verehrung zugestanden wird. Also nicht etwa weil Nestorjahre zugleich durch viele und lange Erfahrung erworbene Weisheit zu Leitung der jüngeren Welt bei sich führen, sondern blos weil, wenn nur keine Schande dasselbe befleckt hat, der Mann, welcher sich so lange erhalten hat, d.i. der Sterblichkeit als dem demüthigendsten Ausspruch, der über ein vernünftiges Wesen nur gefällt werden kann (»du bist Erde und sollst zur Erde werden«), so lange hat ausweichen und gleichsam der Unsterblichkeit hat abgewinnen können, weil, sage ich, ein solcher Mann sich so lange lebend erhalten und zum Beispiel aufgestellt hat."}], "running_header": "Von der Macht des Gemüths durch den bloßen Vorsatz seiner krankhaften Gefühle Meister zu sein"}, {"page_id": "2552_1", "page_pdf": 2552, "page_book": 100, "page_kind": "body", "sigel": "AA VII, 100", "units": [{"type": "paragraph", "text": "Mit der Gesundheit, als dem zweiten natürlichen Wunsche, ist es dagegen nur mißlich bewandt. Man kann sich gesund fühlen (aus dem behaglichen Gefühl seines Lebens urtheilen), nie aber wissen, daß man gesund sei. – Jede Ursache des natürlichen Todes ist Krankheit: man mag sie fühlen oder nicht. – Es giebt viele, von denen, ohne sie eben verspotten zu wollen, man sagt, daß sie für immer kränkeln, nie krank werden können; deren Diät ein immer wechselndes Abschweifen und wieder Einbeugen ihrer Lebensweise ist, und die es im Leben, wenn gleich nicht den Kraftäußerungen, doch der Länge nach weit bringen. Wie viel aber meiner Freunde oder Bekannten habe ich nicht überlebt, die sich bei einer einmal angenommenen ordentlichen Lebensart einer völligen Gesundheit rühmten: indessen daß der Keim des Todes (die Krankheit), der Entwickelung nahe, unbemerkt in ihnen lag, und der, welcher sich gesund fühlte, nicht wußte, daß er krank war; denn die Ursache eines natürlichen Todes kann man doch nicht anders als Krankheit nennen. Die Causalität aber kann man nicht fühlen, dazu gehört Verstand, dessen Urtheil irrig sein kann; indessen daß das Gefühl untrüglich ist, aber nur dann, wenn man sich krankhaft fühlt, diesen Namen führt; fühlt man sich aber so auch nicht, doch gleichwohl in dem Menschen verborgenerweise und zur baldigen Entwickelung bereit liegen kann; daher der Mangel dieses Gefühls keinen andern Ausdruck des Menschen für sein Wohlbefinden verstattet, als daß er scheinbarlich gesund sei. Das lange Leben also, wenn man dahin zurücksieht, kann nur die genossene Gesundheit bezeugen, und die Diätetik wird vor allem in der Kunst das Leben zu verlängern (nicht es zu genießen) ihre Geschicklichkeit oder Wissenschaft zu beweisen haben: wie es auch Herr Hufeland so ausgedrückt haben will."}, {"type": "paragraph", "text": "Anmerkungen:"}], "markers": [{"system": "AA", "band": "VII", "page": 100, "ref": "VII100"}], "running_header": "Von der Macht des Gemüths durch den bloßen Vorsatz seiner krankhaften Gefühle Meister zu sein"}, {"page_id": "2553", "page_pdf": 2553, "page_book": 100, "page_kind": "body", "sigel": "AA VII, 100", "units": [{"type": "paragraph", "text": "* Im dogmatisch-praktischen Vortrage, z.B. derjenigen Beobachtung seiner selbst, die auf Pflichten abzweckt, die Jedermann angehen, spricht der Kanzelredner nicht durch Ich, sondern Wir. In dem erzählenden aber, der Privatempfindung (der Beichte, welche der Patient seinem Arzte ablegt), oder eigener Erfahrung an sich selbst muß er durch Ich reden."}], "running_header": "Von der Macht des Gemüths durch den bloßen Vorsatz seiner krankhaften Gefühle Meister zu sein"}, {"page_id": "2554_0", "page_pdf": 2554, "page_book": 100, "page_kind": "body", "sigel": "AA VII, 100", "units": [{"type": "paragraph", "text": "Grundsatz der Diätetik."}], "running_header": "Grundsatz der Diätetik"}, {"page_id": "2554_1", "page_pdf": 2554, "page_book": 100, "page_kind": "body", "sigel": "AA VII, 100", "units": [{"type": "paragraph", "text": "Auf Gemächlichkeit muß die Diätetik nicht berechnet werden; denn diese Schonung seiner Kräfte und Gefühle ist Verzärtelung, d.i. sie hat Schwäche und Kraftlosigkeit zur Folge und ein allmähliges Erlöschen der Lebenskraft aus Mangel der Übung; so wie eine Erschöpfung derselben durch zu häufigen und starken Gebrauch derselben. Der Stoicism als Princip der Diätetik (_sustine et abstine_) gehört also nicht bloß zur praktischen Philosophie als Tugendlehre, sondern auch zu ihr als Heilkunde. – Diese ist alsdann philosophisch, wenn bloß die Macht der"}], "markers": [{"system": "AA", "band": "VII", "page": 100, "ref": "VII100"}], "running_header": "Grundsatz der Diätetik"}, {"page_id": "2554_2", "page_pdf": 2554, "page_book": 101, "page_kind": "body", "sigel": "AA VII, 101", "units": [{"type": "paragraph", "text": "Vernunft im Menschen, über seine sinnliche Gefühle durch einen sich selbst gegebenen Grundsatz Meister zu sein, die Lebensweise bestimmt. Dagegen, wenn sie diese Empfindungen zu erregen oder abzuwehren die Hülfe außer sich in körperlichen Mitteln (der Apotheke, oder der Chirurgie) sucht, sie bloß empirisch und mechanisch ist. Die Wärme, der Schlaf, die sorgfältige Pflege des nicht Kranken sind solche Verwöhnungen der Gemächlichkeit. 1) Ich kann der Erfahrung an mir selbst gemäß der Vorschrift nicht beistimmen: man soll Kopf und Füße warm halten. Ich finde es dagegen gerathener, beide kalt zu halten (wozu die Russen auch die Brust zählen), gerade der Sorgfalt wegen, um mich nicht zu verkälten. – Es ist freilich gemächlicher im laulichen Wasser sich die Füße zu waschen, als es zur Winterszeit mit beinahe eiskaltem zu thun; dafür aber entgeht man dem Übel der Erschlaffung der Blutgefäße in so weit vom Herzen entlegenen Theilen, welches im Alter oft eine nicht mehr zu hebende Krankheit der Füße nach sich zieht. – Den Bauch, vornehmlich bei kalter Witterung, warm zu halten, möchte eher zur diätetischen Vorschrift statt der Gemächlichkeit gehören: weil er Gedärme in sich schließt, die einen langen Gang hindurch einen nicht-flüssigen Stoff forttreiben sollen; wozu der sogenannte Schmachtriemen (ein breites den Unterleib haltendes und die Muskeln desselben unterstützendes Band) bei Alten, aber eigentlich nicht der Wärme wegen gehört. 2) Lange oder (wiederholentlich, durch Mittagsruhe) viel schlafen ist freilich eben so viel Ersparniß am Ungemache, was überhaupt das Leben im Wachen unvermeidlich bei sich führt, und es ist wunderlich genug, sich ein langes Leben zu wünschen, um es größtentheils zu verschlafen. Aber das, worauf es hier eigentlich ankommt, dieses vermeinte Mittel des langen Lebens, die Gemächlichkeit, widerspricht sich in seiner Absicht selbst. Denn das wechselnde Erwachen und wieder Einschlummern in langen Winternächten ist für das ganze Nervensystem lähmend, zermalmend und in täuschender Ruhe krafterschöpfend: mithin die Gemächlichkeit hier eine Ursache der Verkürzung des Lebens. – Das Bett ist das Nest einer Menge von Krankheiten. 3) Im Alter sich zu pflegen oder pflegen zu lassen, blos um seine Kräfte durch die Vermeidung der Ungemächlichkeit (z.B. des Ausgehens in schlimmem Wetter) oder überhaupt die Übertragung der Arbeit an Andere, die man selbst verrichten könnte, zu schonen, so aber das Leben"}], "markers": [{"system": "AA", "band": "VII", "page": 101, "ref": "VII101"}], "running_header": "Grundsatz der Diätetik"}, {"page_id": "2554_3", "page_pdf": 2554, "page_book": 102, "page_kind": "body", "sigel": "AA VII, 102", "units": [{"type": "paragraph", "text": "zu verlängern, diese Sorgfalt bewirkt gerade das Widerspiel, nämlich das frühe Altwerden und Verkürzung des Lebens. – – Auch daß sehr alt gewordene mehrentheils verehelichte Personen gewesen wären, möchte schwer zu beweisen sein. – In einigen Familien ist das Altwerden erblich, und die Paarung in einer solchen kann wohl einen Familienschlag dieser Art begründen. Es ist auch kein übles politisches Princip, zu Beförderung der Ehen das gepaarte Leben als ein langes Leben anzupreisen; obgleich die Erfahrung immer verhältnißweise nur wenig Beispiele davon an die Hand giebt von solchen, die neben einander vorzüglich alt geworden sind; aber die Frage ist hier nur vom physiologischen Grunde des Altwerdens – wie es die Natur verfügt, nicht vom politischen, wie die Convenienz des Staats die öffentliche Meinung seiner Absicht gemäß bestimmt zu sein verlangt. – Übrigens ist das Philosophiren, ohne darum eben Philosoph zu sein, auch ein Mittel der Abwehrung mancher unangenehmer Gefühle und doch zugleich Agitation des Gemüths, welches in seine Beschäftigung ein Interesse bringt, das von"}], "markers": [{"system": "AA", "band": "VII", "page": 102, "ref": "VII102"}], "running_header": "Grundsatz der Diätetik"}, {"page_id": "2555_0", "page_pdf": 2555, "page_book": 102, "page_kind": "body", "sigel": "AA VII, 102", "units": [{"type": "paragraph", "text": "äußern Zufälligkeiten unabhängig und eben darum, obgleich nur als Spiel, dennoch kräftig und inniglich ist und die Lebenskraft nicht stocken läßt. Dagegen Philosophie, die ihr Interesse am Ganzen des Endzwecks der Vernunft (der eine absolute Einheit ist) hat, ein Gefühl der Kraft bei sich führt, welches die körperliche Schwächen des Alters in gewissem Maße durch vernünftige Schätzung des Werths des Lebens wohl vergüten kann. – Aber neu sich eröffnende Aussichten zu Erweiterung seiner Erkenntnisse, wenn sie auch gerade nicht zur Philosophie gehörten, leisten doch auch eben dasselbe, oder etwas dem Ähnliches; und sofern der Mathematiker hieran ein unmittelbares Interesse (nicht als an einem Werkzeuge zu anderer Absicht) nimmt, so ist er in sofern auch Philosoph und genießt die Wohlthätigkeit einer solchen Erregungsart seiner Kräfte in einem verjüngten und ohne Erschöpfung verlängerten Leben. Aber auch bloße Tändeleien in einem sorgenfreien Zustande leisten, als Surrogate, bei eingeschränkten Köpfen fast eben dasselbe, und die mit Nichtsthun immer vollauf zu thun haben, werden gemeiniglich auch alt. – Ein sehr bejahrter Mann fand dabei ein großes Interesse, daß die vielen Stutzuhren in seinem Zimmer immer nach einander, keine mit der andern zugleich schlagen mußten; welches ihn und den Uhrmacher den Tag über genug beschäftigte und dem letztern zu verdienen gab. Ein Anderer fand in der Abfütterung und Cur seiner Sangvögel hinreichende Beschäftigung,"}], "running_header": "Grundsatz der Diätetik"}, {"page_id": "2555_1", "page_pdf": 2555, "page_book": 103, "page_kind": "body", "sigel": "AA VII, 103", "units": [{"type": "paragraph", "text": "um die Zeit zwischen seiner eigenen Abfütterung und dem Schlaf auszufüllen. Eine alte begüterte Frau fand diese Ausfüllung am Spinnrade unter dabei eingemischten unbedeutenden Gesprächen und klagte daher in ihrem sehr hohen Alter, gleich als über den Verlust einer guten Gesellschaft, daß, da sie nunmehr den Faden zwischen den Fingern nicht mehr fühlen könnte, sie vor langer Weile zu sterben Gefahr liefe. Doch damit mein Discurs über das lange Leben Ihnen nicht auch lange Weile mache und eben dadurch gefährlich werde, will ich der Sprachseligkeit, die man als einen Fehler des Alters zu belächlen, wenn gleich nicht zu schelten pflegt, hiemit Grenzen setzen."}, {"type": "paragraph", "text": "»Hierwider möchte ich doch die Beobachtung anführen: daß unverehelichte (oder jung verwittwete) alte Männer mehrenteils länger ein jugendliches Aussehen erhalten, als verehelichte, welches doch auf eine längere Lebensdauer zu deuten scheint. – Sollten wohl die letztern an ihren härteren Gesichtszügen den Zustand eines getragenen Jochs (davon _conjugium_), nämlich das frühere Altwerden verrathen, welches auf ein kürzeres Lebensziel hindeutet?«"}], "markers": [{"system": "AA", "band": "VII", "page": 103, "ref": "VII103"}], "running_header": "Grundsatz der Diätetik"}, {"page_id": "2556_0", "page_pdf": 2556, "page_book": 103, "page_kind": "body", "sigel": "AA VII, 103", "units": [{"type": "paragraph", "text": "1. Von der Hypochondrie."}], "running_header": "1. Von der Hypochondrie"}, {"page_id": "2556_1", "page_pdf": 2556, "page_book": 103, "page_kind": "body", "sigel": "AA VII, 103", "units": [{"type": "paragraph", "text": "Die Schwäche, sich seinen krankhaften Gefühlen überhaupt, ohne ein bestimmtes Object, muthlos zu überlassen (mithin ohne den Versuch zu machen über sie durch die Vernunft Meister zu werden), – die Grillenkrankheit (_hypochondria vaga_),* welche gar keinen bestimmten Sitz im Körper hat und ein Geschöpf der Einbildungskraft ist und daher auch die dichtende heißen könnte – wo der Patient alle Krankheiten, von denen er in Büchern liest, an sich zu bemerken glaubt, ist das gerade Widerspiel jenes Vermögens des Gemüths über seine krankhafte Gefühle Meister zu sein, nämlich Verzagtheit, über Übel, welche Menschen zustoßen könnten, zu brüten, ohne, wenn sie kämen, ihnen widerstehen zu können; eine Art von Wahnsinn, welchem freilich wohl irgend ein Krankheitsstoff (Blähung oder Verstopfung) zum Grunde liegen mag, der aber nicht unmittelbar, wie er den Sinn afficirt, gefühlt, sondern als bevorstehendes Übel von der dichtenden Einbildungskraft vorgespiegelt wird; wo dann der Selbstquäler (_heautontimorumenos_), statt sich selbst zu ermannen, vergeblich die Hülfe des Arztes aufruft: weil nur er selbst durch die Diätetik seines Gedankenspiels belästigende Vorstellungen, die sich unwillkürlich einfinden, und zwar von Übeln, wider die sich doch nichts veranstalten ließe, wenn sie sich wirklich einstellten, aufheben kann. – Von dem, der mit dieser Krankheit behaftet, und so lange er es ist, kann man nicht verlangen, er solle seiner krankhaften Gefühle durch den bloßen Vorsatz Meister werden. Denn"}], "markers": [{"system": "AA", "band": "VII", "page": 103, "ref": "VII103"}], "running_header": "1. Von der Hypochondrie"}, {"page_id": "2556_2", "page_pdf": 2556, "page_book": 104, "page_kind": "body", "sigel": "AA VII, 104", "units": [{"type": "paragraph", "text": "wenn er dieses könnte, so wäre er nicht hypochondrisch. Ein vernünftiger Mensch statuirt keine solche Hypochondrie: sondern wenn ihm Beängstigungen anwandeln, die in Grillen, d.i. selbst ausgedachte Übel, ausschlagen wollen, so fragt er sich, ob ein Object derselben da sei. Findet er keines, welches gegründete Ursache zu dieser Beängstigung abgeben kann, oder sieht er ein, daß, wenn auch gleich ein solches wirklich wäre, doch dabei nichts zu thun möglich sei, um seine Wirkung abzuwenden, so geht er mit diesem Anspruche seines inneren Gefühls zur Tagesordnung, d.i. er läßt seine Beklommenheit (welche alsdann bloß topisch ist) an ihrer Stelle liegen (als ob sie ihm nichts anginge) und richtet seine Aufmerksamkeit auf die Geschäfte, mit denen er zu thun hat. Ich habe wegen meiner flachen und engen Brust, die für die Bewegung des Herzens und der Lunge wenig Spielraum läßt, eine natürliche Anlage zur Hypochondrie, welche in früheren Jahren bis an den Überdruß des Lebens gränzte. Aber die Überlegung, daß die Ursache dieser Herzbeklemmung vielleicht bloß mechanisch und nicht zu heben sei, brachte es bald dahin, daß ich mich an sie gar nicht kehrte, und während dessen, daß ich mich in der Brust beklommen fühlte, im Kopf doch Ruhe und Heiterkeit herrschte, die sich auch in der Gesellschaft nicht nach abwechselnden Launen (wie Hypochondrische pflegen), sondern absichtlich und natürlich mitzutheilen nicht ermangelte. Und da man des Lebens mehr froh wird durch das, was man im freien Gebrauch desselben thut, als was man genießt, so können Geistesarbeiten eine andere Art von befördertem Lebensgefühl den Hemmungen entgegen setzen, welche bloß den Körper angehen. Die Beklemmung ist mir geblieben; denn ihre Ursache liegt in meinem körperlichen Bau. Aber über ihren Einfluß auf meine Gedanken und Handlungen bin ich Meister geworden durch Abkehrung der Aufmerksamkeit von diesem Gefühle, als ob es mich gar nicht anginge."}, {"type": "paragraph", "text": "Anmerkungen: * Zum Unterschiede von der topischen (_hypochondria intestinalis_)_. _"}], "markers": [{"system": "AA", "band": "VII", "page": 104, "ref": "VII104"}], "running_header": "1. Von der Hypochondrie"}, {"page_id": "2557_0", "page_pdf": 2557, "page_book": 104, "page_kind": "body", "sigel": "AA VII, 104", "units": [{"type": "paragraph", "text": "2. Vom Schlafe."}], "running_header": "2. Vom Schlafe"}, {"page_id": "2557_1", "page_pdf": 2557, "page_book": 104, "page_kind": "body", "sigel": "AA VII, 104", "units": [{"type": "paragraph", "text": "Was die Türken nach ihren Grundsätzen der Prädestination über die Mäßigkeit sagen: daß nämlich im Anfange der Welt jedem Menschen die Portion zugemessen worden, wie viel er im Leben zu essen haben werde, und, wenn er seinen beschiedenen Theil in großen Portionen verzehrt, er auf eine desto kürzere Zeit zu essen, mithin zu sein sich Rechnung machen"}], "markers": [{"system": "AA", "band": "VII", "page": 104, "ref": "VII104"}], "running_header": "2. Vom Schlafe"}, {"page_id": "2557_2", "page_pdf": 2557, "page_book": 105, "page_kind": "body", "sigel": "AA VII, 105", "units": [{"type": "paragraph", "text": "könne: das kann in einer Diätetik als Kinderlehre (denn im Genießen müssen auch Männer von Ärzten oft als Kinder behandelt werden) auch zur Regel dienen: nämlich daß jedem Menschen von Anbeginn her vom Verhängnisse seine Portion Schlaf zugemessen worden, und der, welcher von seiner Lebenszeit in Mannsjahren zu viel (über das Dritttheil) dem Schlafen eingeräumt hat, sich nicht eine lange Zeit zu schlafen, d.i. zu leben und alt zu werden, versprechen darf. – Wer dem Schlaf als süßen Genuß im Schlummern (der Siesta der Spanier) oder als Zeitkürzung (in langen Winternächten) viel mehr als ein Dritttheil seiner Lebenszeit einräumt, oder ihn sich auch theilweise (mit Absätzen), nicht in einem Stück für jeden Tag zumißt, verrechnet sich sehr in Ansehung seines Lebensquantum theils dem Grade, theils der Länge nach. – Da nun schwerlich ein Mensch wünschen wird, daß der Schlaf überhaupt gar nicht Bedürfniß für ihn wäre (woraus doch wohl erhellt, daß er das lange Leben als eine lange Plage fühlt, von dem, so viel er verschlafen, eben so viel Mühseligkeit zu tragen er sich erspart hat), so ist es gerathener fürs Gefühl sowohl als für die Vernunft, dieses genuß- und thatleere Drittel ganz auf eine Seite zu bringen und es der unentbehrlichen Naturrestauration zu überlassen: doch mit einer genauen Abgemessenheit der Zeit, von wo an und wie lange sie dauern soll."}, {"type": "paragraph", "text": "—————"}, {"type": "paragraph", "text": "Es gehört unter die krankhaften Gefühle zu der bestimmten und gewohnten Zeit nicht schlafen, oder auch sich nicht wach halten zu können; vornehmlich aber das erstere, in dieser Absicht sich zu Bette zu legen und doch schlaflos zu liegen. – Sich alle Gedanken aus dem Kopf zu schlagen, ist zwar der gewöhnliche Rath, den der Arzt giebt: aber sie oder andere an ihre Stelle kommen wieder und erhalten wach. Es ist kein anderer diätetischer Rath, als beim inneren Wahrnehmen oder Bewußtwerden irgend eines sich regenden Gedanken die Aufmerksamkeit davon sofort abzuwenden (gleich als ob man mit geschlossenen Augen diese auf eine andere Seite kehrte): wo dann durch das Abbrechen jedes Gedanken, den man inne wird, allmählig eine Verwirrung der Vorstellungen entspringt, dadurch das Bewußtsein seiner körperlichen (äußeren) Lage aufgehoben wird, und eine ganz verschiedene Ordnung, nämlich ein unwillkürliches Spiel der Einbildungskraft (das im gesunden Zustande der Traum ist), eintritt, in welchem durch ein bewundernswürdiges Kunststück der thierischen Organisation"}], "markers": [{"system": "AA", "band": "VII", "page": 105, "ref": "VII105"}], "running_header": "2. Vom Schlafe"}, {"page_id": "2557_3", "page_pdf": 2557, "page_book": 106, "page_kind": "body", "sigel": "AA VII, 106", "units": [{"type": "paragraph", "text": "der Körper für die animalischen Bewegungen abgespannt, für die Vitalbewegung aber innigst agitirt wird und zwar durch Träume, die, wenn wir uns gleich derselben im Erwachen nicht erinnern, gleichwohl nicht haben ausbleiben können: weil sonst bei gänzlicher Ermangelung derselben, wenn die Nervenkraft, die vom Gehirn, dem Sitze der Vorstellungen, ausgeht, nicht mit der Muskelkraft der Eingeweide vereinigt wirkte, das Leben sich nicht einen Augenblick erhalten könnte. Daher träumen vermuthlich alle Thiere, wenn sie schlafen. Jedermann aber, der sich zu Bette und in Bereitschaft zu schlafen gelegt hat, wird bisweilen bei aller obgedachten Ablenkung seiner Gedanken doch nicht zum Einschlafen kommen können. In diesem Fall wird er im Gehirn etwas Spastisches (Krampfartiges) fühlen, welches auch mit der Beobachtung gut zusammenhängt: daß ein Mensch gleich nach dem Erwachen etwa ½ Zoll länger sei, als wenn er sogar im Bette geblieben und dabei nur gewacht hätte. – Da Schlaflosigkeit ein Fehler des schwächlichen Alters und die linke Seite überhaupt genommen die schwächere ist,* so fühlte ich seit etwa einem Jahre diese krampfichte Anwandelungen und sehr empfindliche Reize"}], "markers": [{"system": "AA", "band": "VII", "page": 106, "ref": "VII106"}], "running_header": "2. Vom Schlafe"}, {"page_id": "2558_0", "page_pdf": 2558, "page_book": 106, "page_kind": "body", "sigel": "AA VII, 106", "units": [{"type": "paragraph", "text": "dieser Art (obzwar nicht wirkliche und sichtbare Bewegungen der darauf afficirten Gliedmaßen als Krämpfe), die ich nach der Beschreibung anderer für gichtische Zufälle halten und dafür einen Arzt suchen mußte. Nun aber, aus Ungeduld, am Schlafen mich gehindert zu fühlen, griff ich bald zu meinem stoischen Mittel, meinen Gedanken mit"}], "running_header": "2. Vom Schlafe"}, {"page_id": "2558_1", "page_pdf": 2558, "page_book": 107, "page_kind": "body", "sigel": "AA VII, 107", "units": [{"type": "paragraph", "text": "Anstrengung auf irgend ein von mir gewähltes gleichgültiges Object, was es auch sei, (z.B. auf den viel Nebenvorstellungen enthaltenden Namen Cicero) zu heften: mithin die Aufmerksamkeit von jener Empfindung abzulenken; dadurch diese dann und zwar schleunig stumpf wurde, und so die Schläfrigkeit sie überwog, und dieses kann ich jederzeit bei wiederkommenden Anfällen dieser Art in den kleinen Unterbrechungen des Nachtschlafs mit gleich gutem Erfolg wiederholen. Daß aber dieses nicht etwa bloß eingebildete Schmerzen waren, davon konnte mich die des andern Morgens früh sich zeigende glühende Röthe der Zehen des linken Fußes überzeugen. – Ich bin gewiß, daß viele gichtische Zufälle, wenn nur die Diät des Genusses nicht gar zu sehr dawider ist, ja Krämpfe und selbst epileptische Zufälle (nur nicht bei Weibern und Kindern, als die dergleichen Kraft des Vorsatzes nicht haben), auch wohl das für unheilbar verschriene Podagra bei jeder neuen Anwandlung desselben durch diese Festigkeit des Vorsatzes (seine Aufmerksamkeit von einem solchen Leiden abzuwenden) abgehalten und nach und nach gar gehoben werden könnte."}, {"type": "paragraph", "text": "Anmerkungen: * Es ist ein ganz unrichtiges Vorgeben, daß, was die Stärke im Gebrauch seiner äußern Gliedmaßen betrifft, es bloß auf die Übung, und wie man frühe gewöhnt worden, ankomme, welche von beiden Seiten des Körpers die stärkere oder schwächere sein solle; ob im Gefechte mit dem rechten oder linken Arm der Säbel geführt, ob sich der Reiter, im Steigbügel stehend, von der Rechten zur Linken oder umgekehrt aufs Pferd schwinge, u.dgl. Die Erfahrung lehrt aber, daß, wer sich am linken Fuße Maß für seine Schuhe nehmen läßt, wenn der Schuh dem linken genau anpaßt, er für den rechten zu enge sei, ohne daß man die Schuld davon den Eltern geben kann, die ihre Kinder nicht besser belehrt hätten; so wie der Vorzug der rechten Seite vor der linken auch daran zu sehen ist, daß der, welcher über einen etwas tiefen Graben schreiten will, den linken Fuß ansetzt und mit dem rechten überschreitet; widrigenfalls er in den Graben zu fallen Gefahr läuft. Daß der preußische Infanterist geübt wird, mit dem linken Fuße anzutreten, widerlegt jenen Satz nicht, sondern bestätigt ihn vielmehr; denn er setzt diesen voran, gleich als auf ein Hypomochlium, um mit der rechten Seite den Schwung des Angriffs zu machen, welchen er mit der rechten gegen die linke verrichtet."}], "markers": [{"system": "AA", "band": "VII", "page": 107, "ref": "VII107"}], "running_header": "2. Vom Schlafe"}, {"page_id": "2559_0", "page_pdf": 2559, "page_book": 107, "page_kind": "body", "sigel": "AA VII, 107", "units": [{"type": "paragraph", "text": "3. Vom Essen und Trinken."}], "running_header": "3. Vom Essen und Trinken"}, {"page_id": "2559_1", "page_pdf": 2559, "page_book": 107, "page_kind": "body", "sigel": "AA VII, 107", "units": [{"type": "paragraph", "text": "Im gesunden Zustande und der Jugend ist es das Gerathenste in Ansehung des Genusses, der Zeit und Menge nach, bloß den Appetit (Hunger und Durst) zu befragen; aber bei den mit dem Alter sich einfindenden Schwächen ist eine gewisse Angewohnheit einer geprüften und heilsam gefundenen Lebensart, nämlich wie man es einen Tag gehalten hat, es eben so alle Tage zu halten, ein diätetischer Grundsatz, welcher dem langen Leben am günstigsten ist; doch unter der Bedingung, daß diese Abfütterung für den sich weigernden Appetit die gehörige Ausnahmen mache. – Dieser nämlich weigert im Alter die Quantität des Flüssigen (Suppen oder viel Wasser zu trinken) vornehmlich dem männlichen Geschlecht: verlangt dagegen derbere Kost und anreizenderes Getränk (z.B. Wein), sowohl um die wurmförmige Bewegung der Gedärme (die unter allen Eingeweiden am meisten von der _vita propria_ zu haben scheinen, weil sie, wenn sie noch warm aus dem Thier gerissen und zerhauen werden, als Würmer kriechen, deren Arbeit man nicht bloß fühlen, sondern sogar hören kann) zu befördern und zugleich solche Theile in den Blutumlauf zu"}], "markers": [{"system": "AA", "band": "VII", "page": 107, "ref": "VII107"}], "running_header": "3. Vom Essen und Trinken"}, {"page_id": "2559_2", "page_pdf": 2559, "page_book": 108, "page_kind": "body", "sigel": "AA VII, 108", "units": [{"type": "paragraph", "text": "bringen, die durch ihren Reiz das Geräder zur Blutbewegung im Umlauf zu erhalten beförderlich sind. Das Wasser braucht aber bei alten Leuten längere Zeit, um, ins Blut aufgenommen, den langen Gang seiner Absonderung von der Blutmasse durch die Nieren zur Harnblase zu machen, wenn es nicht dem Blute assimilirte Theile (dergleichen der Wein ist), und die einen Reiz der Blutgefäße zum Fortschaffen bei sich führen, in sich enthält; welcher letztere aber alsdann als Medicin gebraucht wird, dessen künstlicher Gebrauch eben darum eigentlich nicht zur Diätetik gehört. Der Anwandelung des Appetits zum Wassertrinken (dem Durst), welche großentheils nur Angewohnheit ist, nicht sofort nachzugeben, und ein hierüber genommener fester Vorsatz bringt diesen Reiz in das Maß des natürlichen Bedürfnisses des den festen Speisen beizugebenden Flüssigen, dessen Genuß in Menge im Alter selbst durch den Naturinstinct geweigert wird. Man schläft auch nicht gut, wenigstens nicht tief bei dieser Wasserschwelgerei, weil die Blutwärme dadurch vermindert wird. Es ist oft gefragt worden: ob, gleich wie in 24 Stunden nur Ein Schlaf, so auch in eben so viel Stunden nur Eine Mahlzeit nach diätetischer Regel verwilligt werden könne, oder ob es nicht besser (gesunder) sei, dem Appetit am Mittagstische etwas abzubrechen, um dafür auch zu Nacht essen zu können. Zeitkürzender ist freilich das letztere. – Das letztere halte ich auch in den sogenannten besten Lebensjahren (dem Mittelalter) für zuträglicher; das erstere aber im späteren Alter. Denn da das Stadium für die Operation der Gedärme zum Behuf der Verdauung im Alter ohne Zweifel langsamer abläuft, als in jüngeren Jahren, so kann man glauben, daß ein neues Pensum (in einer Abendmahlzeit) der Natur aufzugeben, indessen daß das erstere Stadium der Verdauung noch nicht abgelaufen ist, der Gesundheit nachtheilig werden müsse. – Auf solche Weise kann man den Anreiz zum Abendessen nach einer hinreichenden Sättigung des Mittags für ein krankhaftes Gefühl halten, dessen man durch einen festen Vorsatz so Meister werden kann, daß auch die Anwandelung desselben nachgerade nicht mehr verspürt wird."}], "markers": [{"system": "AA", "band": "VII", "page": 108, "ref": "VII108"}], "running_header": "3. Vom Essen und Trinken"}, {"page_id": "2560_0", "page_pdf": 2560, "page_book": 108, "page_kind": "body", "sigel": "AA VII, 108", "units": [{"type": "paragraph", "text": "4. Von dem krankhaften Gefühl aus der Unzeit im Denken."}], "running_header": "4. Von dem krankhaften Gefühl aus der Unzeit im Denken"}, {"page_id": "2560_1", "page_pdf": 2560, "page_book": 109, "page_kind": "body", "sigel": "AA VII, 109", "units": [{"type": "paragraph", "text": "Einem Gelehrten ist das Denken ein Nahrungsmittel, ohne welches, wenn er wach und allein ist, er nicht leben kann; jenes mag nun im Lernen (Bücherlesen) oder im Ausdenken (Nachsinnen und Erfinden) bestehen. Aber beim Essen oder Gehen sich zugleich angestrengt mit einem bestimmten Gedanken beschäftigen, Kopf und Magen oder Kopf und Füße mit zwei Arbeiten zugleich belästigen, davon bringt das eine Hypochondrie, das andere Schwindel hervor. Um also dieses krankhaften Zustandes durch Diätetik Meister zu sein, wird nichts weiter erfordert, als die mechanische Beschäftigung des Magens oder der Füße mit der geistigen des Denkens wechseln zu lassen und während dieser (der Restauration gewidmeten) Zeit das absichtliche Denken zu hemmen und dem (dem mechanischen ähnlichen) freien Spiele der Einbildungskraft den Lauf zu lassen; wozu aber bei einem Studirenden ein allgemein gefaßter und fester Vorsatz der Diät im Denken erfordert wird. Es finden sich krankhafte Gefühle ein, wenn man in einer Mahlzeit ohne Gesellschaft sich zugleich mit Bücherlesen oder Nachdenken beschäftigt, weil die Lebenskraft durch Kopfarbeit von dem Magen, den man belästigt, abgeleitet wird. Eben so, wenn dieses Nachdenken mit der krafterschöpfenden Arbeit der Füße (im Promeniren)* verbunden wird. (Man kann das Lucubriren noch hinzufügen, wenn es ungewöhnlich ist.) Indessen sind die krankhaften Gefühle aus diesen unzeitig (_invita Minerva_) vorgenommenen Geistesarbeiten doch nicht von der Art, daß sie sich unmittelbar durch den bloßen Vorsatz augenblicklich, sondern allein durch Entwöhnung vermöge eines entgegengesetzten Princips nach und nach heben lassen, und von den ersteren soll hier nur geredet werden."}, {"type": "paragraph", "text": "Anmerkungen: * Studirende können es schwerlich unterlassen, in einsamen Spaziergängen sich mit Nachdenken selbst und allein zu unterhalten. Ich habe es aber an mir gefunden und auch von andern, die ich darum befrug, gehört: daß das angestrengte Denken im Gehen geschwinde matt macht; dagegen, wenn man sich dem freien Spiel der Einbildungskraft überläßt, die Motion restaurirend ist. Noch mehr geschieht dieses, wenn bei dieser mit Nachdenken verbundenen Bewegung zugleich Unterredung mit einem Andern gehalten wird, so daß man sich bald genöthigt sieht, das Spiel seiner Gedanken sitzend fortzusetzen. – Das Spazieren im Freien hat gerade die Absicht durch den Wechsel der Gegenstände seine Aufmerksamkeit auf jeden einzelnen abzuspannen."}], "markers": [{"system": "AA", "band": "VII", "page": 109, "ref": "VII109"}], "running_header": "4. Von dem krankhaften Gefühl aus der Unzeit im Denken"}, {"page_id": "2561_0", "page_pdf": 2561, "page_book": 109, "page_kind": "body", "sigel": "AA VII, 109", "units": [{"type": "paragraph", "text": "5. Von der Hebung und Verhütung krankhafter Zufälle durch den Vorsatz im Athemziehen."}], "running_header": "5. Von der Hebung und Verhütung krankhafter Zufälle durch den Vorsatz im Athemziehen"}, {"page_id": "2561_1", "page_pdf": 2561, "page_book": 110, "page_kind": "body", "sigel": "AA VII, 110", "units": [{"type": "paragraph", "text": "Ich war vor wenigen Jahren noch dann und wann vom Schnupfen und Husten heimgesucht, welche beide Zufälle mir desto ungelegener waren, als sie sich bisweilen beim Schlafengehen zutrugen. Gleichsam entrüstet über diese Störung des Nachtschlafs entschloß ich mich, was den ersteren Zufall betrifft, mit fest geschlossenen Lippen durchaus die Luft durch die Nase zu ziehen; welches mir anfangs nur mit einem schwachen Pfeifen und, da ich nicht absetzte oder nachließ, immer mit stärkerem, zuletzt mit vollem und freiem Luftzuge gelang, es durch die Nase zu Stande zu bringen, darüber ich dann sofort einschlief. – Was dies gleichsam convulsivische und mit dazwischen vorfallendem Einathmen (nicht wie beim Lachen ein continuirtes) stoßweise erschallende Ausathmen, den Husten, betrifft, vornehmlich den, welchen der gemeine Mann in England den Altmannshusten (im Bette liegend) nennt, so war er mir um so mehr ungelegen, da er sich bisweilen bald nach der Erwärmung im Bette einstellte und das Einschlafen verzögerte. Dieses Husten, welches durch den Reiz der mit offenem Munde eingeathmeten Luft auf den Luftröhrenkopf erregt wird,*"}], "markers": [{"system": "AA", "band": "VII", "page": 110, "ref": "VII110"}], "running_header": "5. Von der Hebung und Verhütung krankhafter Zufälle durch den Vorsatz im Athemziehen"}, {"page_id": "2561_2", "page_pdf": 2561, "page_book": 111, "page_kind": "body", "sigel": "AA VII, 111", "units": [{"type": "paragraph", "text": "nun zu hemmen, bedurfte es einer nicht mechanischen (pharmaceutischen), sondern nur unmittelbaren Gemüthsoperation: nämlich die Aufmerksamkeit auf diesen Reiz dadurch ganz abzulenken, daß sie mit Anstrengung auf irgend ein Object (wie oben bei krampfhaften Zufällen) gerichtet und dadurch das Ausstoßen der Luft gehemmt wurde, welches mir, wie ich es deutlich fühlte, das Blut ins Gesicht trieb, wobei aber der durch denselben Reiz erregte flüssige Speichel (_saliva_) die Wirkung dieses Reizes, nämlich die Ausstoßung der Luft, verhinderte und ein Herunterschlucken dieser Feuchtigkeit bewirkte. – – Eine Gemüthsoperation, zu der ein recht großer Grad des festen Vorsatzes erforderlich, der aber darum auch desto wohlthätiger ist."}, {"type": "paragraph", "text": "Anmerkungen:"}], "markers": [{"system": "AA", "band": "VII", "page": 111, "ref": "VII111"}], "running_header": "5. Von der Hebung und Verhütung krankhafter Zufälle durch den Vorsatz im Athemziehen"}, {"page_id": "2562", "page_pdf": 2562, "page_book": 111, "page_kind": "body", "sigel": "AA VII, 111", "units": [{"type": "paragraph", "text": "* Sollte auch nicht die atmosphärische Luft, wenn sie durch die Eustachische Röhre (also bei geschlossenen Lippen) circulirt, dadurch, daß sie auf diesem dem Gehirn nahe liegenden Umwege Sauerstoff absetzt, das erquickende Gefühl gestärkter Lebensorgane bewirken, welches dem ähnlich ist, als ob man Luft trinke; wobei diese, ob sie zwar keinen Geruch hat, doch die Geruchsnerven und die denselben nahe liegende einsaugende Gefäße stärkt? Bei manchem Wetter findet sich dieses Erquickliche des Genusses der Luft nicht: bei anderem ist es eine wahre Annehmlichkeit sie auf seiner Wanderung mit langen Zügen zu trinken: welches das Einathmen mit offenem Munde nicht gewährt. – – Das ist aber von der größten diätetischen Wichtigkeit, den Athemzug durch die Nase bei geschlossenen Lippen sich so zur Gewohnheit zu machen, daß er selbst im tiefsten Schlaf nicht anders verrichtet wird, und man sogleich aufwacht, sobald er mit offenem Munde geschieht, und dadurch gleichsam aufgeschreckt wird; wie ich das anfänglich, ehe es mir zur Gewohnheit wurde auf solche Weise zu athmen, bisweilen erfuhr. – Wenn man genöthigt ist stark oder bergan zu schreiten, so gehört größere Stärke des Vorsatzes dazu von jener Regel nicht abzuweichen und eher seine Schritte zu mäßigen, als von ihr eine Ausnahme zu machen; ingleichen, wenn es um starke Motion zu thun ist, die etwa ein Erzieher seinen Zöglingen geben will, daß dieser sie ihre Bewegung lieber stumm, als mit öfterer Einathmung durch den Mund machen lasse. Meine jungen Freunde (ehemalige Zuhörer) haben diese diätetische Maxime als probat und heilsam gepriesen und sie nicht unter die Kleinigkeiten gezählt, weil sie bloßes Hausmittel ist, das den Arzt entbehrlich macht. – Merkwürdig ist noch: daß, da es scheint, beim lange fortgesetzten Sprechen geschehe das Einathmen auch durch den so oft geöffneten Mund, mithin jene Regel werde da doch ohne Schaden überschritten, es sich wirklich nicht so verhält. Denn es geschieht doch auch durch die Nase. Denn wäre diese zu der Zeit verstopft, so würde man von dem Redner sagen, er spreche durch die Nase (ein sehr widriger Laut), indem er wirklich nicht durch die Nase spräche, und umgekehrt, er spreche nicht durch die Nase, indem er wirklich durch die Nase spricht: wie es Hr. Hofr. Lichtenberg launicht und richtig bemerkt. – Das ist auch der Grund, warum der, welcher lange und laut spricht (Vorleser oder Prediger), es ohne Rauhigkeit der Kehle eine Stunde lang wohl aushalten kann: weil nämlich sein Athemziehen eigentlich durch die Nase, nicht durch den Mund geschieht, als durch welchen nur das Ausathmen verrichtet wird. – Ein Nebenvortheil dieser Angewohnheit des Athemzuges mit beständig geschlossenen Lippen, wenn man für sich allein wenigstens nicht im Discurs begriffen ist, ist der: daß die sich immer absondernde und den Schlund befeuchtende _Saliva _hiebei zugleich als Verdauungsmittel (_stomachale_), vielleicht auch (verschluckt) als Abführungsmittel wirkt, wenn man fest genug entschlossen ist, sie nicht durch üble Angewohnheit zu verschwenden."}], "markers": [{"system": "AA", "band": "VII", "page": 111, "ref": "VII111"}], "running_header": "5. Von der Hebung und Verhütung krankhafter Zufälle durch den Vorsatz im Athemziehen"}, {"page_id": "2563_0", "page_pdf": 2563, "page_book": 111, "page_kind": "body", "sigel": "AA VII, 111", "units": [{"type": "paragraph", "text": "6. Von den Folgen dieser Angewohnheit des Athemziehens mit geschlossenen Lippen."}], "running_header": "6. Von den Folgen dieser Angewohnheit des Athemziehens mit geschlossenen Lippen"}, {"page_id": "2563_1", "page_pdf": 2563, "page_book": 111, "page_kind": "body", "sigel": "AA VII, 111", "units": [{"type": "paragraph", "text": "Die unmittelbare Folge davon ist, daß sie auch im Schlafe fortwährt, und ich sogleich aus dem Schlafe aufgeschreckt werde, wenn ich zufälligerweise die Lippen öffne und ein Athemzug durch den Mund geschieht; woraus man sieht, daß der Schlaf und mit ihm der Traum nicht"}], "markers": [{"system": "AA", "band": "VII", "page": 111, "ref": "VII111"}], "running_header": "6. Von den Folgen dieser Angewohnheit des Athemziehens mit geschlossenen Lippen"}, {"page_id": "2563_2", "page_pdf": 2563, "page_book": 112, "page_kind": "body", "sigel": "AA VII, 112", "units": [{"type": "paragraph", "text": "eine so gänzliche Abwesenheit von dem Zustande des Wachenden ist, daß sich nicht auch eine Aufmerksamkeit auf seine Lage in jenem Zustande mit einmische: wie man denn dieses auch daraus abnehmen kann, daß die, welche sich des Abends vorher vorgenommen haben früher als gewöhnlich (etwa zu einer Spazierfahrt) aufzustehen, auch früher erwachen; indem sie vermuthlich durch die Stadtuhren aufgeweckt worden, die sie also auch mitten im Schlaf haben hören und darauf Acht geben müssen. – Die mittelbare Folge dieser löblichen Angewöhnung ist: daß das unwillkürliche abgenöthigte Husten (nicht das Aufhusten eines Schleims als beabsichtigter Auswurf) in beiderlei Zustande verhütet und so durch die bloße Macht des Vorsatzes eine Krankheit verhütet wird. – – Ich habe sogar gefunden, daß, da mich nach ausgelöschtem Licht (und eben zu Bette gelegt) auf einmal ein starker Durst anwandelte, den mit Wassertrinken zu löschen ich im Finstern hätte in eine andere Stube gehen und durch Herumtappen das Wassergeschirr suchen müssen, ich darauf fiel, verschiedene und starke Athemzüge mit Erhebung der Brust zu thun und gleichsam Luft durch die Nase zu trinken; wodurch der Durst in wenig Secunden völlig gelöscht war. Es war ein krankhafter Reiz, der durch einen Gegenreiz gehoben ward."}], "markers": [{"system": "AA", "band": "VII", "page": 112, "ref": "VII112"}], "running_header": "6. Von den Folgen dieser Angewohnheit des Athemziehens mit geschlossenen Lippen"}, {"page_id": "2564_0", "page_pdf": 2564, "page_book": 112, "page_kind": "body", "sigel": "AA VII, 112", "units": [{"type": "paragraph", "text": "Beschluß."}], "running_header": "Beschluß"}, {"page_id": "2564_1", "page_pdf": 2564, "page_book": 112, "page_kind": "body", "sigel": "AA VII, 112", "units": [{"type": "paragraph", "text": "Krankhafte Zufälle, in Ansehung deren das Gemüth das Vermögen besitzt, des Gefühls derselben durch den bloßen standhaften Willen des Menschen, als einer Obermacht des vernünftigen Thieres, Meister werden zu können, sind alle von der spastischen (krampfhaften) Art: man kann aber nicht umgekehrt sagen, daß alle von dieser Art durch den bloßen festen Vorsatz gehemmt oder gehoben werden können. – Denn einige derselben sind von der Beschaffenheit, daß die Versuche sie der Kraft des Vorsatzes zu unterwerfen das krampfhafte Leiden vielmehr noch verstärken; wie es der Fall mit mir selber ist, da diejenige Krankheit, welche vor etwa einem Jahr in der Kopenhagener Zeitung als »epidemischer, mit Kopfbedrückung verbundener Katarrh« beschrieben wurde,* (bei mir aber wohl ein Jahr älter, aber doch von ähnlicher Empfindung ist) mich für eigene Kopfarbeiten gleichsam desorganisirt, wenigstens geschwächt und stumpf gemacht hat und, da sich diese Bedrückung auf die natürliche Schwäche"}], "markers": [{"system": "AA", "band": "VII", "page": 112, "ref": "VII112"}], "running_header": "Beschluß"}, {"page_id": "2564_2", "page_pdf": 2564, "page_book": 113, "page_kind": "body", "sigel": "AA VII, 113", "units": [{"type": "paragraph", "text": "des Alters geworfen hat, wohl nicht anders als mit dem Leben zugleich aufhören wird. Die krankhafte Beschaffenheit des Patienten, die das Denken, in sofern es ein Festhalten eines Begriffs (der Einheit des Bewußtseins verbundener Vorstellungen) ist, begleitet und erschwert, bringt das Gefühl eines spastischen Zustandes des Organs des Denkens (des Gehirns) als eines Drucks hervor, der zwar das Denken und Nachdenken selbst, ingleichen das Gedächtniß in Ansehung des ehedem Gedachten eigentlich nicht schwächt, aber im Vortrage (dem mündlichen oder schriftlichen) das feste Zusammenhalten der Vorstellungen in ihrer Zeitfolge wider Zerstreuung sicheren soll, bewirkt selbst einen unwillkürlichen spastischen Zustand des Gehirns, als ein Unvermögen, bei dem Wechsel der auf einander folgenden Vorstellungen die Einheit des Bewußtseins derselben zu erhalten. Daher begegnet es mir: daß, wenn ich, wie es in jeder Rede jederzeit geschieht, zuerst zu dem, was ich sagen will, (den Hörer oder Leser) vorbereite, ihm den Gegenstand, wohin ich gehen will, in der Aussicht, dann ihn auch auf das, wovon ich ausgegangen bin, zurückgewiesen habe (ohne welche zwei Hinweisungen kein Zusammenhang der Rede Statt findet) und ich nun das letztere mit dem ersteren verknüpfen soll, ich auf einmal meinen Zuhörer (oder stillschweigend mich selbst) fragen muß: Wo war ich doch? Wovon ging ich aus? welcher Fehler nicht sowohl ein Fehler des Geistes, auch nicht des Gedächtnisses allein, sondern der Geistesgegenwart (im Verknüpfen), d.i. unwillkürliche Zerstreuung und ein sehr peinigender Fehler ist, dem man zwar in Schriften (zumal den philosophischen: weil man da nicht immer so leicht zurücksehen kann, von wo man ausging) mühsam vorbeugen, obzwar mit aller Mühe nie völlig verhüten kann. Mit dem Mathematiker, der seine Begriffe oder die Stellvertreter derselben (Größen- und Zahlenzeichen) in der Anschauung vor sich hinstellen, und daß, so weit er gegangen ist, alles richtig sei, versichert sein kann, ist es anders bewandt, als mit dem Arbeiter im Fache der vornehmlich reinen Philosophie (Logik und Metaphysik), der seinen Gegenstand in der Luft vor sich schwebend erhalten muß und ihn nicht bloß theilweise, sondern jederzeit zugleich in einem Ganzen des Systems (d. r. V.) sich darstellen und prüfen muß. Daher es eben nicht zu verwundern ist, wenn ein Metaphysiker eher invalid wird, als der Studirende in einem anderen Fache, ingleichen als Geschäftsphilosophen; indessen daß es doch einige"}], "markers": [{"system": "AA", "band": "VII", "page": 113, "ref": "VII113"}], "running_header": "Beschluß"}, {"page_id": "2564_3", "page_pdf": 2564, "page_book": 114, "page_kind": "body", "sigel": "AA VII, 114", "units": [{"type": "paragraph", "text": "derer geben muß, die sich jenem ganz widmen, weil ohne Metaphysik überhaupt es gar keine Philosophie geben könnte. Hieraus ist auch zu erklären, wie jemand für sein Alter gesund zu sein sich rühmen kann, ob er zwar in Ansehung gewisser ihm obliegenden Geschäfte sich in die Krankenliste mußte einschreiben lassen. Denn weil das Unvermögen zugleich den Gebrauch und mit diesem auch den Verbrauch und die Erschöpfung der Lebenskraft abhält, und er gleichsam nur in einer niedrigeren Stufe (als vegetirendes Wesen) zu leben gesteht, nämlich essen, gehen und schlafen zu können, was für seine animalische Existenz gesund, für die bürgerliche (zu öffentlichen"}], "markers": [{"system": "AA", "band": "VII", "page": 114, "ref": "VII114"}], "running_header": "Beschluß"}, {"page_id": "2565", "page_pdf": 2565, "page_book": 114, "page_kind": "body", "sigel": "AA VII, 114", "units": [{"type": "paragraph", "text": "Geschäften verpflichtete) Existenz aber krank, d.i. invalid, heißt: so widerspricht sich dieser Candidat des Todes hiemit gar nicht. Dahin führt die Kunst das menschliche Leben zu verlängern: daß man endlich unter den Lebenden nur so geduldet wird, welches eben nicht die ergötzlichste Lage ist. Hieran aber habe ich selber Schuld. Denn warum will ich auch der hinanstrebenden jüngeren Welt nicht Platz machen und, um zu leben, mir den gewöhnten Genuß des Lebens schmälern: warum ein schwächliches Leben durch Entsagungen in ungewöhnliche Länge ziehen, die Sterbelisten, in denen doch auf den Zuschnitt der von Natur Schwächeren und ihre muthmaßliche Lebensdauer mit gerechnet ist, durch mein Beispiel in Verwirrung bringen und das alles, was man sonst Schicksal nannte (dem man sich demüthig und andächtig unterwarf), dem eigenen festen Vorsatze unterwerfen; welcher doch schwerlich zur allgemeinen diätetischen Regel, nach welcher die Vernunft unmittelbar Heilkraft ausübt, aufgenommen werden und die therapeutische Formeln der Officin jemals verdrängen wird?"}, {"type": "paragraph", "text": "Anmerkungen: * Ich halte sie für eine Gicht, die sich zum Theil aufs Gehirn geworfen hat."}], "running_header": "Beschluß"}, {"page_id": "2566_0", "page_pdf": 2566, "page_book": 114, "page_kind": "body", "sigel": "AA VII, 114", "units": [{"type": "paragraph", "text": "Nachschrift."}], "running_header": "Nachschrift"}, {"page_id": "2566_1", "page_pdf": 2566, "page_book": 114, "page_kind": "body", "sigel": "AA VII, 114", "units": [{"type": "paragraph", "text": "Den Verfasser der Kunst das menschliche (auch besonders das literärische) Leben zu verlängern darf ich also dazu wohl auffordern, daß er wohlwollend auch darauf bedacht sei, die Augen der Leser (vornehmlich der jetzt großen Zahl der Leserinnen, die den Übelstand der Brille noch härter fühlen dürften) in Schutz zu nehmen, auf welche jetzt aus elender Ziererei der Buchdrucker (denn Buchstaben haben doch als Malerei schlechterdings nichts Schönes an sich) von allen Seiten Jagd gemacht wird: damit nicht, so wie in Marokko durch weiße Übertünchung aller Häuser ein großer"}], "markers": [{"system": "AA", "band": "VII", "page": 114, "ref": "VII114"}], "running_header": "Nachschrift"}, {"page_id": "2566_2", "page_pdf": 2566, "page_book": 115, "page_kind": "body", "sigel": "AA VII, 115", "units": [{"type": "paragraph", "text": "Theil der Einwohner der Stadt blind ist, dieses Übel aus ähnlicher Ursache auch bei uns einreiße, vielmehr die Buchdrucker desfalls unter Polizeigesetze gebracht werden. – Die jetzige Mode will es dagegen anders; nämlich: 1) Nicht mit schwarzer, sondern grauer Tinte (weil es sanfter und lieblicher auf schönem weißen Papier absteche) zu drucken. 2) Mit Didotschen Lettern von schmalen Füßen, nicht mit Breitkopfschen, die ihrem Namen Buchstaben (gleichsam bücherner Stäbe zum Feststehen) besser entsprechen würden. 3) Mit lateinischer (wohl gar Cursiv-) Schrift ein Werk deutschen Inhalts, von welcher Breitkopf mit Grunde sagte: daß niemand das Lesen derselben für seine Augen so lange aushalte, als mit der deutschen. 4) Mit so kleiner Schrift, als nur möglich, damit für die unten etwa beizufügende Noten noch kleinere (dem Auge noch knapper angemessene) leserlich bleibe. Diesem Unwesen zu steuren, schlage ich vor: den Druck der Berliner Monatsschrift (nach Text und Noten) zum Muster zu nehmen; denn man mag, welches Stück man will, in die Hand nehmen, so wird man die durch obige Leserei angegriffene Augen durch Ansicht des letzteren merklich gestärkt fühlen.*"}, {"type": "paragraph", "text": "I. Kant."}, {"type": "paragraph", "text": "Anmerkungen: * Unter den krankhaften Zufällen der Augen (nicht eigentlichen Augenkrankheiten) habe ich die Erfahrung von einem, der mir zuerst in meinen Vierzigerjahren einmal, späterhin mit Zwischenräumen von einigen Jahren dann und wann, jetzt aber in einem Jahre etlichemal begegnet ist, gemacht; wo das Phänomen darin besteht: daß auf dem Blatt, welches ich lese, auf einmal alle Buchstaben verwirrt und durch eine gewisse über dasselbe verbreitete Helligkeit vermischt und ganz unleserlich werden: ein Zustand, der nicht über 6 Minuten dauert, der einem Prediger, welcher seine Predigt vom Blatte zu lesen gewohnt ist, sehr gefährlich sein dürfte, von mir aber in meinem Auditorium der Logik oder Metaphysik, wo nach gehöriger Vorbereitung im freien Vortrage (aus dem Kopfe) geredet werden kann, nichts als die Besorgniß entsprang, es möchte dieser Zufall der Vorbote vom Erblinden sein; worüber ich gleichwohl jetzt beruhigt bin: da ich bei diesem jetzt öfter als sonst sich ereignenden Zufalle an meinem Einen gesunden Auge (denn das linke hat das Sehen seit etwa 5 Jahren verloren) nicht den mindesten Abgang an Klarheit verspüre. – Zufälligerweise kam ich darauf, wenn sich jenes Phänomen ereignete, meine Augen zu schließen, ja um noch besser das äußere Licht abzuhalten, meine Hand darüber zu legen, und dann sah ich eine hellweiße, wie mit Phosphor im Finstern auf einem Blatt verzeichnete Figur, ähnlich der, wie das letzte Viertel im Kalender vorgestellt wird, doch mit einem auf der convexen Seite ausgezackten Rande, welche allmählich an Helligkeit verlor und in obbenannter Zeit verschwand. – Ich möchte wohl wissen: ob diese Beobachtung auch von Andern gemacht, und wie diese Erscheinung, die wohl eigentlich nicht in den Augen – als bei deren Bewegung dies Bild nicht zugleich mit bewegt, sondern immer an derselben Stelle gesehen wird –, sondern im _Sensorium commune _ihren Sitz haben dürfte, zu erklären sei. Zugleich ist es seltsam, daß man ein Auge (innerhalb einer Zeit, die ich etwa auf 3 Jahre schätze) einbüßen kann, ohne es zu vermissen."}], "markers": [{"system": "AA", "band": "VII", "page": 115, "ref": "VII115"}], "running_header": "Nachschrift"}, {"page_id": "2567", "page_pdf": 2567, "page_book": 115, "page_kind": "blank", "sigel": "AA VII, 115", "units": []}]};
